    public static $reachActions = array(
        array(
            'Type' => 'Full Lunge',
            'Description' => 'The Full Lunge involves a couple of steps or a leap forwards, as well as twisting and leaning the body to maximise the Lunge from back foot to leading hand, or weapon tip. A Full Lunge is a great attacking move, but will leave even a Master open to attack while they recover.',
            'Rules' => 'The Full Lunge adds the +3 Pips to each card played as an Attack in the Action, but leaves can leave the Character exposed after their attack. The Full Lunge adds 1d6 RT to the attack, but a roll of 5 or 6 adds 1 additional GRT to the Action instead.',
