        array(
            'Type' => 'Core',
            'Description' => 'This is a Core Game. You cannot edit Core components, but can use them in your own projects. Core Games define common rules sets and the like for many other Games.'
        ) ,
        array(
            'Type' => 'World-building',
            'Description' => 'World-building Games used by Referees and Authors to flesh out worlds and develop the Game&#39;s background. Word-building games are sometimes used to construct an area for a Sandbox game.'
        ) ,
        array(
            'Type' => 'Collaborative',
            'Description' => 'Collaborative Games are world-building Games that are shared between multiple Authors or Referees.'
        ) ,
        array(
            'Type' => 'Sandbox',
            'Description' => 'Sandbox Games are constructed Settings - which are Locations, usually villages, towns, kingdoms or whole worlds, populated with Characters and Descendants, typically with a built-in and some what delicate balance. When the PCs interact with the Sandbox, it will push the world out of balance somehow, and cause a number of reactions from the different factions, groups, and Characters in the Sandbox. Sandboxes are both complicated to set up and can be complex to run, but feel like living places when done right.'
        ) ,
        array(
