    public static $tensionLevels = 'Deprecated';
    public static $suspenseLevels = array(
        array(
            'Suspense_Level' => 0,
            'Type' => 'Exhausted',
            'Description' => 'Typically used when a Plot has concluded or an Embodiment Character has collapsed due to Stress, Strain and Shock, leading to Drama and a Break.',
            'Scene_Description'=>'An Exhausted Scene is often narrated as skipped time. For example, if an Embodiment Player Character has collapsed due to Shock, Drama and a Break, they may be told ,"The last thing you see, before your vision fades, is the Dragon slithering away. When you wake up, aching and sore, it is light again.". Other Characters will not experience the Exhausted Scene, and will have a different Scene based on the normal Act Suspense Level.',
            'Level_Trigger_Event'=>'This Level is triggered automatically during a Break, or after a Plot has resolved.',

            'Plot_Behaviour' => 'An Exhausted Plot can use some External Embodiments, but is limited to a single Character Embodiment in any Scene.',
            'Plot_Hooks'=>'Exhasuted Plots usually cannot Hook new Character Embodiments, but Hooking an existing Character Embodiment with a Hidden Embodiment is possible.',
            'Plot_Influence'=>'An Exhausted Plot cannot Push or Pull Characters with Tensions or Pressures. An Exhausted Plot cannot cause any Character to <strong>Gain Stress</strong>, and cannot support any Monster Facets. ',

            'Pulled_Embodiments' => 'Pulled Embodiments are content to sleep and rest and perhaps engage in casual conversation. Typically only 1 Embodiment may be present in the Scene.',
            'Pushed_Embodiments' => 'Pushed Embodiments are typically physically exhausted, wishing only to sleep, they may speak, but prefer to listen. Typically only 1 Embodiment may be present in the Scene.',
            'Hidden_Embodiments' => 'Hidden Embodiments are usually physically exhausted and typically sleep. They may speak if awake, but prefer to listen.',
            'External_Embodiments' => 'External Embodiments such as Descendants, Emotions (1 card), Locations and Tones are possible, but typically limited to only 1 Embodiment per Side, Dominant Side may have an additional External Embodiment.',
            'Drama_Pool_Limit' => 21,
            'Dramatic_Stress_Limit' => 16
        ) ,
        array(
            'Suspense_Level' => 1,
            'Type' => 'Cool',
            'Description' => 'This is a very low-level of suspense, very laid-back and care-free, Characters may be drunk, distracted, drugged, or partially asleep. It is usually the result of all the Suspense in a Plot being lost, due to Drama, or may occur very early in a Plot.',

            'Scene_Description'=>'A Cool Scene is low in suspense, tension and pressure. Characters are usually blowing off steam, chilling or resting and Relieving Stress, however they do it.',
            'Level_Trigger_Event'=>'This Level of suspense can be triggered by Characters getting drunk, taking drugs or celebrating some victory. Although this is not guarranteed, as other events are more likely to trigger simultaneously.',
            'Plot_Behaviour' => 'The Cool Plot will favour using External Embodiments, over Character Embodiments, due to limts on Character Embodiments.',

            'Plot_Hooks'=>'A Cool Plot is capable of Hooking and sustaining Character Embodiments, but they are unlikely to bother, unless it is a Hook Scene or they have no available Embodiments.',
            'Plot_Influence'=>'A Cool Plot can cause already Hooked Embodiments to <strong>Gain Stress</strong> if they do not try to Relieve Stress or rest during the Scene.',

            'Pulled_Embodiments' => 'Pulled Embodiments are relaxing and relieving stress. Typically only 2 Pulled Embodiments may be present in the Scene at any time.',
            'Pushed_Embodiments' => 'Pushed Embodiments are usually relieving stress. Typically only 1 Pushed Embodiment may be present in the Scene at any time.',
            'Hidden_Embodiments' => 'May work their conflict by discussing one side of the Conflict with another Character, or manifesting as a Test.',
            'External_Embodiments' => 'Descendants, Emotions (1 card), Failures, Locations, Tests and Tones may be used. External Embodiments usually cannot Wound any Character. Monster Embodiments may reveal / have active only 1 Monster Facet.',
            'Drama_Pool_Limit' => 19,
            'Dramatic_Stress_Limit' => '14'
        ) ,
        array(
            'Suspense_Level' => 2,
            'Type' => 'Awake',
            'Description' => 'This is where most of us spend the day unless we are particularly focused on some complex task.',

            'Scene_Description'=>'An Awake Scene shows Characters in their normal situations. This is the realm of Character Moments and world-building, it is typically used to establish the normal world of the Embodiment Characters. As such it usually occurs only early in the narrative, although it may occur narratively when the Character returns home.',
            'Level_Trigger_Event'=>'This level is triggered automatically when a Character wakes from sleep normally, or is going about their normal routine.',
            'Plot_Behaviour' => 'An Awake Plot is active and planning. It will try to work the Conflict by having Character Embodiments engage with genre and setting appropriate External Embodiments.',

            'Plot_Hooks'=>'Awake Plots will try to Hook potential Character Embodiments as they show themselves to the Plot, as well as securing back-ups where possible.',
            'Plot_Influence'=>'Awake Plots may cause any Hooked Embodiment Character to <strong>Gain Stress</strong> for every Scene that contains another Side’s Embodiments that the Character ignored.',

            'Pulled_Embodiments' => 'Pulled Embodiments are drawn towards other Embodiments by the Plot. However, only 3 Pulled Embodiments may be present in the Scene at the same time.',
            'Pushed_Embodiments' => 'Pushed Embodiments may be pushed towards each other, although they will not be compelled to interact with each other, and are often blocked from interacting directly, but will often spot or assess each other. Up to 3 Sides Pushed Embodiments may be present in a Scene at once.',
            'Hidden_Embodiments' => 'May work their Conflict by having one side manifest as Emotions, Failure Levels, Hurdles, Obstacles, or Tests.',
            'External_Embodiments' => 'All sorts of External Embodiments Descendants, Emotions (1 card), Failures, Hurdles, Locations, Monsters, Obstacles, Ordeals, Tests or Tones may be used. Typically dangerous Embodiments (such as Monsters) can only target Vex or Chorus Extras while Awake. Monster Embodiments may reveal upto 2 Monster Facets.',
            'Drama_Pool_Limit' => 17,
            'Dramatic_Stress_Limit' => '12'
        ) ,
        array(
            'Suspense_Level' => 3,
            'Type' => 'Aware',
            'Description' => 'This is the level of suspense you might feel when you hear the phone ring while you are in the middle of something else. This is the minimal Suspense Level of the first Revelation of the Plot.',

            'Scene_Description'=>'An Aware Scene shows the Characters becoming aware of some aspect of the Plot, usually this is a Revelation Scene, that defines at least one Side of the Conflict.',
            'Level_Trigger_Event'=>'This level of suspense is normally triggered by two Character Embodiments meeting socially, or one Embodiment being told of the existence of another Embodiment.',
            'Plot_Behaviour' => 'Aware Plots will try to work their Conflict and find a Resolution as slowly as possible. They do not favour direct confrontation of Character Embodiments, and limit the number in a Scene, but will let them meet and interact socially.',

            'Plot_Hooks'=>'Plots should Hook and reveal their Embodiments, ideally without drawing too much attention, and without revealing too many details. For example, a Character may be an obvious Embodiment, but of what Facet, and how they are Hooked, should remain a mystery. Some Embodiments (such as Monster, Incarna and Persona) should be held back at this Suspense-Level.',
            'Plot_Influence'=>'Aware plots can cause any Hooked Embodiment Character to <strong>Gain Stress</strong> for every 90 minutes of normal activity (work, study, travelling, training, hobby activity) that the Character performs that ignores the Plot.',

            'Pulled_Embodiments' => 'All Pulled Embodiments present are drawn towards either the largest number of other Embodiments, or the closest other Pulled Embodiment. Each side may have a single Pulled Embodiment present in the Scene at any time.',
            'Pushed_Embodiments' => 'All Push Embodiments are pushed towards an opposed Push Embodiment. Every Side may have 1 Push Embodiment per Side in the Scene at one time.',
            'Hidden_Embodiments' => 'Hidden Embodiments may work their Conflict by experiencing both the Push Pressure and Pull Tension of the Scene on some aspect of their Character.',
            'External_Embodiments' => 'Any External Embodiment is possible, but dangerous Embodiments (such as Traps) can only Kill Extras (and typically not Cast Extras). Emotions may reach 2 cards but 1 card is still more common. Monster Embodiments may reveal upto 3 Monster Facets.',
            'Drama_Pool_Limit' => 15,
            'Dramatic_Stress_Limit' => '10'
        ) ,
        array(
            'Suspense_Level' => 4,
            'Type' => 'Alert',
            'Description' => 'This is the level of suspense you might experience upon hearing an unexpected noise when you are home alone. This usually means that the Characters have become aware of the situation the Plot has created, and may have identified the Protagonist (or at least a fall-guy or minion). ',
            'Scene_Description'=>'Alert Scenes indicate the Sides of the Conflict become fully alert to each other. Character Embodiments from different Sides will meet, and become aware of each others allegiance. This level of Suspense is common in the early Loom.',
            'Level_Trigger_Event'=>'This level of Suspense is triggered by a Character Embodiments from at least two Sides being in the same Location and realising they are on different Sides.',
            'Plot_Behaviour' => 'An Alert Plot should work the Conflict indirectly, and carefully, this can be by having all the Embodiments meet, but not yet engage in any External Embodiment Tests or Ordeals. For example, when the competitors in a Metal Plot first meet, they may argue, fight or compete in some way, but not what they have come to the competition for (racing, sports, chess, etc). ',

            'Plot_Hooks'=>'An Alert Plot is always alert to a potential Embodiment appearing, and will often try to Hook backup Embodiments, and not reveal them, if possible.',
            'Plot_Influence'=>'An Alert Plot can cause any Character Embodiment to <strong>Gain Stress</strong> anytime a Character crosses a threshold (enters or leaves a Location, an hour passes), without becoming "alert to the Plot". If there is a suspicious glow on the horizon, the Plot can add Stress for every hour the Character refuses to aknowledge it or investigate, as well as every time they move rooms in the house and are told about the glow outside the window.',

            'Pulled_Embodiments' => 'Pulled Embodiments are usually drawn to another Pulled Embodiment, often from an Opposed Side. They often choose to pull a Pushed Embodiment from their Side with them.',
            'Pushed_Embodiments' => 'Pushed Embodiments often feel pressured to either approach the closest Opposed Push Embodiment, or move away from the closest Pull Embodiment. They will often feel compelled to make a threat, insult or dismissive display.',
            'Hidden_Embodiments' => 'Push Embodiments should now be aware of their inner Conflict, but will do their best to hide and dismiss the importance of this. They will actively resist attempts to expose or confront this Hidden Embodiment.',
            'External_Embodiments' => 'Any External Embodiments are possible (although Emotions are limited to 2 Cards). Dangerous Embodiments (such as Monsters) may target any Character, but typically will not kill Embodiments.  Monster Embodiments may reveal upto 4 Monster Facets.',
            'Drama_Pool_Limit' => 13,
            'Dramatic_Stress_Limit' => '8'
        ) ,
        array(
            'Suspense_Level' => 5,
            'Type' => 'Engaged',
            'Description' => 'This is the level of suspense that you might feel when you are completely focused on a complex task. All Embodiments are now engaged with the Plot, and they and the Plot are engaged in actively working the Conflict. This is the level of suspense we should expect through most of the Loom in any comedy or romantic drama.',
            'Scene_Description'=>'An Engaged Scene is often an Action scene, the Character Embodiments can compete, interact, fight, etc.',
            'Level_Trigger_Event'=>'This level of suspense is typically triggered by Character Embodiments arguing, or fighting.',
            'Plot_Behaviour' => 'An Engaged Plot should be actively trying to work the Conflict, including by having Embodiments directly compete, argue or "fight" in an Ordeal that is usually an External Embodiment of the Above Side, however such Ordeals are usually limited to Low Stakes Ordeals. ',

            'Plot_Hooks'=>'Engaged Plots may attempt to Hook any Character present in the Scene to one Side of the Conflict or the other, if only as a potential backup.',
            'Plot_Influence'=>'An Engaged Plot may cause any Embodiment Characters to <strong>Gain Stress</strong> that have not engaged the Plot (by rolling a Die, Playing an Ordeal Card, etc, against an Opposed Side’s Embodiment).',

            'Pulled_Embodiments' => 'Pulled Embodiments are drawn towards each other. None Pulled Embodiment Characters may also feel drawn to these Characters as though they were also Pulled.',
            'Pushed_Embodiments' => 'Pushed Embodiments are pushed away from their Side towards the Opposition. None Pushed Embodiments may feel pushed away from Pushed Embodiments.',
            'Hidden_Embodiments' => 'The Hidden Embodiment should work their Conflict by changing their mind about things. This can create a Turn in the Narrative, but is more often an indecision that reflects the Internal Conflict.',
            'External_Embodiments' => 'External Embodiments usually favour Emotions (2 cards), Failure Levels, Hurdles, Monsters, Obstacles, Ordeals, or Tests. Any Facet that does not have a Character Embodiment present in the Scene should have an External Embodiment present. Monster Embodiments may reveal upto 5 Monster Facets.',
            'Drama_Pool_Limit' => 11,
            'Dramatic_Stress_Limit' => '6'
        ) ,
        array(
            'Suspense_Level' => 6,
            'Type' => 'Suspenseful',
            'Description' => 'This is the level of suspense that you might experience if you hear a knock on the door in the middle of the night when you live in the countryside. Suspenseful is the level of suspense where all Characters should begin to feel a sense of anticipation or anxiety. Is that ticking noise the clock, or a bomb? This is the minimum amount of Suspense that should be present in the Loom in a Thriller or similar.',
            'Level_Trigger_Event'=>'This level of suspense is triggered if a Character is anticipating some problem, disaster or injury.',
            'Scene_Description'=>'A Suspenseful Scene is intended to be full of Character and Dramatic Tension and Pressures. Character Embodiments should be anxious, insecure, uncertain and nervous about the outcome (although arrogance and overconfidence may appear as well).',
            'Plot_Behaviour' => 'A Suspenseful Plot is a busy plot, it has multiple things going on at once, and there is always some Question the Plot is asking, or some doubt about the outcome of the Scene.',

            'Plot_Hooks'=>'A Suspenseful Plot will always make references to other Hooked Character Embodiments that have not yet been revealed directly (and potentially have not been Hooked). Even if this is only as vague as an Embodiment asking "Does the boss know about this?".',
            'Plot_Influence'=>'A Suspenseful Plot can cause any Embodiment Character to <strong>Gain Stress</strong> whenever the conversation, arguments, or debate about the current situation pauses, or moves off-topic. In other words, if the Plot has put Kill-bots outside the cabin, talk about the kill-bots, not whose idea the fishing trip was. A Suspenseful Plot may add 1 Monster Facet to any Character Embodiment at this Level.',

            'Pulled_Embodiments' => 'Pull Embodiments will usually experience at least a 2 card Psych effect as part of the Recoiling of the Weft, and may reveal a Monster Facet if genre and setting allow.',
            'Pushed_Embodiments' => 'Push Embodiments usually experience at least a 2 card Psych effect as part of the Recoiling of a Weft Scene, and may reveal a Monster Facet if genre and setting allow.',
            'Hidden_Embodiments' => 'Hidden Embodiments may engage in self-destructive behaviours, including self-targetting Psych Attacks, binge drinking, drug-taking, and risk-taking, as they try to work the inner Conflict. Other Characters that notice and address this conflict are likely to be selected as a Projected Embodiment, creating essentially a fake Pull or Push Embodiment, from the Hidden Embodiment.',
            'External_Embodiments' => 'All Sides should have at least one External Embodiment present in the Scene.  Monster Embodiments may reveal upto 6 Monster Facets.',
            'Drama_Pool_Limit' => 9,
            'Dramatic_Stress_Limit' => '4'
        ) ,
        array(
            'Suspense_Level' => 7,
            'Type' => 'Emotional',
            'Description' => 'This is the level of suspense that you might experience during a profound event like a first love, death in the family or blazing row, where suspense becomes over-whelming and Rational-Conflict begins. This is usually the minimum Suspense Level of any Zenith Act Final Battle Scene.',
            'Scene_Description'=>'An Emotional Scene is simply any scene that has an emotional focus. This might be a Character finding out they are sick, or some traumatic experience, or it could just be a great night out.',
            'Level_Trigger_Event'=>'This level of suspense is triggered if a Character experiences any 2 card Psych effects, or a 1 card Psych effect for the very first time.',
            'Plot_Behaviour' => 'An Emotional Plot is focused on Emotions, Social interactions, and Psychosocial Ordeals. Emotions are often used as Embodiments by these Plots and that can cause Sides to shift almost randomly as Characters change emotional states.',

            'Plot_Hooks'=>'Emotional Plots can Hook Characters to a specific Side based on nothing more than the Emotions they are feeling, this can create complex shifting Conflicts as Characters change emotional states, and try to recruit others to their side. Note that there will often be a more secured Embodiment Characters and at least one External Monster Embodiment in such Plots.',
            'Plot_Influence'=>'An Emotional Plot will cause any Character Embodiment who has not caused, or is not suffering from, an Emotional Effect to <strong>Gain Stress</strong>. So if kill-bots are swarming outside the cabin, dropping Fear effects on the those inside, anyone not Scared is getting Stressed instead. Emotional Plots may add up to 2 Monster Facets to any Character Embodiment, if the genre and setting allow.',

            'Pulled_Embodiments' => 'Pulled Embodiments will suffer an additional card to all emotional effects (to a maximum of 3). Pull Embodiments may reveal 2 Monster Facets if genre and setting allow.',
            'Pushed_Embodiments' => 'Pushed Embodiments will add an additional card to all emotional effects that they cause in others. Push Embodiments may reveal 2 Monster Facets, if setting and genre allow. ',
            'Hidden_Embodiments' => 'The Hidden Embodiment will project all the sides of their Conflict upon other Characters creating Projected Pull and Push Embodiments. Hidden Embodiments may reveal a Monster Facet if allowed by genre and setting.',
            'External_Embodiments' => 'At least one side of the Conflict (usually the Above or Dominant Side) receives an additional External Embodiment, in addition to any other Embodiments. Quests, Emotions and Psychosocial Ordeal Embodiments are favoured.  Monster Embodiments may reveal upto 7 Monster Facets.',
            'Drama_Pool_Limit' => 7,
            'Dramatic_Stress_Limit' => '3'
        ) ,
        array(
            'Suspense_Level' => 8,
            'Type' => 'Intense',
            'Description' => 'This is the level of suspense that you might feel when you are overwhelmed with anxiety, momentarily afraid for your life, or you witness something traumatic occuring. This is where things often peak for suspense. Something must happen now, this is when someone pulls a gun, transforms into a werewolf, or a bomb is tossed into the room. There is a chance things may descalate from here, but it is slim.',
            'Scene_Description'=>'Intense Scenes come in two main types, simple and complex. The simple type focuses its intensity on a single aspect of the Conflict, but makes it important to the point of being unignorable. The complex type is about clutter, lots of Characters, doing lots of things, at the same time, in the same space so they all interact.',
            'Level_Trigger_Event'=>'This level of suspense is triggered if any Pushed Embodiment Characters face off against each other while armed, or if Pulled Embodiment Characters create 3 card Psych effects in any Character Embodiment.',
            'Plot_Behaviour' => 'An Intense Plot is focused entirely upon working the Conflict by any means. Characters are expected to interact, fight, perhaps even try to kill each other.',

            'Plot_Hooks'=>'Intense Plots tend to focus their energy on Hooking specific Characters, they rarely bother Hooking backups for those Characters, as Character Death is an acceptable conclusion for these Plots.',
            'Plot_Influence'=>'The Intense Plot will cause any Embodiment Character to <strong>Gain Stress</strong> who does not react to the situation. In other words, when the kill-bots break the window, you better start fighting or running. Intense Plots can add 3 Monster Facets to any Character Embodiment (Facets are chosen from their Side or Neutral Facets). Intense Plots add an Automatic Failure Level to the Actions of all Characters on the Pressed or Below Side in the Scene.',

            'Pulled_Embodiments' => 'Pulled Embodiments are compelled to act somehow. They might be forced to run, fight, scream, or attack (perhaps with a Positive Psych Effect). If genre and setting appropriate a Pulled Embodiment may reveal upto 3 Monster Facets.',
            'Pushed_Embodiments' => 'Push Embodiments are compelled to react to any other Embodiments, typically by attacking (although this may be a Positive Psych Effect). Pushed Embodiments may kill another Push Embodiment (or Monster). May reveal upto 3 Monster Facets if appropriate to genre and setting.',
            'Hidden_Embodiments' => 'Hidden Embodiments are at their most intense at this level. They may reveal 3 Monster Facets if appropriate to genre and setting. Even these Monsters will create or Project external fake Embodiments to fight themselves.',
            'External_Embodiments' => 'Any Side with a Character in the Scene will also have an External Embodiment. These External Embodiments are often used as the Automatic Failure Levels for Characters on the Pressed Side. Monster Embodiments may reveal upto 8 Monster Facets.',
            'Drama_Pool_Limit' => 5,
            'Dramatic_Stress_Limit' => '2'
        ) ,
        array(
            'Suspense_Level' => 9,
            'Type' => 'Bloody',
            'Description' => 'This is the level of suspense most of us only experience when we are genuinely worried we might die, traffic accidents and heart attacks being the most common forms. Suspense in the scene is about how badly injured everyone is going to get. Direct Rational Conflict between Embodiments is now the only real way the Conflict can be resolveed. This is the highest level of Suspense possible without a Character dying.',
            'Scene_Description'=>'Bloody Scenes are usually fights, although they can range from bare knuckle boxing, to duels, to pitched battles. Typically Actions taken by any Character suffer 1 or 2 Failure Levels.',
            'Level_Trigger_Event'=>'This level of suspense is triggered if any Embodiment Character is wounded with any Wound greater than a Distract, or any Character is Maimed, Crippled, or Mortally Wounded.',
            'Plot_Behaviour' => 'A Bloody Plot will try to bring about a situation where one Character Embodiment must Maim, Cripple, Mortal or Carnage Wound another. Bloody Plots raise the Stakes to at least High.',

            'Plot_Hooks'=>'A Bloody Plot typically will not replace lost Character Embodiments, instead use External Embodiments such as Obstacles or Monsters.',
            'Plot_Influence'=>'Bloody Plots can add additional Monster Facets to any Character Embodiment. A Bloody Plot can cause any Embodiment to <strong>Gain Stress</strong> if they have not been Wounded so far in the Ordeal Phase, Stage, Round or Scene. So when the kill-bots dive at the group, if random chance means three of the group are not injured, they each Gain Stress instead. Bloody Plots can reveal upto 3 Monster Facets.',

            'Pulled_Embodiments' => 'Pulled Embodiments are often overwhelmed by their emotions, which can cause them to experience or cause heartbreak. May reveal upto 4 Monster Facets (their Side’s Facets or Neutral to the Conflict) if appropriate to the genre and setting.',
            'Pushed_Embodiments' => 'Pushed Embodiments may feel compelled to attack and kill, which, depending upon genre and setting may result in them taking 3 card Psych effects and picking up Traumas or Hitches. Violent Pushed Embodiments may even enter a beserk or overkill state, attempting to purge all other Pushed Embodiments from the Conflict.May reveal upto 4 Monster Facets (their Side’s Facets or Neutral to the Conflict) if appropriate to the genre and setting.',
            'Hidden_Embodiments' => 'Hidden Embodiments now behave as both Pushed and Pulled Embodiments. Hidden Embodiments may reveal upto 4 Monster Facets.',
            'External_Embodiments' => 'Every Side should have at least 2 External Embodiments present in the Scene. Monster Embodiments may reveal upto 9 Monster Facets.',
            'Drama_Pool_Limit' => 4,
            'Dramatic_Stress_Limit' => '1'
        ) ,
        array(
            'Suspense_Level' => 10,
            'Type' => 'Tragic',
            'Description' => 'Someone has sacrificed themselves, died or been killed. This level of Suspense is only possible following the death of an Embodiment Character, or a similar extreme situation. In most genres this is the maximum suspense level possible. The minimum possible Stakes are Extreme.',
            'Scene_Description'=>'A Tragic Scene is generally pretty miserable for the Pressed side of a conflict, and is often not all roses for the Dominant Side either. Bad things happen to Characters in Tragic Scenes. A Tragic Scene will add upto 5 Failure Levels to Character Actions in the Scene.',
            'Level_Trigger_Event'=>'This level of suspense if triggered if any Embodiment Character dies, or is effected by multiple Carnage or Carnage+ Wounds.',
            'Plot_Behaviour' => 'A Tragic Plot is going to alter the setting, Characters will be killed, Descendants destroyed, Locations burnt to the ground. The ludo-narrative landscape will be changed forever. ',

            'Plot_Hooks'=>'Tragic Plots lose Hooked Embodiments, and that is usually how they decide the outcome of their Conflict. Hopefully the Bad Guys die, and not the Good Guys, but sometimes the Bad Guys will win. Tragic Plots once they have Hooked and revealed their Characetr Embodiments stick with them.',
            'Plot_Influence'=>'A Tragic Plot can add upto 5 Failure Levels to all Actions and it is possible for no Characters to succeed during these Scenes. The Tragic Plot will replace any dead Character Embodiments with additional External Embodiments. Tragic Plots can also add additional Monster Facets (up to Monster X) to any Character Embodiments. The Tragic Plot can cause any Character to <strong>Gain Stress</strong> who has not witnessed a death or died themselves so far in this Scene, Ordeal Round, Stage or Phase (in exteme cases).',

            'Pulled_Embodiments' => 'Pulled Embodiments are often compelled to extreme lengths, they might die to make their point, or prove their love, and will certainly betray family, friends and lovers, or kill under the right circumstances. They also may reveal upto 10 Monster Facets if genre and setting appropriate.',
            'Pushed_Embodiments' => 'Push Embodiments are often compelled to attack and kill any Character Embodiment that they are not allied with, or if no enemies are available the Pushed Character may attack allies, or themselves. Push Characters in any genre or setting will express at least 1 Monster Facet (although they should remain looking entirely human they may exhibit somewhat enhanced strength, speed or toughness, or just a cold, calculating efficiency), and if appropriate to genre up to 10 Monster Facets.',
            'Hidden_Embodiments' => 'Hidden Embodiments are now Pushed and Pulled. They will have at least 1 Monster Facet regardless of genre or setting, and up to 10 are possible.',
            'External_Embodiments' => ' Monster Embodiments may reveal upto 10 Monster Facets.',
            'Drama_Pool_Limit' => 3,
            'Dramatic_Stress_Limit' => '1'
        ) ,
        array(
            'Suspense_Level' => 11,
            'Type' => 'Catastrophic',
            'Description' => 'This is the ultimate level of not just suspense, but Conflict itself. This is Tragic turned up to 11, or stacked tragedies, the tragic deaths of dozens, hundreds, thousands or millions. This is natural disasters, terrorist attacks, total war, or alien invasion territory. The minimum Stakes are Soul or Paradoxical, and few will get out alive.',
            'Scene_Description'=>'A Catastrophic Scene is as bad as things can get for Characters, they are always life changing events, and have a permanent effect on the world of the narrative. Catastrophic Scenes should be few and far between, even Epics rarely have more than one per Volume (although occasionally a Character may experience one as a Hook and a final showdown in a single Arc, but this is rare).',
            'Level_Trigger_Event'=>'This level of suspense is triggered if countless Extras are wiped out by the Embodiment Characters, or all original Embodiment Characters have died, and the Plot’s Conflict remains unresolved.',
            'Plot_Behaviour' => 'A Catastrophic Plot is determined to change the world, destroying Locations, communities, societies, even whole planets in their events. There are no limits placed on Catastrophic Plots, other than their Size (only Arc plots or higher can actually destroy a universe). They can create Monster XIII Character Embodiments or Hook a Patron D&aelig;mon if necessary.  ',

            'Plot_Hooks'=>'Catastrophic Plots will often create and Hook new Characters to replace lost Embodiments, one death will never be enough to decide a Catastrophic Plot, and a Side may be almost completely destroyed in the climax of this Plot.',
            'Plot_Influence'=>'Catastrophic Plots will add Snags, Hurdles and at least 6 Failure Levels to any Actions taken, and  with heroes and allies becoming Monsters, Rivals and villains during the Chaos. Catastrophic Plots cause any Character attempting any Action to <strong>Gain Stress</strong>. May reveal upto 13 Monster Facets on a Character Embodiment, and even incompatible settings and genres allow upto 2 Monster Facets to be revealed.',

            'Pulled_Embodiments' => 'Pulled Embodiments often feel their lives have been destroyed by the Catastrophic Suspense, and many will wish they had died even if they survive. Pulled Embodiments will even turn on those they have been most drawn towards at this time, who they have protected up until now. They may reveal upto 13 Monster Facets.',
            'Pushed_Embodiments' => 'Pushed Embodiments are typically completely psychotic, transformed into Monsters regardless of the genre, you might find them engaging in cannibalism, rape, senseless murder, bathing in the blood of their (former) enemies, or wearing the skins of the dead. If more than one Pushed Embodiment remains you can bet they are fighting each other, regardless of who is caught in the cross-fire or collateral damage, even their own safety or survival is unlikely to be a concern for them compared with their urge to destroy. Often their own allies will have to put them down. They may reveal at least 2 and upto up to 13 Monster Facets.',
            'Hidden_Embodiments' => 'Hidden Embodiments are not longer possible, they will behave as Pushed, Pulled and Monster Embodiments simultaneously. They may reveal at least 2 and upto 13 Monster Facets.',
            'External_Embodiments' => 'All Sides should have at least 4 External Embodiments at all times.  Monster Embodiments must reveal all Monster Facets.',
            'Drama_Pool_Limit' => 2,
            'Dramatic_Stress_Limit' => '0: Any Stress may create Drama'
        ) ,
    );
    private static $suspenseDramas = array(
        array(
            'Roll' => 1,
            'Card' => 'Diamonds <span class="t13ne-redcard">&diams;</span> 2-10 Pips',
            'Type' => 'Atmospherics',
            'Description' => 'Atmospherics are simple "Flavour-text" events like torches guttering in the wind, changes in the weather, curtains flapping in a breeze, strange howls in the distance, raised voices out in the street, or whispering in the darkness. Atmospherics usually have nothing to do with the Conflict, but help to build Suspense in the Players and ground the adventure showing a passage of time. Atmospherics can be used to foreshadow later events (the howl in the distance is the wolf pack that should be hunting the party in the late Loom)',
            'Stress_Relieved' => 1
        ) ,
        array(
            'Roll' => 2,
            'Card' => 'Hearts <span class="t13ne-redcard">&hearts;</span> 2-10 Pips',
            'Type' => 'Narrative Moment',
            'Description' => 'Narrative Moments are small (often social) moments in the Character&#39;s life. These are intended to give us insight into the Character and who they are. Narrative Moments are specified by Facet and can tie to the Conflict especially at higher Suspense Levels, but are usually randomly determined.',
            'Stress_Relieved' => 'Varies as the Character’s Facet Dice.'
        ) ,
        array(
            'Roll' => 3,
            'Card' => 'Spades <span class="t13ne-blackcard">&spades;</span> 2-10 Pips',
            'Type' => 'Hazard',
            'Description' => 'Hazards are some danger, threat or risk to the Characters. Hazards can be as simple as an imposed number of Failure Levels (1 to Current Suspense Level), an Ordeal Obstacle or Facet Hurdle, where something gets in the way of their investigation or adventure, or it can be a Snag or Fray in its own right. Some gamers will be familiar with Hazards as an encounter with a trap, wandering monster or guards.',
            'Stress_Relieved' => 'Varies 2+'
        ) ,
        array(
            'Roll' => 4,
            'Card' => 'Black Cards <span class="t13ne-blackcard">&clubs;</span> &amp; <span class="t13ne-blackcard">&spades;</span> 11+ Pips (includes Black Joker)',
            'Type' => 'Prod',
            'Description' => 'Prods are meant to force a Hooked Character to pay more attention to the Plot. If the Referee or Yarn-Teller has noticed a Character isn’t particularly engaged, or isn’t acting as Tense as the Suspense Level suggests, then the Yarn-Teller should use a Prod. The idea of a Prod is to raise the Suspense, accelerate the Story and push things forwards, how hard the Character need to be Prodded is up to the Yarn-Teller.',
            'Stress_Relieved' => 2
        ) ,
        array(
            'Roll' => 5,
            'Card' => 'Red Cards <span class="t13ne-redcard">&hearts;</span> &amp; <span class="t13ne-redcard">&diams;</span>11+ Pips (includes Red Joker)',
            'Type' => 'Break',
            'Description' => 'Breaks are used by the Yarn-Teller to slow the pace of the Story down. If a Character is making too much progress too quickly, or if the Suspense has risen too quickly, or higher than intended, or most Characters acting more nervous and jumpy than the Suspense Level and Stakes suggests then the Yarn-Teller should consider using a Break.',
            'Stress' => 'All Current Stress'
        ) ,
        array(
            'Roll' => 6,
            'Card' => 'Clubs <span class="t13ne-blackcard">&clubs;</span> 2-10 Pips',
            'Type' => 'Ratchet',
            'Description' => 'Ratchets are the way the Yarn-Teller (or a Plot) applies a direct connection between the Suspense, Stress and the Narrative. Ratchets imply a change in circumstance in the Story, that might indicate how alert the local guards are, or how agitated the spirit world has become, or how close to eruption the volcano is. Most often the Ratchet will Ratchet together the Dominant and Pressed Sides Embodiments. Ratchets can tighten and sometimes loosen based on the Suspense Level and Narrative.',
            'Stress_Relieved' => 'Varies 2+'
        ) ,
    );
