        array(
            'Type' => 'Neighbours',
            'Description' => '2 cards with sequential values from any suit e.g. 10<span class="t13ne-blackcard">&spades;</span> and J<span class="t13ne-redcard">&diams; </span> Neighbours can be Suited making them slightly more powerful. Neghbours are also known as Shorts, Sequences and Short-runs.',
            'Rule' => 'Neighbours usually grant the Player a Promise. Suited Neighbours also add an Advantage.'
        ) ,
        array(
