		<marker id="b" overflow="visible" orient="auto">
			<path transform="matrix(-.8 0 0 -.8 -10 0)" d="m0 0 5-5-17.5 5 17.5 5z" fill="#009ef8" fill-rule="evenodd" stroke="#009ef8" stroke-width="1pt"/>
		</marker>
		<marker id="c" overflow="visible" orient="auto">
