    public static $playerTypes = array(
        array(
            'Type' => 'Actor',
            'Description' => 'Actors play a Character, but don’t have any ability to Create or Alter them. This usually makes them reliant upon an Author to create their Character. Some games limit all players to this role alone.'
        ) ,
        array(
            'Type' => 'Artist',
            'Description' => 'Artists can create Descendants and Characters, but usually don’t play them. Artists are usually considered specialised Authors. Sometimes combined with Narrator to make Set-Dresser.'
        ) ,
        array(
            'Type' => 'Author',
            'Description' => 'Authors can create Games, Settings, Plots, but they usually don’t play them. Auuthors can also create Characters and Descendants and may play them as a Player.'
        ) ,
        array(
            'Type' => 'Director',
            'Description' => 'Directors are a combination role, that combines Author and Narrator. The Director generally modifies a Story and narrates that story to the others. Directors usually rely on a separate Referee. This is often a Yarn-Teller play style.'
        ) ,
        array(
            'Type' => 'Editor',
            'Description' => 'Editor is a specialised role that involves deciding what the next Scene will be, will it be a Scene from the current Plot, a Sub-Plot, or something else entirely? Often this role is combined with Referee.'
        ) ,
        array(
            'Type' => 'Game-Master',
            'Description' => 'Game Master (GM) is a combination role that combines Editor, Trouper, Referee, Narrator (occasionally Raconteur in the case of GMPCs) and Author. This combination of roles is quite normal in traditional roleplaying games, although less common now than it was in the wilderness-between-dungeons years.'
        ) ,
        array(
            'Type' => 'Narrator',
            'Description' => 'A Narrator narrates reactions to the Players usually in the second and third person, describing descendants, events and situations to the other Players. The Narrator role is often combined with that of Referee to create a Games-Master.'
        ) ,
        array(
            'Type' => 'Player',
            'Description' => 'A Player is a combination role common to roleplaying games that combines the Artist and Actor roles. Players create their own Characters and play them themselves. In T13 we also can add Raconteur and Author to this list, if they are playing a Yarn-Teller Character.'
        ) ,
        array(
            'Type' => 'Raconteur',
            'Description' => 'A Raconteur is a Narrator who tells the story from their own Character’s point of view. This is most common with Yarn-Teller Characters.'
        ) ,
        array(
            'Type' => 'Referee',
            'Description' => 'A Referee has the job of interpreting the Rules of the Game. The Referee is often just an aspect of the Games Master, who has additional responsibilities.'
        ) ,
        array(
            'Type' => 'Set-Dresser',
            'Description' => 'Set-Dressers combine artist (or even author) and narrator. They design locations and narrate their appearance to the others.'
        ) ,
        array(
            'Type' => 'Trouper',
            'Description' => 'Actors who specialise in playing NPC Characters, especially Extras. It is often combined with Narrator, but can be a separate player'
        ) ,
    );
    public static $playerPlayTypes = array(

        array(
            'Type' => 'Ambitious',
            'Description' => 'The Ambitious Player wants to rule the world, or at least a significant portion of it. They will engage with Plots mostly as a way to make Gains and increase their Character’s power, until they can begin to influence the Plots, by perhaps deciding to attack the Lord of the Land or King. Ambitious Players can be a problem for some Yarn-Tellers, unless you accept that they will want to take on your political leaders, and upset your status-quo.'
        ) ,
        array(
            'Type' => 'Antagonist',
            'Description' => 'The Antagonist Player always seems to believe the same thing, first that only their fun is important, secondly that the goal of the game is to "beat" the Referee or Yarn-Teller. Antagonist Players will often be disruptive to the game in general, as they refuse to understand why anyone else should get to have fun. Antagonists can appear similar to many of the other types of player, but often closest to Cheaters, in that they just don’t really understand the game.'
        ) ,
        array(
            'Type' => 'Character-Actor',
            'Description' => 'The Character-Actor Player only cares about their character, they may give a hoot about the Plot, but only because it affects their character and they see some interesting possibilities to the story-line. Character-Actor Players have a lot of similarities to the Drama Llamas, but they are less dramatic and more just players in love with their own character. Character-Actors can be a lot of fun, but Yarn-Tellers and Referees need to be careful of disrupting the Character-Actor’s character, as they can react very poorly.'
        ) ,
        array(
            'Type' => 'Cheater',
            'Description' => 'Cheaters are just no fun to play with. They will fudge dice rolls, calling out Scores that are just far too high, or low, to be reasonable. Card Play will reduce their chances to cheat, but not by much, Referees should keep an eye on their Ordeal Pools and how often they "forget" their Ordeal Pool Limit. Cheaters cheat because they want to feel powerful, sit them next to the Klutz and they should be fine. Never seat them near a Noob unless you want two Cheats at the table and then to pit them against each other. Cheaters don’t understand fair play and usually believe everyone is like them. Cheaters can be easily confused with the Antagonist as there is often a misunderstanding of what the game is, or a failure to understand that their actions at the table effect the fun of the other players.'
        ) ,
        array(
            'Type' => 'Chronicler',
            'Description' => 'The Chronicler Player is usually noted by the copious notes that they take on the game. Chroniclers like good, engaging stories, full of twisting Plots and complex Characters and settings. Chroniclers can appear disengaged from time to time, or may appear like a Thinker, but usually you don’t have to worry about them, as long as the Plot is keeping them writing, they are actually having fun. You can spot a Chronicler by their ability to quote entire sections of previous games, and recap details that Yarn-Tellers might have forgotten.'
        ) ,
        array(
            'Type' => 'Collector',
            'Description' => 'The Collector player is always looking for something. Often they favour collecting magical items and spells, that they think may help them in the future, or simply for completenesses sake. Collectors can be entertained by providing plenty of fun Descendants for them to collect, and especially choices between Descendants that they might want.'
        ) ,
        array(
            'Type' => 'Comedian',
            'Description' => 'The Comedian Player is just there to have fun, sometimes at the expense of the other Players enjoyment. They commonly make out-of-character jokes, and have been known to ignore the entire point of a Plot because they are working on a one-liner. Comedians can be great to play with, making for a fun table experience, but the Yarn-teller will have to work harder to keep everyone else engaged in the plot. Ideally, the Comedian should be playing a comic-relief character to minimise any disruption they may cause.'
        ) ,
        array(
            'Type' => 'Curious',
            'Description' => 'Curious Players explore and ask questions. They can be rather like a Simulationist in that regard. However, they will focus on any apparent mysteries they find, rather than realism.'
        ) ,
        array(
            'Type' => 'Disengaged',
            'Description' => 'The Disengaged player is usually spotted by the fact that during the game they are distracted, or ignore the other players entirely. They may be on social media, or playing another game, this is not the same as momentary disengagement, where a Player’s Character is away and so they may do something else for a bit, until the Referee or Yarn-Teller gets back to them. These Players seem to be uninterested in what is happening, and often are only present because they are accompanying someone else to the group. Yarn-Tellers can try and engage a disengaged Player, but this can create a Ref Hog situation instead. Rather the other Players should be encouraged to engage the Player, especially a Socialiser or Comedian, as they will largely entertain themselves until you get around to what they are up to again.'
        ) ,
        array(
            'Type' => 'Drama Llama',
            'Description' => 'These Players are some of the most in-depth Role-players. They want situations and Narratives that offer them a chance to act out a wide variety of emotions, but especially seem to love angst-ridden teenage protagonists. If the Narratives and Plots don’t give them opportunities for drama, you can count on them to create their own, which can be quite disruptive to a Dungeon / Hex crawl or similar game.'
        ) ,
        array(
            'Type' => 'Edge-lord',
            'Description' => 'Edge-lords (and the much rarer Edge-Lady) are players who can dominate and ruin games. They want "edgy" or "cool" content, by which they mean content with shock-value. If Plots and situations do not grant the Edge-Lord their shocks, rather like the Drama Llama Player, they will create that shock themselves, and you may experience Edge-Lord players who declare they will rape or kill other Characters for no reason. Edge-lords can sometimes be controlled, often by simply making them responsible for the consequences of their own actions. Crime committing Edge-lords should find themselves wanted by the law, etc. Edge-lords are generally toxic, do not play well with other types, and should be avoided if possible.'
        ) ,
        array(
            'Type' => 'Engineer',
            'Description' => 'Engineer Players like to tinker with the system, usually creating Descendants for themselves or other Player Characters to use. Occasionally, they will try and sell their inventions for profit, for the Yarn-Teller this can be a good Plot, or be unbalancing to the status-quo, depending on the game setting and what the Engineer created. Engineer Players are best engaged by the Plot giving them things to build, and problems to solve, just be careful, as you may have to ban something they have made, perhaps like how the gun was known of, but banned, in medieval Japan.'
        ) ,
        array(
            'Type' => 'Explorer',
            'Description' => 'The Explorer Player always wants to go and see. They are similar to the curious player, but are not bothered by Mysteries as such, they just want to see what’s over that hill. Yarn-Tellers should prepare plenty of Locations for the Explorer to explore. They favour Dungeon and Hex crawl geo-plot style games.'
        ) ,
        array(
            'Type' => 'Immersive',
            'Description' => 'The Immersive Player is looking to completely immerse themselves in their character and the World. Sometimes Plot and game mechanics can annoy the immersive player as they drag them out of their immersion. A good Referee should allow the immersive players their immersion, but not at the expense of others fun, if everyone is immersive and they are all working well together then let it stand. Immersive Yarn-Tellers can get carried away and may need to be reined in by other players and the Referee occasionally.'
        ) ,
        array(
            'Type' => 'Klutz',
            'Description' => 'Klutz Players are exactly that, they live in a world of haunted dice that never roll higher than half, and often roll minimum, if they draw cards they draw low. T13 is generally balanced to let them do something, but really unlucky Klutzes can ruin a game with their bad rolls and terrible luck. Yarn-Tellers should be wary of the Klutz, they don’t mean to but they can always mess anything up, and will usually at the worst possible time.'
        ) ,
        array(
            'Type' => 'Munchkin',
            'Description' => 'The Munchkin Player can appear like an Ambitious type, the Antagonist, the Murder-hobo, or the Edge-lord, but they are not the same. Munchkins will attempt to power-game, creating Characters with huge, but unlikely to be triggered Hitches, and favour powerful Annexes with vague names. They see situations as competitive, even when they are not, and may even talk about beating the Yarn-Teller or Referee, by ignoring as much of the Plot as possible. Some Munchkins can try and exert their play style on other Players, and this can quickly become toxic. Munchkins will often bend and break rules if the Referee is not watching them carefully.'
        ) ,
        array(
            'Type' => 'Murder-hobo',
            'Description' => 'The Murder-hobo Player cares little about the Plot, Conflict or World. They just like killing things. They can be a very disruptive player type, especially to complex narratives, but are easily pleased by simple dungeon crawls and the like.'
        ) ,
        array(
            'Type' => 'Noob',
            'Description' => 'The Noob Player doesn’t know much about how this all works, they may need extra Referee or Yarn-Teller time, or need help with aspects of the system or role-playing in general. Noobs often need reminding of rules, procedures and what is expected of them. Some Players never leave Noob status and always need reminding what they have to roll, or when to Draw or Play cards, which can be quite frustrating for others. Try to be patient, they don’t do it on purpose, and will eventually learn, if encouraged to.'
        ) ,
        array(
            'Type' => 'Old School',
            'Description' => 'Old School Players cut their teeth on the boxes and books of games like Tunnels and Trolls, fighting fantasy books, and that game that came in a Basic Blue (or was it Red?) Coloured Box. They come from a simpler time, when the skills of the Player were more important than the skills of the Character, and beating the Scenario often left a trail of PC corpses through each level. These are Players that will strategize with the Strategist, explore with the Explorer and think with the Thinker. They want new challenges constantly, but not so new that it doesn’t fit what they think of as role-playing. They will accept a Total Party Kill much more easily than they will a PC becoming the Yarn-Teller for a while. Kept happy, they are amongst the best, but be wary of going against the gods of the Old School...'
        ) ,
        array(
            'Type' => 'PVPer',
            'Description' => 'The PVPer Player doesn’t believe in things like party cohesion, or morals. They will terminate another PC for the lint in their pocket on a good day. PVPers see the rest of the Players as potential trophies, unless they are currently useful to the Player (or less often the Character). Such Players live in a zero sum world where if someone else is doing well that must mean they are doing badly, and that situation will require rectifying. Yarn-Tellers can keep PVPers in line by providing diverse challenges that ideally make other Characters important to the PVPer’s survival and success.'
        ) ,
        array(
            'Type' => 'Ref Hog',
            'Description' => 'The Ref Hog Player is always trying to get the Referee or Yarn-Teller to engage solely with them. They can be recognised by the way they will interrupt other Players to ask the Referee or Yarn-Teller questions that only affect their Character, not the party as a whole. Sometimes Ref Hogs are actually asocial people, or are just really engaged with their own Character’s position and stake in the Plot and enthused about the game, and they may not realise what they are doing. The Yarn-Teller may need to implement a Spotlight, or talking stick system to stop the Ref Hog from frustrating the rest of the group.'
        ) ,
        array(
            'Type' => 'Rules Lawyer',
            'Description' => 'Rules Lawyers learn the system inside and out, and will always know where to find the rules they think will save them from whatever situation the Yarn-Teller has planned. Rules Lawyers can work in any game, especially if you convert them into Rules Barristers/Attorneys, where they can baby sit and teach the Noobs.'
        ) ,
        array(
            'Type' => 'Simulationist',
            'Description' => 'These Players like details, and realism in their Narratives and Settings. They expect a lot from their Yarn-Tellers, and will always ask questions about details the Yarn-Teller is unlikely to have considered. Yarn-Tellers have to remain consistent, and very well prepared (which inevitably means additional work on the Plots) if they wish to keep them engaged. Simulationist Yarn-Tellers will be generally detail orientated, but many may miss big-picture issues resulting from character actions.'
        ) ,
        array(
            'Type' => 'Socialiser',
            'Description' => 'The Socialiser Player plays just to socialise with the others at the table, they will engage in the Plots and so on if everyone else is engaged, but will require more face time with the Yarn-Teller and Referee as they engage in long conversations with every bartender and shopkeeper in the land. A good Yarn-Teller should bear in mind the Socialiser, and create a few talkative gossipy characters in every township and village, as well as some gossip for them to share.'
        ) ,
        array(
            'Type' => 'Story-Teller',
            'Description' => 'Story-Tellers are sort of the opposite of Old School Gamers. They don’t want complex, and deadly traps, or asymmetric random encounters, they want collaborative story-telling, where everyone builds on what has come before and no one is really going to win. They are the first to adapt to Yarn-Telling, but can feel hemmed in by the rules and other players from time to time. They rarely play well with Old School Players, unless there are clearly established ground rules between the two styles.'
        ) ,
        array(
            'Type' => 'Strategist',
            'Description' => 'These Players like complex combats, where they can use their knowledge of the system and warfare to some advantage. They tend to dominate combat, and may be difficult to provide suitable challenges for. Strategists can be amongst the first to make the move to Yarn-Telling, but they and the Referee should be aware their Strategies may make for a Total Party Kill if there are no other good strategists at the table.'
        ) ,
        array(
            'Type' => 'Thinker',
            'Description' => 'The Thinker Player is one of the hardest to run for. They typically can be like the Curious or Simulationist Player, but often they will silently listen to what is happening around the table, before they finally tell the Yarn-Teller what they are going to do. Thinkers have a habit of seeing through complex ruses and logic puzzles, although they may let others walk into danger before they reveal that they have seen it coming. The Thinker, unlike some other types, isn’t doing this maliciously, it is just that by staying quiet they know they will get more data. Thinkers are best engaged by random surprises, these will often get them to talk about how their expectations are being subverted.'
        ) ,
        array(
            'Type' => 'Warrior',
            'Description' => 'The Warrior Player can appear similar to the Strategist, PVPer, Edge-lord and Munchkin, but actually they just like any combat. The Warrior likes challenging combats and situations, they like to win, but want that win to be hard fought. They will occasionally abandon good strategy to make things harder for themselves, and so can be hard to keep alive.'
        ) ,
        array(
            'Type' => 'Wizard',
            'Description' => 'The Wizard Player just wants to be the best at what they do, which is usually throwing spells around, but could be hacking computers, or being a martial artist, etc. Wizards can be similar to the Old School and Thinker players, in that they like thinking outside the box, but unlike them, they will always try to bring everything back to their specialist skill, be it throwing a spell or hacking a computer. As long as a Wizard’s skills are useful to a Plot, they will be engaged, but the moment they feel useless, they can become incredibly disruptive.'
        ) ,
    );
    public static $bulmasArchetypes = array(
        array(
            'Type' => 'Ant',
            'Description' => 'Ant characters are strong, physically and mentally, they are very social and communicative, believing in teamwork, loyalty and duty. Their only failing is perhaps that they are overly confident and this can lead them to bite off far more than they can chew in some situations. Ants are so social that many are capable of swarm forms, controlling multiple bodies at once, although such control is often limited in either number of forms or precision of control, large swarms are difficult to coordinate well.'
        ) ,
        array(
            'Type' => 'Antelope',
            'Description' => 'Antelope characters are graceful and athletic, they are quick thinkers, and unfortunately are quick to jump to assumptions. They can seem paranoid to some people, always assuming the worst of any situation, and then running in terror, but often this will keep them safe. Antelope Souls often develop the ability to leap from one Lea path to another, throwing themselves across the Lea almost instantly. This ability can be further developed into an abilty to teleport instantly through the Lea about as far as they can normally jump.'
        ) ,
        array(
            'Type' => 'Ape',
            'Description' => 'Ape characters are sometimes split into two types, quiet, peaceful, gentle intelligences and raucous, violent, strong beasts, but the truth is they are both. While they are thought of as vegetarian, only a few apes will turn down meat when they can get it, and most eat insects from time to time. They can even be patient, planning and brutal, striking in deadly ambushes and rampaging highly coordinated hunting parties.'
        ) ,
        array(
            'Type' => 'Armadillo',
            'Description' => 'Armadillo characters are seen as trust-worthy, peaceful and compassionate, and unless you are an insect this is probably true. They are a predator who look and act more like prey, and often have more in common with Field Bulmäs than their Followers brethren. Armadillo Souls often develop an ability to create a barrier or boundary effect around themselves that can protect them from most spiritual and a lot of phsyical attacks.'
        ) ,
        array(
            'Type' => 'Badger',
            'Description' => 'Badger characters known as quiet and unassuming sorts, they generally keep to themselves, although they can be quite curious from time to time, they are usually too wise to draw attention to their investigations. Although badgers keep to themselves and are generally quiet, do not assume they are defenceless, as Badgers are strong, tenacious and quite dangerous to animals even as large as a wolf, or a bear. Badger Souls are known amongst the Bulmäs as magicians, capable of manipulating the Lea in strange ways that mimic, and some say improve on, F&aelig;ry magics.'
        ) ,
        array(
            'Type' => 'Bat',
            'Description' => 'Bat characters are one part playful trickster, and another part brave hunter, they can be predator or prey, depending upon the ecosystem and fruit or insect eating as well. Bats are perceptive and cunning, they keep to the darkest shadows and strike suddenly when they attack, often with theatrical or playful flourishes to their plans. They are highly social, but can be manipulative, usually though these manipulations are simply the set-up to some joke or surprise. Bats can occasionally turn nasty, though, and if this happens their theatrics, tricks and manipulations will also become dark and nasty. Bat Souls are known for their ability to perceive other souls, reading them at range as most would taste them, and their ability to tie on souls they taste quickly and precisely, as though they had eaten them. Souls they eat, they often learn secrets from.'
        ) ,
        array(
            'Type' => 'Bear',
            'Description' => 'Bear characters are notable for their strength, patience and aggressive nature, although this can just be their protective nature getting out of hand. Bears, whether actual bears or humans with bear-like qualities are often nurturing, but authoritative figures, commanding respect by their presence alone. Bears have a nature of duality due to their hibernation through the winter, and are regarded as a symbol of devoted motherhood and berserk rage. Bear Souls are known for their ability to sleep in the land, although less capable than Lord Vermis, who can sleep for millenia, Bears can effectively hide their souls amongst all living things, including plants while they hibernate through the winter. Although they sleep, they dream the events their territory experiences.'
        ) ,
        array(
            'Type' => 'Beetle',
            'Description' => 'Beetle characters are amongst the most common amongst the Bulmäs, they are known for their pleasant, sympathetic, and exceptionally optimistic natures. Beetles are considered gifted, although this gift varies, some are perceptive (seeing things others cannot see), some empathic (feeling what others feel around them), others are creative (artists, smiths, and musicians), some are simply beautiful to behold and a final few are gifted magically (able to manipulate luck, or create order from chaos), but they are rarely known for their leadership or intelligence, but are incredible team-workers.'
        ) ,
        array(
            'Type' => 'Bull',
            'Description' => 'Bull characters are known for their incredible strength, toughness, stamina and determination. Bull-like humans and the animals alike are known for their stubbornness and resilience. Bull Souls are among the more aggressive of the herbivores, and they are known to employ weapons as part of their defence of their Field. Bull Souls will often carry paired Horn-blades, sharpen their own horns, or may own a Moon-stave weapon.'
        ) ,
        array(
            'Type' => 'Butterfly',
            'Description' => 'Butterfly characters are seen as beautiful, creative and communicative and joyful souls, often idealistic, and usually optimistic. They are associated with transformations, and many butterfly’s pass through a much darker, depressive phase when younger, sometimes this can be due to a past-life trauma that must be worked around, other times it is about the butterfly discovering something, and realising they can love this discovered part of themselves. Butterfly Souls are known amongst the Bulmäs as the most powerful Lea walkers able to create huge Lea Gates that travel immense distances through the Lea, Butterfly Souls have no problem opening Portals into, or out of, the Lea, in fact, they can find they have difficulty passing into the Lea without bursting open a portal whenever they try. '
        ) ,
        array(
            'Type' => 'Carnivore',
            'Description' => 'Carnivore characters are generic predatory creatures that are not specified elsewhere. They are generally solitary, aggressive, proud, and while never completely stupid they always think they are smarter than they actually are, of course a few are exceptionally smart. Carnivore characters usually have a nomadic lifestyle following prey as they migrate, although some favour a territorial approach as a carnivorous Broccen.'
        ) ,
        array(
            'Type' => 'Cat',
            'Description' => 'Cat characters have an uncommon combination of traits. Cat character is perceptive, wise and intelligent, often to the point of it being uncanny, and hedonistic, seeking physical pleasures where ever they can find them, but they are also introverted and solitary usually, preferring to remove themselves from crowds, as most people irritate them, as they see them as stupid, or unaware. Cats can often seem aloof, unapproachable, but if they choose you as an ally, they can be a great help. Cats, especially the big cats, have a reputation as cold-blooded killers that toy with their kills, this toying is the way the cats practise and perfect their killing techniques. Cat Souls are known to develop very individualistic abilities that can seem magickal, such as their Soul Sight, Soul Whiskers, and '
        ) , //5
        array(
            'Type' => 'Centaur',
            'Description' => 'Centaur characters are very rare, they are known for their incredible knowledge and wisdom, because Centaurs often have incredible memories that can reach back through many incarnations perfectly. Centaurs are the doctors, smiths, theologians, scientists and teachers of the Bulmäs, as well as strong fighters and proficient hunters, this is on top of their beauty and grace which will often let them pass as horses, pterippi or unicorns.'
        ) ,
        array(
            'Type' => 'Centipede',
            'Description' => 'Centipede characters are known for their swiftness, aggression and ferocity. Everything about them is fast and deadly, they are quick to anger, flying into a furious, blinding rage, where they usually throw themselves at their enemy, ignoring everything to attack. Centipedes are so aggressive, and so powerful that even the Vermis consider them a threat. They are anti-social, usually solitary, although they do enjoy some gatherings, especially if they can demonstrate their physical prowess.'
        ) ,
        array(
            'Type' => 'Cephalopod',
            'Description' => 'Cephalopod (squid, octopus, and cuttlefish) characters are intelligent, curious, changeable, and somewhat mischievous, they are the most mercurial tricksters of the oceans. Cephalopod characters are used to having a sub-brain that controls each limb, and this can allow them to walk multiple lea paths simultaneously, creating multiple bodies in potentially separate locations that are still mentally connected. The most a Cephalopod can do this is equal to their Incarna Score.'
        ) ,
        array(
            'Type' => 'Chimera',
            'Description' => 'Chimera characters created by a blend of other animal souls together, a few chimerical types are considered as distinct types. Chimera souls can be considered monstrous by some Bulmäs, but in general they just blend the attributes of their various component souls. '
        ) ,
        array(
            'Type' => 'Cow',
            'Description' => 'Cow characters are social, calm, grounded individuals. Real cows or cow-like people are usually considered pleasant, if not exciting or clever. They may be hard working, and create an abundance, but are usually considered dull, however do not confuse dullness for safe, cow’s are almost as strong as bulls.'
        ) ,
        array(
            'Type' => 'Crab',
            'Description' => 'Crab characters are usually considered selfish and overly emotional, as well as defensive, protective and, of course, crabby. However, the thing about crabs is, they are incredibly adaptable and complex forming surprisingly large social groups. Their body shape has evolved multiple times, as a strong example of convergent evolution, or Bulmäs walking something new onto a crab path.'
        ) ,
        array(
            'Type' => 'Crocodile',
            'Description' => 'Crocodile (and the Alligator and Caiman) characters are liminal characters, often displaying dual natures, that seem oxymoronic or paradoxical, such as being cold-hearted, but emotionally nurturing, or being incredibly patient, but short-tempered. In general, Crocodiles are known for their wisdom, strength, stamina and patience, a crocodile will lay plans months, or years, ahead of time, with an attention to detail that can seem like foresight to others. In fact, it is said that some crocodiles, when appearing to sleep underwater are actually swimming forward in time to see glimpses of the future.'
        ) ,
        array(
            'Type' => 'Crow',
            'Description' => 'Crow characters are seen as mischievous tricksters. Intelligent, flexible, adaptable, and audacious, crows have a reputation for magic, with crows being interested in prestidigitation, pick-pocketing, illusions, transformations and doom-weaving, although their luck learning such skills will vary. Crows are warm and social beings happy to spend time in the company of almost any other beings, and almost completely fearless, although that will get them into trouble from time to time, crows know it can also lead to interesting, and useful friendships.'
        ) ,
        array(
            'Type' => 'Deer',
            'Description' => 'Deer characters are graceful, alert and while they are often seen as quite shy, quick to flee any situation that becomes too tense or dangerous, they are actually remarkably social and perceptive, and love hanging out in crowds, playing games with friends, dancing, eating and drinking, but are excellent at reading cues around them, which means when trouble begins most deer are already gone. Deer can be actual animals or just good-looking, healthy, but slightly anxious people.'
        ) ,
        array(
            'Type' => 'Dinosaur',
            'Description' => 'Dinosaur Characters cover a wide number of different dinosaur species, these are usually large animals that combine lizard, mammal and bird body-parts in weird combinations. Dinosaurs might have horns, beaks, armoured bodies, huge frills of feathers or bone, spiked or clubbed tails, some favour two legs, others four, many swapping between. They are generally seen friendly social beings, not given to academic or intellectual pursuits, unless it is history, but with a rustic folk-wisdom. Some can be belligerent, even aggressive, but this is a protective bluster, and if reassured they will quickly stand-down from battle, but if challenged they fight with deadly weapons to dissuade, injure or kill an attacker.'
        ) ,
        array(
            'Type' => 'Dog',
            'Description' => 'Dog characters are loyal, devoted, brave and trusting, whether a real dog, or a trusted friend, they are great Allies. Dogs are tenacious and unwilling to compromise, which can mean that if their loyalty or trust is abused, they can twist into an angry, dangerous and destructive foe.'
        ) , //12
        array(
            'Type' => 'Dolphin',
            'Description' => 'Dolphin characters are often seen as fun-loving, social, and graceful creatures, full of joy at everything, and ultimately a symbol of freedom, however this is not the full story of dolphin, while they are fun-loving, it is often bordering on hedonism, they are social, but only within their small cliques or pods, and while they are graceful, it can be a brutal grace. Dolphins are an embodiment of freedom, but that also means they are free to do as they will, often without consequences falling upon them, and egged on by their friends this freedom and hedonism can become selfishness and abuse.'
        ) ,
        array(
            'Type' => 'Donkey',
            'Description' => 'Donkey characters are perceived as strong, capable and long-suffering, they are friendly and range from wise to comically stupid in nature, but even the wise are slow, plodding thinkers. Donkeys are not as quick or as powerful as horses, but they are stalwart companions and often braver and more loyal than horses alone, and can have a calming effect on horses.'
        ) ,
        array(
            'Type' => 'Dragonfly',
            'Description' => 'Dragonfly characters are known as ferocious carnivores, with lightning fast reflexes and incredible vision. For a while all the Dragonfly souls were bound to Vermis, but increasingly since Teucoi walked the all-path more Dragonflies have appeared among the Hunting parties. Dragonfly Bulmäs are notable as having no sense of smell, nor any ability to process smells in other body forms, but they compensate by processing visual and sound information much more quickly than anyone else, always granting them an automatic success on any speed or reaction-time based Tests, including Ordeal initiative.'
        ) ,
        array(
            'Type' => 'Duck',
            'Description' => 'Duck characters are known for their incredible stamina, although they are not the smartest, occasionally confusing themselves and others as they try to communicate too much too quickly, they are very adaptable, loving and friendly folk, quickly adapting to new situations. '
        ) ,
        array(
            'Type' => 'Eagle',
            'Description' => 'Eagle characters are known for their nobility, majesty and power. They are often perceptive or even visionary, and others look to them for inspiration and leadership automatically, but they can be arrogant, aloof and overbearing.'
        ) ,
        array(
            'Type' => 'Elephant',
            'Description' => 'Elephant characters are known for their size, strength and memory, they are recognised for their wisdom and ability to remove barriers also. Their strength can be physical, mental, spiritual, or even supernatural in nature.'
        ) ,
        array(
            'Type' => 'Fish',
            'Description' => 'Fish characters are social with their own kind, but can be aloof or timid around anything strange or unknown. Fish characters are generally emotionally reserved, and can seem cool or even cold to most people, but they are completely open with those closest to them.'
        ) ,
        array(
            'Type' => 'Flea',
            'Description' => 'Flea characters are cowardly, quick to leave at the slightest sign of danger, but are determined, they will return as soon as their fear subsides. Fleas are selfish, social as far as it is getting them something, but quick to abandon those around them for a better situation if it is presented. Flea characters are perceptive and sensitive to changes in their environment that others may not notice, and fleas can tell as lot about something from a taste, even learning from the blood they drink. This can make fleas very knowledgeable and even capable of magical acts.'
        ) ,
        array(
            'Type' => 'Fowl',
            'Description' => 'Fowl characters (whether chicken, peafowl, partridge, or turkey) are known as determined, enthusiastic, and somewhat proud beings, they are social beings, mixing often with others. Fowl characters are known to be balanced in their approach to life, they are bold to a point, but know when to take flight, and they often have a knack for lateral thinking, and find new uses for old things. Fowl characters are often noted for having a habit of uncovering the truth.'
        ) ,
        array(
            'Type' => 'Fox',
            'Description' => 'Fox characters are known to be cunning, perceptive, wise and of a protective nature, playful and fun-loving, but they are also known to be greedy, wantonly destructive and hedonistic. Foxes are nocturnal hunters that hide and play by day, but they are also strong tunnelers and are many are known to dig tunnels through the Lea that can allow them to view a few days ahead or behind themselves in a given area. This adds to their trickster nature allowing them to retro-actively set up traps and escape routes that can seem magical.'
        ) ,
        array(
            'Type' => 'Frog',
            'Description' => 'Frog characters are known as being incredibly social, talkative and noisy individuals, they are considered dual-natured by some, because of their amphibious lifestyle, and are associated with a knowledge of poisons and medicines, that they may use capriciously to delude, confuse and harm, as well as cure illnesses, aid and even renew others. Frogs are often prosperous and associated with fertility, some can even control the weather to benefit the lands they live in.'
        ) ,
        array(
            'Type' => 'Giraffe',
            'Description' => 'Giraffe characters are seen as aloof and graceful, and it is true that they are peaceful and have a protective nature, and giraffes are known for their, at times, clairvoyantly perceptive foresight, but their alleged aloofness is more often shyness, and their grace while present is required, without grace a giraffe is comically clumsy.'
        ) ,
        array(
            'Type' => 'Goat',
            'Description' => 'Goat characters are known for their persistence, determination, greed, and general fearlessness. Goat characters can often appear foolish, as their bravado and stubbornness will get them into a lot more trouble than it gets them out of, however goats know this about themselves and will often have some back-up plan or have made some provision to get themselves out of the trouble they get into. Goats are intrepid, and industrious, leaping where few other beings dare to tread, always pushing and breaking through barriers to find new exploitable fields.'
        ) ,
        array(
            'Type' => 'Griffin',
            'Description' => 'Griffin characters are seen as regal, majestic, and guardian beings, they are powerful predators, marked by their highly perceptive nature, valorous bravery and deadly sharp claws and beak, but are also highly territorial, this is due to their often Broccen like nature. They are the only predatory Bulmäs who claim Broccen territories apart from Vermis. Some Bulmäs believe that Griffin souls were actually created by the Broccen using their chimerical abilities, to act as guardians around Broccen territories.'
        ) ,
        array(
            'Type' => 'Hawk',
            'Description' => 'Hawk characters are focused, competitive and often aggressive. Whether a human being with a particularly war-like attitude, or an actual bird, hawks are energetic, protective and strategic thinkers, as well as predatory. They will strike at an enemy’s weaknesses, ideally without warning, and will not relent or waiver. The hawk’s singular focus can be a weakness, as it can cause it to overlook something it should easily have seen.'
        ) ,
        array(
            'Type' => 'Hedgehog',
            'Description' => 'Hedgehog characters are seen as gentle and protective, curious but timid, but many also forget that they are predators, as well as prey, and in fact they could be better described as cool and collected rather than gentle. Above all else, hedgehog characters are practical, they are resourceful and intelligent enough to avoid trouble.'
        ) ,
        array(
            'Type' => 'Herbivore',
            'Description' => 'Herbivore characters are generic prey animals that are not specified elsewhere. Generally Herbivore characters are social, affable, friendly, but can be shy or timid especially around strangers or in unfamiliar situations. Prey characters can be smart or dim, but universally believe that others have worth, and are usually humble about their own abilities. Herbivore animals are usually nomadic, following seasonal feeding patterns and dietary changes, but a few are territorial and may behave like vegetarian Broccen.'
        ) ,
        array(
            'Type' => 'Hippopotamus',
            'Description' => 'Hippopotamus characters are known for their emotional turmoil and aggressive nature. Hippos are liminal, amphibious beings and this gives them a dual nature. They are strong and authoritative, intuitive and deep, focused and reserved, but they are also stubborn and judgemental beings, that can become reckless and impulsive as well as aggressive, Hippos are emotionally turbulent, usually dealing with complex inner conflicts that they do not wish public.'
        ) ,
        array(
            'Type' => 'Hominid',
            'Description' => 'Hominid characters are rare amongst the Bulmäs, only a very few souls will claim descent from the man-like apes, most would rather claim Ape descent when possible. Hominid characters are seen as sly, duplicitous, cunning and terrifying, they are actually curious and usually peaceful beings, but their knowledge, intelligence and creative reasoning often grants them technologies that grant them an edge over all other predators and prey. Among the Hominid souls, for example, there are those who favour controlling and manipulating their environment, which can seem dark and dangerous to other Bulmäs, especially when these technologies are magical in nature.'
        ) ,
        array(
            'Type' => 'Horse',
            'Description' => 'Horse characters are patient and strong, noble and often beautiful to look upon. Whether an actual horse, or just a horse-like companion matters little. The horse character, however, can be flighty, easily distracted, and may even be a coward, despite their strengths.'
        ) , //21
        array(
            'Type' => 'Hyena',
            'Description' => 'Hyena characters are known for their trickster ways, coarse dark humoured giggling, gender ambiguity, and brutality. Hyenas are scavengers first, and as such closely associate with vultures and Vermis, although they never were folded into Vermis in the same way as some other souls, hyenas were always too tricksy to be caught that way. Hyena characters are strong strategists and tactical thinkers, with excellent communication and survival skills.'
        ) ,
        array(
            'Type' => 'Insect',
            'Description' => 'Insect characters are the most common of all the Bulmäs, although huge numbers of their souls became trapped as aspects of Lord Vermis until Teucoi completed the all-path. Insect characters are usually fairly social (some especially so), with very varied temperaments ranging from timid to bold, some are stealthy assassins, others exuberant, iridescent dandies and completely silent to deafeningly chatty. The only thing that unites all insects is that they are never very intelligent.'
        ) ,
        array(
            'Type' => 'Lemur',
            'Description' => 'Lemur characters are known for their sense of humour and generally good-tempered nature, they often want to be the best they can be at things, having a competitive and driven personality, but can have unrealistic expectations based on over-confidence and lack of understanding. Lemur characters have a natural dexterity and coordination and they can seem very like squirrel characters, but Lemurs are more attuned to night life than squirrels and are less industrious or well prepared. Where the squirrel will work hard to make time to play hard, the lemur will play hard first, and then muddle through in the end.'
        ) ,
        array(
            'Type' => 'Lion',
            'Description' => 'Lions characters are similar to other cats, having similar carnivorous tendencies, but lions are different in one major regard, to all the other cat types. Lions are incredibly, and deeply social, they do not share most cats solitary and distant nature. Instead, the lion radiates majesty, charisma and cooperation, because of this social nature and physical prowess the Lion is almost free of fear, only fearing the largest packs, and animals.'
        ) ,
        array(
            'Type' => 'Lizard',
            'Description' => 'Lizard characters are cool and alert, unblinkingly aware of what is around them, and quick to move on if things are not going their way. Lizards are believed to be wise and knowledgeable, and some are, some have knowledge of medicine and poisons, but others are gifted with knowledge of secret ways, or very ancient survival knowledge. Lizard characters are often shown to have incredible powers of regeneration, some are able to even shed their body-parts to leave behind for predators to attack, while the lizard escapes and regrows their tail.'
        ) ,
        array(
            'Type' => 'Louse',
            'Description' => 'Louse characters are thought to be similar to fleas, although in fact this is not strictly true, as the louse is less cowardly than the flea, but generally prefers to keep a lower profile and not draw attention to themselves. Lice characters simply take from others, ideally without being sensed or noticed, they do not understand that others are offended or upset by this behaviour as the louse is usually a solitary and anti-social being. Louse characters are unlikely to develop the ability to learn from blood drinking, as they are simply too self-absorbed to care about their food, beyond it keeping them alive.'
        ) ,
        array(
            'Type' => 'Minotaur',
            'Description' => 'Minotaur characters (such as Asterion) are known for their stamina, imperviousness and near immortality, which they were originally given as part of their role as the Guardians of the Labyrinth and the Bodyguards of the Goddess. It is said that their blood will not spill, and that even if their body is killed and destroyed they will reform around their soul by the next dawn, and this is certainly true of Labyrinthine Bulmäs. Minotaur characters are taciturn and stoic to the point of asocial silence, although some are very good listeners, and communicate well with body language, few have ever heard a Minotaur speak. Minotaur souls are often confused with Bull souls with whom they of course share many traits.'
        ) ,
        array(
            'Type' => 'Mole',
            'Description' => 'Mole characters are sensitive, tactile people, keen listeners and obsessed with touching, smelling and tasting things, especially rich or fine things, but this is more their sensual nature rather than some pride or love of the finer things in life. Mole characters are known for their strong sense of self, and strong faith (usually in others, or religious in nature), and they are also known for their knowledge of roots and tunnels. Mole characters have an understanding of the deep lea that surpasses even Labyrinthine Bulmäs, as no Mole soul has ever got lost into the labyrinth, and they are believed to have uncanny ways of sensing and avoiding the Increated in the deep Lea, although they cannot fight them.'
        ) ,
        array(
            'Type' => 'Monkey',
            'Description' => 'Monkey characters are seen as playful, fun-loving, often trickster creatures, that are intelligent and resourceful, associated with art, balance and harmony. Monkeys can be faithful and penitent, or lust-filled and debauched, and anything in between.'
        ) ,
        array(
            'Type' => 'Moose',
            'Description' => 'Moose (or Elk) Characters are known for their strength and majesty, although they can be graceful or clumsy in almost equal measure. Moose are usually very grounded personalities, down to earth and not prone to flights of fancy, or even excessive speculation, but they always seem to know the right thing to say to make another laugh or smile. Moose characters are strong and resilient, but have a soft side and a kind-heart that they must keep protected and secret, or it will be easily exploited by others.'
        ) ,
        array(
			   'Type' => 'Moth',
			   'Description' => 'A Moth character is graceful and beautiful, but are always somehow distant or strange. They are usually asocial, and are great navigators, having some of the longest lea paths, that sweep down through the Labyrinth. They have a reputation for both silence and illusions, although in most cases these are exaggerations.'
		  ) ,
        array(
            'Type' => 'Mouse',
            'Description' => 'A Mouse character is timid, but sneaky. They are quick to flee conflict of any sort, but what they cannot take by force they know they can take by theft. Unlike Rats, mice are not as social, they are too timid to form large groups. Mice are not smarter than Rats, but they are better thieves, more attuned to small details and more perceptive than their ratty brethren, mice are naturally dismissed and overlooked by all but a few specialised predators. '
        ) ,
        array(
            'Type' => 'Otter',
            'Description' => 'Otter characters are curious and playful, to the point that they can seem entirely child-like with their love of play. That is until the game becomes rougher, with otters it is all fun and games until someone loses a finger, or a life. Otters play hard, work hard and fight hard, and do all three with the same exuberance and sense of fun, throwing themselves completely into whatever they are currently doing one hundred percent. Otters find it harder to plan ahead or dwell on the past than other souls, in fact many otters have a hard time walking their own soul-paths back, they would rather revel in the immediacy of now rather than think about their own history or past lives.'
        ) ,
        array(
            'Type' => 'Owl',
            'Description' => 'Owl characters are considered very intelligent and intellectual by others, they are often philosophical thinkers, and usually have knowledge of occult and fringe topics. Owls have a reputation for laziness, but this is due to their nocturnal nature, they work hardest when no one is watching. Owl characters are known as deadly hunters, but they are careful, never placing themselves in unnecessary danger, and always scouting around a target before they attack. An owl would rather leave prey to escape than risk a trap.'
        ) ,
        array(
            'Type' => 'Parrot',
            'Description' => 'Parrot characters are gregarious, charming and quirky characters that have a deep confidence and intelligence. Parrot characters are natural risk-takers, jumping in, or speaking up before they have thought if it is appropriate.'
        ) ,
        array(
            'Type' => 'Phoenix',
            'Description' => 'Phoenix characters are noted for their self-sacrificing and noble natures. Phoenix characters upon gaining their travelling soul will also experience an intense fever, but those who survive are always reborn. They will gain access to Bulmäs Phoenix flame magic, which can both burn and heal as the phoenix wishes, allowing a phoenix to cloak themselves in a protective, healing flame, that will burn their enemies.'
        ) ,
        array(
            'Type' => 'Pig',
            'Description' => 'Pigs are often thought of as a simple character, boorish, violent, and greedy. However, while it is true that a pig character is hedonistic and does love their food and drink, and they are quick to anger, and when angered are merciless and capable of anything, they are also loyal and brave, and usually quite cheerful sorts. While not generally considered smart, they have an instinct for sniffing out secrets, and can often spot and realise things that "smarter" people miss. Of course, some pigs use their gifts to persuade and manipulate the gullible and naive into positions the pig can take advantage of too.'
        ) ,
        array(
            'Type' => 'Porcupine',
            'Description' => 'Porcupine characters are kind, humble, independent, determined and very grounded, but Porcupine characters are often overly sensitive, critical of others, give off a sense of being unapproachable, or even hostile. They are accused of being angry quite often, and this is not always true, but Porcupines who do lose their temper lose it completely.'
        ) ,
        array(
            'Type' => 'Pterippi',
            'Description' => 'Pterippi characters (also known as winged horses, or Pegasi after Pegasus) are exceptionally rare souls, who were tasked as messengers of the goddess. Pterippi are known for their grace, speed and beauty, similar to horses, for whom they are often mistaken, are also known for their imaginations, and ecstatic visions, which often contain traces of prophesy and spiritual and divine magics. Pterippi are able to move through the lea up to a hundred times faster than other Bulmäs, but whenever they do so, regardless of the path they take they will arrive in their soul-form.'
        ) ,
        array(
            'Type' => 'Pterosaur',
            'Description' => 'Pterosaur characters are known for their huge wings and often having a large brightly coloured crest on their head. Pterosaur characters are excitable types, fairly social, with strong senses and a wide variety of diets, they are easily confused with birds and bats, but are distinct and pre-date both by a long time. In fact, both birds and bats were probably created by walking mammals and theropods along Pterosaur paths. Pterosaur characters are often considered the most versatile fliers, even more so than bird types as they have millions of years more practice.'
        ) ,
        array(
            'Type' => 'Rabbit',
            'Description' => 'A Rabbit (or Hare) character is noted by their love of comfort, security, and family. Whether the actual animal or a human who is rabbit-like they are also timid, quiet, shy beings, but are noted for their speed and their ability to burrow deeper for additional security. Rabbit characters are generally pleasant and charming, but turn vicious when cornered, and reveal hidden strengths and weapons.'
        ) ,
        array(
            'Type' => 'Rat',
            'Description' => 'Rat characters are resourceful, clever and sneaky. It applies to both the animal and humans who are rat-like that they are social, fast and nimble, able to get themselves into, and out of, situations that others would not contemplate. Rats can be successful, and generous, sharing their abundances with everyone, just don’t ask too deeply about how the rat came to have such an abundance, rats think its yours if you take it. Rats have a reputation for duplicity, this stems from their misunderstood nature, a rat doesn’t hold steadfast beliefs, they are not dogmatic or loyal, but independent thinkers who agree with whoever is currently making the best case, and will turn on anyone that threatens them.'
        ) ,
        array(
            'Type' => 'Raven',
            'Description' => 'Raven characters are mysterious, mindful and mischievous, although occasionally melancholy and macabre. Whether a bird or a dark cloaked person, the Raven has an almost bi-polar personality, they can be a laughing trickster one minute, before lapsing into despair, or dwell on deep matters for days, before taking a break to prank another, the only steadiness of their personality is their quick, mercurial, creative, intelligence. Ravens often fill the role of messengers, whether delivering gossip, or as a harbinger of sorrows. They are also known as battle-birds, as they gather over battlefields, but while they’re not overly aggressive they are highly territorial and opportunistic.'
        ) ,
        array(
            'Type' => 'Rhinoceros',
            'Description' => 'Rhinoceros characters are seen as sturdy, strong, and resilient, they are known for their amazing stamina, and short-sightedness (which is as much mental as a vision problem). Rhinos are generally peaceful characters, but they are quick to anger, preferring to charge an enemy at least once before leaving, just so they know the rhinoceros is serious.'
        ) ,
        array(
            'Type' => 'Sauropod',
            'Description' => 'Sauropod characters are based on those huge long-necked and long-tailed dinosaurs, they are also known as Thunder-lizards by the Bulmäs. Sauropod characters are known for their strength, perpetual hunger and their slowness, they think and move slowly just because of their enormous size, the only parts of their body that moves with any sort of speed are their neck, moving their head to new vegetation, and tail which moves constantly to counter-balance the head and body when walking, and can also be used as an enormous bull-whip, accelerating the tip beyond the speed of sound, lacerating enemies and creating a incredibly loud crack that can stun predators and act as a warning to others in the herd.'
        ) ,
        array(
            'Type' => 'Scorpion',
            'Description' => 'Scorpion characters are known for their secretive, perceptive nature, they can have an assertive and charismatic personality, that draws people in, before the scorpion ambushes them. Scorpion characters have a gift for poison and medicine, and has a strong association with death, with many believing Scorpions are a form of Vermis. This is because scorpions, unlike most predators, favour eating other predators, with some hunting other scorpions, spiders, or centipedes as their preferred prey, they hunt by tracking scent trails across the ground and detecting vibrations in the air, generally launching a sudden ambush upon their target after hiding themselves somehow.'
        ) ,
        array(
            'Type' => 'Seal',
            'Description' => 'Seal characters are known for their imaginations and creativity, they love learning new tricks and skills, this can be mistaken for a playful, or flippant personality, but the truth is seals are joyful, happy beings, but they are just as happy killing, smashing, and destroying as they are doing anything. Seals enjoy life and get a kick out of evading another predator with a cool trick, especially if it means they get a kill of their own.'
        ) ,
        array(
            'Type' => 'Shark',
            'Description' => 'Shark characters are known for their strength, power and authority. Shark characters are instinctual hunters, ruthless and furious, but they are careful too, never risking injury for a meal. Sharks are curious beings, but mainly wonder what something will taste like. Sharks are always on the move, tirelessly swimming, and this means they can find it impossible to settle in a territory, even as a Broccen.'
        ) ,
        array(
            'Type' => 'Skunk',
            'Description' => 'Skunk characters are seen as offensive, foul and obscene, but they are also usually non-violent and self-protecting beings. Skunk characters are considered brave, but it is simply that their fear response is hard-coded as fight then flight, where fight ideally involves spraying foul-smelling  musk at the enemy as an attack.'
        ) ,
        array(
            'Type' => 'Snake',
            'Description' => 'Snake characters are cool, patient and manipulative, they like to get their own way and always have their own goals, but snakes are slow to anger, preferring to bide their time and wait for a chance to strike back later, although once a snake loses their cool they will become deadly and violent, not caring who they hurt to get what they want.'
        ) ,
        array(
            'Type' => 'Songbird',
            'Description' => 'Songbird characters are easy to understand as they are always singing, and their songs will reflect their mood. Songbirds wear their heart on their sleeve and they are always musical, but they range from cheerful three-note whistlers, to brooding poet types, with complex melodic, lyrical and harmonic patterns to their songs.'
        ) ,
        array(
            'Type' => 'Spider',
            'Description' => 'Spider characters are seen as quiet, wise types, creative and gifted in knowledge especially esoterica that includes poison and magic. Spider characters can learn to manipulate the lea as a web, allowing them to claim territory and even in some cases doom-bend.'
        ) ,
        array(
            'Type' => 'Squirrel',
            'Description' => 'Squirrel characters are known for their preparedness, hoarding, balance and agility. Whether an actual squirrel or somebody who seems squirrel-like, they are industrious, but also playful, putting equal energy into fun and work is the squirrel way, but no matter how well-prepared a squirrel may be, don’t expect them to help out much in a conflict. The squirrel is more likely to avoid and placate than confront.'
        ) ,
        array(
            'Type' => 'Theropod',
            'Description' => 'Theropod characters (which are the three-toed, two-legged, long-tailed proto-birds of the dinosaurs) are seen as aggressive brutes by some, but they are quite social, adaptable and intelligent hunters. They are very perceptive, but often impatient and hungry, and this can lead them into trouble, as they are drawn so strongly to the scents of blood and carrion, and by the sounds of struggle and pain, that they can blunder into traps such as pits very easily. Theropod characters always have a number of deadly weapons at their disposal, and strong tactical knowledge, but they favour flanking assaults and surprise charges.'
        ) ,
        array(
            'Type' => 'Toad',
            'Description' => 'Toad characters are considered disgusting by many, often seen as dirty, fawning, slimy, sleazy, compliant, gluttonous, cowardly and impure. This is often true more of human toads, than the actual animal. However, the Toad has redeeming qualities, a certain wisdom, as they always know their own mind, foibles and weaknesses, they are never delusional about themselves, their position, or how others view them. They also know how to hide and submerge themselves in their environment, as well as how to flatter and insult others, and these manipulations can grant them power of those who think them subservient.'
        ) ,
        array(
            'Type' => 'Tortoise',
            'Description' => 'Tortoises, or their semi or fully aquatic cousins, terrapins or turtles are known for their slowness of action and generally peaceful nature. Because they are physically slow, the tortoise is usually a wise tactician and planner, thinking ahead will save them unnecessary trips, and while generally placid, a tortoise will bite if left with no other recourse. Tortoises are known for their defences, and no tortoise will ever be found without at least one backup plan.'
        ) ,
        array(
            'Type' => 'Unicorn',
            'Description' => 'Unicorn characters are very rare, they were never common, being the bridge between the F&aelig; and the Bulmäs. It is said that Unicorn souls can manipulate the Lea with their horns like the F&aelig;ries manipulate the threads of the Tapestry. Unicorns are often arrogant, self-possessed beings, they believe in their own superiority in a way some would find alarming. Unicorns are famously wild and ferocious, although this aggression is overstated in some cases, they are a prey animal with a carnivore’s predilection for attack.'
        ) ,
        array(
            'Type' => 'Vermis',
            'Description' => 'Vermis is bound by a great duty and overall sense of weariness, that only seems to lift when they travel to a new world. Vermis characters are all technically a singular character, Lord Vermis, who is tasked to collect the souls of the Bulmäs who die, and shepherd those souls to new worlds where they can be reincarnated once again. Vermis has an over-riding sense of duty, the blended instincts of worms, maggots, flies and dragons, a hive-mind / gestalt / swarm experience that believes itself devoid of any individuality, a desire to be solemn and careful with the souls harboured, burning hunger for Bulmäs souls (especially those that have "Dead" or "Dying" Hitches of any type), and a considerable amount of frustration and anger at their lot. Each Vermis character will display a slightly different amount of each of these traits, based on which parts their original personality most resembled, and since the All-Walkers this effect has increased with individual Vermis varying more.'
        ) ,
        array(
            'Type' => 'Vulture',
            'Description' => 'Vulture characters are known for their patience and incredibly keen senses. Vulture characters are known as death birds and have no fear of Vermis, who owned their form for quite a while until Teucoi of the All-path released several Vulture souls. Vulture characters are seen as serious, perceptive, and trustworthy, but are also feared for their links with death, and are seen as aggressive, unclean and disease-ridden, although this last is rarely true as vultures are virtually immune to all bacteria and most viruses.'
        ) ,
        array(
            'Type' => 'Warthog',
            'Description' => 'Warthog characters are seen as courageous, fierce and vigilant, they are always on the look out for trouble, and when they see it, they will charge it down and bite it. In fact, the warthog has a reputation for biting off way more than anyone thinks it can chew, facing down and even killing animals much larger, and allegedly more aggressive than itself when threatened. Warthogs are generally considered a great friend and a fierce enemy, who has no idea of their own ability, but are full of confidence, the sort of person who will agree to a project goal without thinking if it is possible, but who will then throw everything they have at trying to achieve it, no matter what.'
        ) ,
        array(
            'Type' => 'Weasel',
            'Description' => 'Weasel characters are proper characters, always with a uniquely quirky personality, that are known for their playful nature, courage and quick wits. Weasels can also be known for their aggression, cunning and for playing innocent when they are anything but. Weasels are specialised hunters, that favour carnivorous snakes as their own pray, especially in the case of the Mongoose (which is really just a weasel cousin).'
        ) ,
        array(
            'Type' => 'Whale',
            'Description' => 'Whale characters are seen as peaceful and compassionate beings, although many are aggressive hunters, they are quite social creatures, although they have a reputation for solitude, they do communicate over vast distances of the oceans with their incredible songs. Whale characters are seen as intelligent, inventive, powerful and graceful, as well as enduring, but this majestic combination can lead to them seeming vain, proud or arrogant depending on their levels of charisma. The greatest strength the whales possess in their own opinion is their ability to navigate the lea, although they are not quite as gifted in that regard as Moles they are a close second.'
        ) ,
        array(
            'Type' => 'Wolf',
            'Description' => 'Wolf characters are known as predators and deceivers, they may be charming and beautiful to look at, and display some characteristics of Dogs, being brave, and smart, even loyal for a time, if well "fed", but the Wolf has strong hungers, that are often dark and strange, and that almost always involve preying on others in some form or another. This hunger will drive the wolf to kill, in order to sate whatever need they feel.'
        ) ,
    );
    public static $combatRoles = array( //array('Type'=>'', 'Description'=>'', 'Rules'=>''),
        array(
            'Type' => 'All-rounder',
            'Description' => 'The All-rounder is a jack-of-all-trades, able to strike, buff, debuff, heal, lead, soak and move, to some degree. They are often exceptional individuals and no side should have more than one.',
            'Rules' => 'All-rounders usually require combat annexes, weapons, armour descendants and generic magic annexes too, they are usually limited compared to any specialist in what they can achieve, very few All-rounders are also samaurai-neuro-surgeons.'
        ) ,
        array(
            'Type' => 'Brick',
            'Description' => 'The Brick is like a Tank or Heavy, if they just stood and took the damage. Bricks are usually large, tough-guys, but they never really fight back. They are a big target that draws and soaks hits.',
            'Rules' => 'Bricks must be able to soak, ignore or heal damage rapidly, but they are usually very limited in their ability to hit back, although they can often create Obstacles for the enemy some how, and are often much more mobile than a Heavy or a Tank.'
        ) ,
        array(
            'Type' => 'Buffer',
            'Description' => 'The Buffer is a generic support Character, who supports all other roles by "buffing" them, usually via magic or equipment upgrades.',
            'Rules' => 'Buffers require an ability to buff, this may be an Annex that lets them improve another, or allows them to prepare cards upon allies at a distance, increase the Ally’s ability to hit, do damage, etc. Buffers usually have limited abilities to de-buff the enemy, and limited healing or attack abilities.'
        ) ,
        array(
            'Type' => 'Debuffer',
            'Description' => 'The Debuffer is a highly specialised roles who supports their allies by "de-buffing" the enemy forces, usually by magic or equipment interference.',
            'Rules' => 'Debuffers must have an Annex with an ability to interfere with the enemy, usually in the form of affecting them with Umbrals, Tangles, or even Hitches. Debuffers rarely have the ability to directly attack an enemy, although many can also perform limited buffs or healing on allies.'
        ) ,
        array(
            'Type' => 'Dragon',
            'Description' => 'The Dragon is an ultimate warrior, usually heavily armoured, capable of engaging multiple targets simultaneously whether through Size, speed or tactical brilliance. The Dragon is similar to a Tank although usually more mobile.',
            'Rules' => 'Dragons are fairly mobile (at least in the air), armoured (at least as well as soldier or knight) and often have an area-denial attack or at least Splash damage comparable to Glass Cannons. Dragons are not great at stealth and favour charges, drive-bys and fly-overs as well as ranged attacks, rather than melee, especially against large groups.'
        ) ,
        array(
            'Type' => 'Engineer',
            'Description' => 'The Engineer (also called the Sapper or Demolitions) is a combat engineer who specialises in fixing, building, digging, and blowing things up, down or in. Engineers build castle walls, and they undermine them. Depending upon the technology available to the engineer they may take months to build a defensive wall, or to sap a similar wall, or the same result may be achieved with a single explosive charge.',
            'Rules' => 'Engineers have Annexes in building, fixing, crafting weapons and traps (obstacles), digging or sapping, and usually explosives, sometimes they also have a combat Annex.'
        ) ,
        array(
            'Type' => 'Flanker',
            'Description' => 'The Flanker is built for sneak attacks and ambushes, they are excellent at hiding, stealth, and often deploy force multiplication tactics such as superior tech, fearsome reputations, poison, force concentration and so on. Flankers include wily rogues, some rangers, movie ninjas, and most commandos.',
            'Rules' => 'Flankers should have Annexes in hiding, stealth, movement, and attack. They especially like setting snares, traps, and ranged ambushes.'
        ) ,
        array(
            'Type' => 'Glass Cannon',
            'Description' => 'The Glass Cannon is the character who is often found wearing robes (or Gillie suits) instead of armour, who thinks a stick with a knob on the end beats war mace, or that one big missile from far away is better than a load of smaller ones close up. The Glass Cannon is designed to dish out damage, but don’t expect them to take any hits at all, or to be running all over the battlefield. Field Spotters and Wizards are examples of Glass Cannons',
            'Rules' => 'Glass Cannons have to have some way of doing a lot of damage with their Annexes to a wide area. Their Annexes usually have an area effect to increase the number of potential targets.'
        ) ,
        array(
            'Type' => 'Grenadier',
            'Description' => 'Considered by some to be a type of Heavy or Shocker. The Grenadier is known for their use of explosives, typically hand grenades or RPGs, and for leading assaults.',
            'Rules' => 'Grenadiers are usually large and powerful fighters, that have good mobility, and explosive weaponry. They rarely favour armour, preferring mobility and assault capabilities.'
        ) ,
        array(
            'Type' => 'Healer',
            'Description' => 'The Healer is a medical or clerical character who focuses on healing injuries, easing pain, neutralising toxins, and other forms of combat medicine. Depending upon the genre and setting the Healer will either just be triaging and stabilising wounds with First Aid, or using Healing magic, Nanotech, or praying for miracles to close wounds and remove scars.',
            'Rules' => 'Healers will have suitable Annexes to provide First Aid, Paramedicine, Medicine, Surgery, or Healing abilities. Healers will often also have Annexes that grant them additional support buffs such as increasing another character’s chance to hit, damage or defend.'
        ) ,
        array(
            'Type' => 'Heavy',
            'Description' => 'The Heavy can dish out damage and take it. They are tough, powerful foes, but not usually particularly agile. The Heavy is usually armed with special training, tactics, armour and weapons that increase their ability to do damage to the enemy and minimise the damage they take.',
            'Rules' => 'Heavies have annexes in defences and attack, but never in anything like agility, stealth or hiding. They often carry special heavy weapons.'
        ) ,
        array(
            'Type' => 'Knight',
            'Description' => 'Knights are known for their armour and mobility (usually on horse-back or via vehicles), they also hit pretty hard, but not as hard as a striker.',
            'Rules' => 'Knights rely on armour, mobility and attack, but should focus on armour and mobility. Knights usually rely on specialised weapons and tactics for defeating particular types of targets and should repeatedly engage and disengage enemies (they often have abilities that increase their ability to disengage rapidly and safely).'
        ) ,
        array(
            'Type' => 'Officer',
            'Description' => 'The Officer is a leadership role that uses superior tactics, strategy and logistics, to assist and direct their allies for mutual protection and combined attacks.',
            'Rules' => 'Officers usually use orders, given via voice, communications or sign language to their allies, to add their cards to their allies. Officers are usually built similarly to the troops they lead, although they are often given heavier armour and lighter weapons.'
        ) ,
        array(
            'Type' => 'Rifleman / Missile Infantry',
            'Description' => 'Rifleman are infantry missile troops, and crossbowmen, musketeers, and archers also fit this mould, although with shorter ranged weapons. Missile Infantry are usually not very mobile, and may dig in, place large shields or set up behind cover, to limit the ability of the enemy to engage them back.',
            'Rules' => 'Missile Infantry favour range, and damage, then self-defence. Mobility is a lesser concern for these fighters, who will dig in, and deny an enemy access to an area, with their long range and concentrated fire-power.'
        ) ,
        array(
            'Type' => 'Scout',
            'Description' => 'The Scout is built for stealth, mobility and observation skills, they are intended to be intelligence gathering, spotting enemy ambushes ahead of time, and reporting back. Scouts are usually lightly armed and armoured.',
            'Rules' => 'Scouts should have Annexes in Stealthy movement, Observation / Perception / Senses, Fast movement (possibly) and an Attack (maybe).'
        ) ,
        array(
            'Type' => 'Shield',
            'Description' => 'The Shield is a character who is very like a Brick. However, the Shield is often built to protect others as well as themselves. Shields do not generally have an attack Annex, but they may carry a weapon.',
            'Rules' => 'The Shield uses all their Annexes to augment their defences, technically all their Annexes should be defence orientated, although at least one should also provide mobility or range, to let the shield get or place defences or obstacles between the attacker and any threatened allies.'
        ) ,
        array(
            'Type' => 'Shockers',
            'Description' => 'Shockers (or Shock Cavalry, Shock Troopers, Assault Troops, etc) are similar to Strikers, and Knights, but Shockers seek to overwhelm, destroy, capture or rout enemies rather than disengaging after an attack like a Knight or Striker. Shockers have a strong reliance of scare tactics, and reputation, which can limit their usefulness.',
            'Rules' => 'Shockers have a heavy reliance on speed, mobility, stealth and defence, but will reduce these factors for a good scare tactic or psychological advantage. Shockers attempt to induce Stress and Shock in their opponents allowing them to be overrun, to this end Shockers will often use more intimidating customized arms and armour.'
        ) ,
        array(
            'Type' => 'Sniper',
            'Description' => 'Snipers are built for stealth and doing a lot of damage to a single distant target, everything else is usually irrelevant to their tactics. Snipers will lie in wait, creating ambushes that can kill with their first well-prepared shot, and then often slip away unseen to another spot for a second kill.',
            'Rules' => 'Snipers require great skill or talent in stealth and excellent ranged combat prowess, they should ideally have at least one power that can attack at a range, as well as a powerful weapon. Snipers usually begin Ordeals with Preparation Actions, hiding themselves, then aiming, before taking that deadly shot.'
        ) ,
        array(
            'Type' => 'Soldier',
            'Description' => 'The Soldier is a good mix of speed, strength, armour and fire-power. Professional soldiers are well-trained, well-equipped and battle-hardened.',
            'Rules' => 'The soldier is optimised for Combat Ordeals, usually with Annexes and Descendants for attack, defence, soak, mobility and tactics. Soldiers often have good psych defences, as part of their rigorous discipline and duty Hitches.'
        ) ,
        array(
            'Type' => 'Striker',
            'Description' => 'The Striker is built for hit and run tactics, favouring a rapid charge or better yet ambush, lots of damage and then controlled disengagement, fall back and regroup. This is the typical pattern of cavalry, some rangers and barbarians.',
            'Rules' => 'Strikers need mobility and the ability to do damage, they often have no special defences beyond light armour or shields. Strikers may have some special ability to rapidly disengage, usually by outpacing their enemies.'
        ) ,
        array(
            'Type' => 'Support',
            'Description' => 'Support roles boost the abilities or capabilities of other roles. They may act as a spotter for a sniper, as communications for an Officer, as a squire to a knight, etc. Support are usually well equipped and often carry spare ammo for other Characters.',
            'Rules' => 'Support Characters are usually similar to the role they are intended to support, with at least one Annex replaced with a Support Annex that will assist or buff the specific role they assist in a number of ways. For example giving an Officer the ability to spread their orders (and Cards) to multiple Targets, or making a Squire able to Prepare Cards into their Knight’s Style Reserve.'
        ) ,
        array(
            'Type' => 'Tank',
            'Description' => 'The Tank is a Heavy who wears more armour, and can both soak and deal out damage. Tanks usually having at least one ridiculously oversized weapon to hit the enemy with. Tanks are often surprisingly mobile as well.',
            'Rules' => 'The Tank must have Annexes that can soak, avoid, or ignore Wounds, such as Tough. Tanks usually have at least one Annex devoted to attack as well. Unlike Heavies, Tanks can be fast.'
        ) ,
    );
    public static $narrativeArchetypes = array( //consider splitting into archetypes by side or similar. This is very basic and non-comprehensive atm.
        array(
            'Type' => 'Ally',
            'Description' => 'An Ally is a Character who will act alongside a character, often the Protagonist (although other characters may have their own allies). Allies might be family members, friends, loyal employees, hired mercenaries, enemies of an enemy, or just those currently politically aligned, depending upon the situation. They are usually at least Cast Extras.'
        ) , //0
        array(
            'Type' => 'Antagonist',
            'Description' => 'The Character opposed to the Protagonist, usually the Embodiment of the Dominant side of the Conflict. The Antagonist is your villain and may only appear in one Story. Sometimes to mix things up in a series/campaign the normal Protagonist may become an Antagonist, Ally, Foil or even Love Interest for a Story.'
        ) , //1
        array(
            'Type' => 'Comic Relief',
            'Description' => 'Comic Relief Characters are usually Chorus Extras (although one or two may rise to Cast or higher), that are Allies of the Protagonist. Surprisingly often the Comic Relief may be associated with the Dominant Facet, when they are normally low-level Mooks.'
        ) , //6
        array(
            'Type' => 'Confidante',
            'Description' => 'A variant Ally who is often the closest friend of the Protagonist and is therefore the person that they tell everything to. The confidante can often be combined with other Characters, such as the Innocent, Mentor, Herald, Foil, or often a Love Interest, or Pet.'
        ) , //7
        array(
            'Type' => 'Critic',
            'Description' => 'Critics are characters who criticise the actions and plans of the Protagonist or Antagonist. The Critic can only find fault in others, and rarely improve a situation, only point out how it is going wrong, they specialise in complaint rather than constructive criticism. Critics may act to deflect, hinder, or confuse the Protagonist or Antagonist, often while claiming alliance with one side, but actually being neither.'
        ) , //9
        array(
            'Type' => 'Cynic',
            'Description' => 'Cynics are characters who do not support anyone, they will generally oppose everyone and everything, and will rarely be persuaded away from this position. Cynics will not believe in a cause, they will not join up, instead they will avoid and disbelieve.'
        ) , //10
        array(
            'Type' => 'Dynamic',
            'Description' => 'Any Character that changes from being an Antagonist to Protagonist, or vice-versa is a Dynamic Character. Depending on the plot, they may change what Facets they embody, or simply remain the same as the Plot revolves the status-quo around them.'
        ) , //13
        array(
            'Type' => 'Ensemble',
            'Description' => 'Ensemble characters are usually Chorus or Cast Extras, who have names, and even some defined character traits, that elevate them above the Stock, but they are still very minor characters. Often associated together as a group (hence the name), they may actually be a Pact Descendant that include Allies, Love Interests, Mentors, etc (such as Robin Hood’s Merry-men, or that Magical Headmaster’s Army of Students). The ensemble might be allies, mooks, or outsiders depending upon the situation.'
        ) , //14
        array(
            'Type' => 'Everyone',
            'Description' => 'The Everyone (inclusive of the every-woman and every-man) character is a mundane individual (as such often a working-class or lower-middle class person, usually neither child nor elderly, nor exceptional in ability or looks). Everyone Protagonists are surprisingly common throughout fiction, often though they will develop unusual skills and abilities later in their Arc. Everyone characters can often serve as an audience surrogate, asking for exposition for any part of the setting that is unusual, or little known. This is especially true of things impossible in the real world, but part of the setting, an Everyone character can keep asking "what was that?" and the audience will appreciate any answers they get.'
        ) , //15
        array(
            'Type' => 'Fall-guy',
            'Description' => 'A Fall-guy is a character who is set up as a scapegoat for the Antagonist, they are usually assumed to be the antagonist by the protagonist, until the deception is revealed.'
        ) , //16
        array(
            'Type' => 'Fatale',
            'Description' => 'A Fatale (or Vamp / Vampire / Temptation) character is a dangerous, seductive foe, they are usually driven by personal ambitions, and are blessed with intelligence, good-looks, and charm, but are cunning, ruthless, and treacherous, manipulating their lovers, and others, with a hypnotic sexual allure that traps and endangers. Fatale characters may be armed with subduing weapons, such as knock-out drops, sleeping gas, or narcotic lipstick, although this is not necessary as these characters play at Soul-Stakes most of the time, with their treachery pitched to break hearts and scar souls. Often Fatales will ally themselves with the Protagonist, only to turn on them later, revealing they are the lover of a Rival or the Antagonist.'
        ) ,
        array(
            'Type' => 'Foil',
            'Description' => 'A Foil is a contrasting Character, perhaps quick to another’s slow, or perhaps cowardly to another’s bravery. Foils are often recurring Characters and they are usually a Mirror Rival (but don’t have to be), in fact, the best Foils are often crafted specifically for that role. Foil Characters usually compare a Facet to its Anti-Facet, but they can explore other Conflicts.'
        ) , //17
        array(
            'Type' => 'Fool',
            'Description' => 'A Fool is a character who is a comic-relief character, but to whom some wisdom is given. The old saying is many a true word spoken in jest and the Fool exemplifies this, telling jokes at others expense always involves a sprinkle of truth. Fool’s can often have a Cassandra effect, where they state exactly what is going on, everyone laughs thinking it is a joke, and then ignores any advice the Fool gives them.'
        ) ,
        array(
            'Type' => 'Henchman',
            'Description' => 'Henchman are side-kicks to Antagonists. They often are Foil or Rival characters to the Protagonist. Henchman are sometimes a Foil contrast to the Antagonist, and can be both at once.'
        ) , //18
        array(
            'Type' => 'Herald',
            'Description' => 'In T13 a Herald is a Character that exposes some aspect of the plot, Conflict, Embodiments, setting or background through a Revelation Scene. Usually Heralds are Chorus Extras, but one may rise to Cast (and Ally) if they recur often enough.'
        ) , //20
        array(
            'Type' => 'Imposter',
            'Description' => 'Imposters are characters who pretend to be something they are not. Imposters come in two main types, accidental and malicious, accidental imposters are mistaken for someone or something they are not, but circumstances make it difficult for them to admit they are not who everyone thinks they are; malicious imposters do it deliberately (for all sorts of reasons, from being a doppelganger replacement for the original, to a desire for power) and will often kill to protect their secret.'
        ) , //22
        array(
            'Type' => 'Innocent',
            'Description' => 'Innocents are often children, but don’t have to be. They are sympathetic Characters that the Protagonist is meant to try and protect. Innocents are usually Vexes or Chorus Extras, although at least one usually rises to Cast Extra (or better). Innocents that lose their innocence somehow during a narrative may become another archetype, often a Tragic.'
        ) , //23
        array(
            'Type' => 'Janus',
            'Description' => 'The Janus is the two-faced friend, they appear as an Ally, or a Mook, but they are not. While they don’t generally act against their friends directly, they do speak badly of them behind their back. This can sour relationships and create situations where information leaks, via gossip channels, to the enemy.'
        ) , //24
        array(
            'Type' => 'Looker',
            'Description' => 'The Looker is a beautiful person, a stunner. They may be of either gender, but are gorgeous to behold. Often the Looker will have some perceived character flaw that makes them unsuitable to be the Love Interest, this will occasionally turn out to be a misunderstanding and the Looker will become the Love Interest, but this is rare.'
        ) , //25
        array(
            'Type' => 'Love Interest',
            'Description' => 'A Love Interest is a type of recurring Antagonist Character who has a Tension "Conflict" with the Protagonist that draws the Characters together. This may express as a will-they-won’t-they relationship. Of course, for some stories these relationships may be reversed, with the Love Interest being the Protagonist of their own Stories.'
        ) , //26
        array(
            'Type' => 'Magna Mater',
            'Description' => 'The Magna Mater (or Earth-mother) is a female character who has a mentor-like role (and is often married to another mentor), the magna mater offers nourishment and advice, usually of a spiritual or emotional nature, rarely this may be of a romantic or sexual nature.'
        ) ,
        array(
            'Type' => 'Master',
            'Description' => 'A Master is a powerful NPC that has a unique relationship with the Protagonist or PCs. Masters come in many types, from the Slave-master or Lord, who literally owns others, to the Mentors of Apprentices, Master of a vessel the PCs serve upon, or just a boss at work. Masters usually set Tasks (often Quests) for the PCs to perform. Masters can often be the Embodiment of the Above side of the Conflict.'
        ) , //27
        array(
            'Type' => 'Mentor',
            'Description' => 'Mentors are a teacher, they will teach the Protagonist their Skills, Talents and Powers, or at least some Training Descendants. Mentors are usually more powerful than the Protagonist, but they are often busy fighting larger problems, or are too old for adventuring. It is not unusual for Protagonists to have several Mentors through their lives. In T13, Grunts usually require a Hero Mentor, to teach them how to manipulate Dooms. Heroes often eventually seek out a Yarn-Teller to teach them the ways of the Omniversal Characters. Sometimes the Mentor of Grunts may be a Yarn-Teller who will guide them through both.'
        ) , //28
        array(
            'Type' => 'Minder',
            'Description' => 'The Minder is a side-kick, ally, mook, henchman, or Love Interest character who protects and takes care of the Protagonist (or Antagonist). They are usually strong, tough, and athletic, and will die to protect the Protagonist (or Antagonist) from harm. Crucially though, the Minder cares nothing about the Protagonist’s (or Antagonist’s) goals or desires, only their physical well-being is important. The Minder can also be used as a parental figure, especially for younger Protagonists (or Antagonists).'
        ) , //29
        array(
            'Type' => 'Monster',
            'Description' => 'Monsters are an Antagonist Character that physically Embodies the Conflict like no other Character can. "Monster-of-the-week" are Cast or Force of Nature Extras with at least a single Monster Facet (usually the Dominant Facet of the Conflict), "Boss-Monsters" add at least Two and upto 5 or 6 Monster Facets to a Force of Nature Extra (or a Detailed or Full Character), "Big-Bads" can add all the Conflict Facets to their Monsters and may be Demons, Kaiju or similar Characters.'
        ) , //30
        array(
            'Type' => 'Mooks',
            'Description' => 'Mooks are the usually nameless minions / Allies of an Antagonist or Protagonist. Mooks can be any NPC type, but are usually an Extra, from Vex to Force of Nature, depending on the power level being played at. Plots can add Mooks to a Scene,'
        ) , //31
        array(
            'Type' => 'Obsessive',
            'Description' => 'Obsessives are characters who at first seem like an Ally, or potential Love Interest, but they are revealed to be darkly, morbidly obsessed with something (a job, a person, an objective target, revenge, etc), and will turn on anyone (usually the Protagonist or a Love Interest) if they get in the way of the Obsessive’s goals.'
        ) , //33
        array(
            'Type' => 'Outsider',
            'Description' => 'Outsiders are a type of Mentor or Critic character that sit outside of the Conflict. They are often characters who can provide some perspective on the situation, but will never be drawn into it. Outsiders are usually not accepted by either side of the conflict, and may be pariahs or outcasts, but always have insight into the conflict. If all the main characters are young, the outsider is often much older.'
        ) , //34
        array(
            'Type' => 'Patron',
            'Description' => 'A Patron is a master, but usually not the PC’s, often a lord, someone with political clout, or just a bit of cash, who wants a job doing. Patrons may approach the Protagonist offering them work, for pay, or they may blackmail, or exert other pressures upon the PCs to incline them to perform the task.'
        ) , //35
        array(
            'Type' => 'Philanderer',
            'Description' => 'Philanderers are characters, male or female, who seek only hedonistic pursuits. They seek to seduce characters not for love, but as conquests, to be discarded once they have had their way with them. Traditionally, the male Philanderer is seen as more evil than the feminine seductress, due to the perceived nature and worth of feminine and male sexuality and virtue.'
        ) , //36
        array(
            'Type' => 'Platonic',
            'Description' => 'Platonics are Ally characters that could act as Love Interests, but do not. This may be because they are related to the Character, or they have been friends for so long that they cannot see each other as sexual beings. Platonics do not change and never become a Love Interest to the Protagonist (although they can become a Love Interest to literally any other character).'
        ) , //38
        array(
            'Type' => 'Possessive',
            'Description' => 'Possessives are Allies and potential Love Interests, or apparent Platonics, who will sabotage and ruin the Protagonists relationships and even life, so that they are forced to spend time with the Possessive. Possessives can appear deranged, with "If I can’t have them, no one can" often being their ultimate psychotic manifesto. In some cases, the Possessive will actually be the Antagonist, and try to destroy the Protagonist.'
        ) , //39
        array(
            'Type' => 'Protagonist',
            'Description' => 'The primary Character of a Story, usually the Embodiment of the Pressed side of the Conflict, often referred to as the hero or heroine.'
        ) , //40
        array(
            'Type' => 'Rational',
            'Description' => 'A Rational is a thinking, logical, sagacious, character. They will use logic to decide what is best for themselves and others around them, and will not respond well to an emotional appeal. A Rational can usually be persuaded by logic to assist either side. Variants include the emotionless robot, the repressing great emotions with mental techniques alien, the neuro-divergent scientist, and the cold-blooded fish-dude.'
        ) , //43
        array(
            'Type' => 'Rival',
            'Description' => 'A recurring Character who competes with a character (often the Protagonist). They may be the Antagonist for a particular Story (usually a sub-plot), but can appear in other Stories as a Foil, Ally, or as a stand-in if no Embodiment is available. There are a number of different types of Rival.'
        ) , //45
        array(
            'Type' => 'Rogue',
            'Description' => 'A Rogue will not abide by all the laws, rules and demands of the society that they live in. Rogues are usually quick-witted, charming, independent thinkers, who are often liars and criminals because they see no reason not to be. Rogues can be more virtuous than sinful though, as they will often do the right thing, such as saving a life, or helping someone, out of some sense of personal honour, pride, or some desire to subvert expectations. In fact, many rogues seem to cultivate an uncaring, or mercenary attitude, so that others will not expect their help and be surprised when it is offered.'
        ) , //46
        array(
            'Type' => 'Scoundrel',
            'Description' => 'A Character who is often similar to a Rogue in behaviour and appearance, but is actually a Rival to both the Protagonist and Antagonist. Scoundrels delight in lies, betrayal, back-stabbing, and double-dealing, where the Rogue may act rough, but is virtuous, the scoundrel is the opposite, they will act innocent, all sweetness and light, while planning out exactly they are going to skin you.'
        ) , //47
        array(
            'Type' => 'Sentimental',
            'Description' => 'The Sentimental is emotional, often idealistic, and completely driven by emotions. They will oppose or support characters for purely emotional reasons, and cannot be persuaded by logic.'
        ) , //48
        array(
            'Type' => 'Shy',
            'Description' => 'Shys are characters who are the quiet, even silent, shy type. They have difficulty expressing themselves, especially around those they find attractive and may seem asocial or even antisocial. They come in a number of variants, wall-flowers, the invisible, the unrequited.  '
        ) , //49
        array(
            'Type' => 'Side-kick',
            'Description' => 'Side-kicks are usually less powerful companions of the Protagonist. They are often Foil Characters who contrast the Protagonist somehow, such as Watson to Holmes. The Protagonist often takes a Mentor role to the Side-kick, and for this reason Side-kicks and Innocents may be merged to create child Side-kicks. Side-kicks can be merged with the Comic Relief, Love-Interest or Tragic as well to various effects.'
        ) , //50
        array(
            'Type' => 'Stock',
            'Description' => 'Stock (or gag, background or generic) Characters are everyone else, all the shop keepers, politicians, policeman, everyone. They are usually Vex or Chorus Extras (although may rise to Cast Extras if they are reused often enough).'
        ) , //53
        array(
            'Type' => 'Tragic',
            'Description' => 'A tragic is a character fated to die. They are often the "Mr. Body" of the story, a victim of circumstance, in some cases they are an Innocent, who dies immediately that their innocence is lost. Often the Tragic character will not be very detailed because they are destined to die, but a good Yarn-Teller will always be aware of the tragic’s full backstory.'
        ) , //55
        array(
            'Type' => 'Tsundere',
            'Description' => 'A Tsundere is a character who is initially cold towards the Protagonist, but who mellows, and warms towards them eventually. Although, there are a number of variants, Aloof but warms, Scary but mellows, and the lovey-dovey psycho, are all possible.'
        ) , //56
        array(
            'Type' => 'Unruly',
            'Description' => 'An Unruly character is usually a lower social class, although they may be an outsider or a venerable high-class character who no longer gives a hoot, regardless they can get away with bending and breaking the normal rules of society. They will be cheeky, scandalously flirtatious and sexualised, and may act as comic-relief or a love-interest.'
        ) ,
        array(
            'Type' => 'Vice',
            'Description' => 'Vice characters are a hold-over from morality plays, originally they were the embodiment of a specific vice, but over time this evolved into a more comic role, "The Vice" who is seen as some Agent of the Devil, sent to tempt mankind, although due to the comic nature here they are largely bawdy revellers, mostly focused on the hypocrisy of priests. The Vice can be thought of as a comic villain, sometimes more comedic, sometimes more antagonist.'
        ) ,
        array(
            'Type' => 'Wit',
            'Description' => 'A wit character is a type of comedic hero, although they can act as a rival, love-interest or a foil, they are clever, loquacious, sharp-tongued and quick-witted. They are usually a strongly independent and bold character, the sort who will mock a lord to his face, especially if social convention forbids him from acknowledging. Wits can cut a man down to size with a few expertly chosen words, and their quick-wits usually also translate into sound tactical planning and fast foot-work should things go wrong.'
        ) ,
        array(
            'Type' => 'Wretch',
            'Description' => 'A Wretch is any Character who appears to be a sympathetic character, someone down on their luck, homeless, poor, broken-hearted or similar, but who actually is allied to the Antagonist. Wretches are often addicted to substances that the Antagonist will willing provide, in exchange for favours and information. Wretches will sometimes attach themselves to the Protagonist, hanging around their location, following them, ostensibly as a friend-in-need, but really so that they can more directly spy on them for the antagonist.'
        ) , //58

    );
    public static $rivals = array(
        array(
            'Type' => 'Anima',
            'Description' => 'Anima Rivals are more "passive / creative / accepting / nurturing / feminine" versions of the Character. They may not be female, but are often portrayed as camp or effeminate if they are male, although this is not universal. Anima Rivals increase Yin Facets by one Boon and Reduce Yang Facets by one Boon. Such Characters may require some balancing and alterations to Annexes, to be practical.'
        ) , //0
        array(
            'Type' => 'Animus',
            'Description' => 'Animus Rivals are more "aggressive / warlike / destructive/ active / masculine" versions of the Character, they are usually a male version of a female Character, but can just be a more muscular, taciturn or aggressive version. They typically are similar to a Twin, but increase all Yang Boons by one and decrease all Yin Boons by one. Such Characters may need more balancing to be practical, entire Annexes may require rebuilding, rather than just renaming.'
        ) , //1
        array(
            'Type' => 'Competitor',
            'Description' => 'The Competitor is a fairly standard Rival who is intended to be a bit different to the original. For each Facet Boon roll 1d6-3 and apply the result to all Yang facets -altering the Yin Facet Boons as well. You can apply the 1d6-3 again for the Yin Facet (again altering the Yang as well). Competitors generally have similar Annexes to the original character, but obviously Values should vary. Competitors are usually a friendly rivalry, but can also be murderous.'
        ) , //2
        array(
            'Type' => 'Corrupted Clone',
            'Description' => 'The Corrupted Clone is usually a version of the Character that has been mutated somehow. The Corrupted Clone will have at least one additional Hitch (often a Woe) and additional Scale to match. The Corrupted Clone will have largely the same Skills and Talents (although often with changes to Umbrals and Nimbeds), but will usually have a dramatically different seeming variant on the original’s Power, with different Umbrals and Nimbeds to reflect the mutation.'
        ) , //3
        array(
            'Type' => 'Dark',
            'Description' => 'Dark Rivals are (even more) evil versions of the Character. Increase the Character’s Sin and either Heresy or Fury Boons by two and decrease Virtue and either Orthodox or Quiet by two also. Dark Rivals are usually similar to the original, although they may favour Fiend, Beast and Deviant Personalities, and frequently have more dangerous Descendants and darker Annexes and Proficiencies. Dark Rivals may have additional Hitches and increased Scale too.'
        ) , //4
        array(
            'Type' => 'Frenemy',
            'Description' => 'The Frenemy is a Rival to the Character who is both a friend and an enemy. They often have complicated relationships, and may be pulled or pushed embodiments as required, indeed Frenemies can save the Protagonist from danger, only to declare that it is only so they will kill them later. Frenemies usually have some reason they are trusted by the Protagonist and vice-versa. The Frenemy usually has at least one Annex in common with the Protagonist, but their Facets are randomly assigned, not based on the Rivalry.'
        ) ,
        array(
            'Type' => 'Lancer',
            'Description' => 'The Lancer is a Rival to the Character who is on the same team, and often is a best friend to the original. Lancers will have a similar build to the original, but with a major change in the Style of that build. If the main Character is a ice-based, melee-based, shocker, then the Lancer could be a fire-based, ranged, tank. Lancers may alter a quarter of their Boons (6) up by 1, which will also force a quarter (6) down by 1. Lancers are usually the same Scale as the original.'
        ) , //5
        array(
            'Type' => 'Love Rival',
            'Description' => 'The Love Rival seeks the same romantic interest as the Character. A Love Rival is often a Rake or Idol Personality, but may actully be of any Persona. The Love Rival usually has a little in common with the Protagonist, sharing a hobby or profession (ideally they are already what the Character aspires to be), but is often richer, more successful, and more powerful (having at least one more Hitch and often extra Scale).'
        ) , //6
        array(
            'Type' => 'Mirror',
            'Description' => 'Mirror Rivals swap Yin Facets for Yang Facets and vice-versa everywhere they occur. So a Defensive Annex on the original Character becomes an Attack Annex on the Mirror Rival. A Detective may become an Enigma, a Prince a Pauper and so on.'
        ) , //7
        array(
            'Type' => 'Monstrous',
            'Description' => 'The Monstrous Rival is the ultimate Rival type in T13. Monstrous Rivals are an extreme version of the Character. Adding at least Two Monster Facets to the Character (usually the Conflict Facet(s) for their side, plus the Monster Facet of the original Character’s Persona, Core or Highest Hitch). Monsters usually also increase the Boons of their Monster Facets by 3 (with a negative 3 to their anti-facets).'
        ) , //8
        array(
            'Type' => 'Outlander',
            'Description' => 'The outlander is basically a Mirror or Twin Character, with one important difference. They are a different nationality, race or even species to the original Character. Usually the differences will all be in Descendants (often just the National Pact the Character is a member of), although the Outlander may also be Scale +1 to the original.'
        ) , //9
        array(
            'Type' => 'Pure',
            'Description' => 'Pure Rivals are the opposite of Dark Rivals. Increase the Character’s Virtue and Orthodox or Quiet by two and decrease Sin and Heresy or Fury Boons by two also. Pure Rivals are usually similar to the original, although they may favour Hallow, Hermit and Mentor Personalities, and are more benevolent in their choices for Proficiencies, Annexes and Descendants. Pure Rivals may have additional Hitches and increased Scale too, but this is much rarer than with Dark Rivals.'
        ) , //10
        array(
            'Type' => 'Reversed',
            'Description' => 'A Reversed Rival is based off the Character, using the same Statblock, but every Annex is reversed, Personality for Core, Core for Personality, Root for Channel, Channel for Root. Otherwise the Reversed Rival is generally equal in power to the original Character. You may also swap Umbrals for Nimbeds and Resolved and Active Hitches too, where appropriate.'
        ) , //11
        array(
            'Type' => 'Twin',
            'Description' => 'A Twin Rival is exactly like the original Character, although details such as the Proficiencies used, and Annex names may be a little different. The Twin is commonly used when creating a rival group to the PCs, with the group having a Twin for each Character.'
        ) , //12

    );
    public static $playStatusTypes = array(
        array(
            'Type' => 'Planning',
            'Description' => 'This game or plot is in a planning stage. There is very little in it yet, beyond a few notes and maybe a mood board gallery.'
        ) ,
        array(
            'Type' => 'Development',
            'Description' => 'This game or plot is in development. Some things are completed, but it is not ready to play.'
        ) ,
        array(
            'Type' => 'Ready',
            'Description' => 'This game or plot is ready to be played.'
        ) ,
        array(
            'Type' => 'Begun',
            'Description' => 'This game or plot is being played, but they are still in the early game.'
        ) ,
        array(
            'Type' => 'In Progress',
            'Description' => 'This game or plot is being played.'
        ) ,
        array(
            'Type' => 'Hiatus',
            'Description' => 'This game or plot is currently on hold, it may be that they just have not played in a while.'
        ) ,
        array(
            'Type' => 'Finished',
            'Description' => 'This game or plot has been completed.'
        )
    );
    public static $stakes = array(
        array(
            'Type' => 'Low',
            'Description' => 'Low Stakes Ordeals are the least dangerous, or important of the Ordeal Stakes. They are suitable for situations like conversations, studying, or a training sessions. In a Duel situation it would be a Duel to the first touch (Flesh Wound).',
            'Round_Wild_Pool' => '2 Cards',
            'Wound_Modifier' => 'Base Pips &times; 3 are required. (6: Distract, 15: Flesh, 24: Maim, 36:Crippling, 48: Mortal, 63: Carnage, 78: Carnage+) Essentially 3 (or 4 for the Mortal+ Wounds) Cards are required to create that Wound.',
            'Maximum_Soak_Levels' => '3',
            'Rules' => '<ul class="t13ne-stakes"><li>There are Unlimited Phases to the Ordeal Stage</li><li>The Ordeal ends when someone Succeeds or quits.</li><li>Side Bets, Raises, Blinds and Antes are limited to only Score, Tao Sway and Facet Sway.</li></ul>'
        ) ,
        array(
            'Type' => 'Medium',
            'Description' => 'Medium Stakes Ordeals are what we consider a normal Ordeal. They are suitable for most standard work, sports (including contact sports) or an argument. In a Duel situation it would be a Duel to the first Blood (Maim Wound).',
            'Round_Wild_Pool' => '3 Cards',
            'Wound_Modifier' => 'Base Pips &times; 2 are required. (4: Distract, 10: Flesh, 16: Maim, 24:Crippling, 32: Mortal, 42: Carnage, 52: Carnage+) Essentially 2 (or 3 for the Mortal+ Wounds) Cards are required to create that Wound.',
            'Maximum_Soak_Levels' => '2',
            'Rules' => '<ul class="t13ne-stakes"><li>During each Round you begin with a Round Wild Pool of 3 Cards.</li><li>The maximum number of Phases a Character can take in the Stage is equal to the Character’s Facet Boon (normally Zeal in a Motional Ordeal, or Craft in a Creative Ordeal, or Trial in a Competitive Ordeal) in the Ordeal.</li><li>The Ordeal is limited by a Time-limit (a number of Rounds that it must be completed in).</li><li>Side Bets, Raises, Blinds and Antes usually consist of Chi or Stress.</li></ul>'
        ) ,
        array(
            'Type' => 'High',
            'Description' => 'High Stakes Ordeals are where normal combat lies. A fight, sprinting, dangerous work, dangerous sports are all solid examples. In a Duel situation it would be a "Knock-out" situation (Duel ends when all opponents are Crippled or worse).',
            'Round_Wild_Pool' => '4 Cards',
            'Wound_Modifier' => 'All Wounds cost simple Base Cost and require a Limit card, so to cause a Carnage you need an Ace for the Limit, but the attack needs at least another 7 Pips from other cards. (2: Distract, 5: Flesh, 8: Maim, 12:Crippling, 16: Mortal, 21: Carnage, 26: Carnage+)',
            'Maximum_Soak_Levels' => '3',
            'Rules' => '<ul class="t13ne-stakes"><li>During High Stakes Ordeal any Unrecoverable failure in any Stage will usually result in failure overall.</li><li>Characters are limited to Facet Score Phases Per Stage. </li><li>Side Bets, Raises, Blinds and Antes may include Yarn, Shock, Descendants and specific Wounds.</li></ul>'
        ) ,
        array(
            'Type' => 'Extreme',
            'Description' => 'Extreme Stakes Ordeals are where modern warfare and combat lies. Warfare, Rooftop Parkour, and Extreme Sports are all good examples. Any situation where "Life is on the line" or it’s "Life or death" you are looking at Extreme Stakes. In a Duel situation it would be a "To The Death" situation (Duel ends with Maximised Wounds that are Mortal or worse).',
            'Round_Wild_Pool' => '5 Cards',
            'Wound_Modifier' => 'All Wounds are summoned by the Limit Card alone (2: Distract, 5: Flesh, 8: Maim, 10:Crippling, 12: Mortal, 14: Carnage, 15: Carnage+). So an Ace alone creates a Carnage Wound.',
            'Maximum_Soak_Levels' => '4',
            'Rules' => '<ul class="t13ne-stakes"><li>During Extreme Stakes Ordeal any failure in any Stage will result in complete failure and depending upon the ante and side bets may incur additional Wounds or Hitches.</li><li>Characters are limited to Facet Draw Phases per Stage (minimum of 1 for Normal Stages and 2 for Court Stages)</li><li>Side Bets, Raises, Blinds and Antes may usually include specific Wounds, Descendants or Characters (Allies connections).</li></ul>'
        ) ,
        array(
            'Type' => 'Soul',
            'Description' => 'Soul Stakes Ordeals are, perhaps, the highest possible Stakes in the game, at least for any individual Character who is not mucking about in their own past. Any time your immortal soul is placed on the line, by fighting demons, falling in love, testing faith, dealing with Traumas, any situation  that is bigger than life and death, or if the bad guy just made it personal, you are probably in Soul Stakes. In a Duel situation the Duel ends with the Creation of a new Flaw or Woe Hitch for the Characters involved.',
            'Round_Wild_Pool' => '6 Cards',
            'Wound_Modifier' => 'All cards are at +1-6 Pips (roll 1d6). Wounds are summoned by the Limit Pips alone (2: Distract, 5: Flesh, 8: Maim, 10:Crippling, 12: Mortal, 14: Carnage, 15: Carnage+), including the additional Pips. This allows a 4 to summon a Flesh, Maim or Crippling Wound depending upon the roll, and means a Queen must summon at least a Carnage Wound.',
            'Maximum_Soak_Levels' => '1',
            'Rules' => '<ul class="t13ne-stakes"><li>A Soul Stakes Ordeal continues until all Stages are complete, failure won’t end the Ordeal early, not while you can accrue more failure.</li><li>Number of Phases per Stage is usually decided by Yarn-Teller as a set number.</li><li>Side Bets, Raises, Blinds and Antes often consist of specified Quirk or Flaw Hitches.</li></ul>'
        ) ,
        array(
            'Type' => 'Paradoxical',
            'Description' => 'Paradoxical Stakes Ordeals occur when The Fate of the World, Time, History, Sanity, or the nature of Reality is on the line. It is commonly used during Temporal Paradoxes and similar situations. You do not generally have Paradoxical Duels, although fighting your own Grandfather would probably count, he can kill you, but you can’t kill him.',
            'Round_Wild_Pool' => '3 Cards chosen by Yarn-Teller (or Plot) from their own Pool and Hand.',
            'Wound_Modifier' => '>Wounds are summoned for the Limit Pips but at +1 Wound Level over the Card’s normal Limit (2: Flesh, 5: Maim, 8: Crippling, 10:Mortal, 12: Carnage, 14: Carnage+). Wildcards add an additional free Distract Wound along with the Carnage+.',
            'Maximum_Soak_Levels' => '2',
            'Rules' => '<ul class="t13ne-stakes"><li>The Ordeal ends when the Paradox is resolved.</li><li>Number of Phases per Stage is determined by the Yarn-Teller.</li><li>Side Bets, Raises, Blinds and Antes include Alternates.</li></ul>'
        )
    );
    public static $ordealTypes = array(
        array(
            'Type' => 'Railroad',
            'Suitable_For' => 'Simple Linear Ordeals such as Item Creation, Lock-picking, or Linear Travel',
            'Description' => 'Each Stage follows on from the previous Stage only if the Character completes that Stage. If they have to build a fire in the forge as the first step and fail, they will never forge that sword. There may be choices (from Kings, etc) in individual Stages, but the choices are generally irrelevant to the next Stage. It matters very little if the forge is lit with wood or paper, or if the main fuel is charcoal or coal, or if the bellows are pumped by hand or foot.',
            'Image' => '<figure class="tableimage"><svg width="297mm" height="210mm" version="1.1" viewBox="0 0 297 210" xmlns="http://www.w3.org/2000/svg" xmlns:cc="http://creativecommons.org/ns#" xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:rdf="http://www.w3.org/1999/02/22-rdf-syntax-ns#">
