        array(
            'Type' => 'Node-Map',
            'Suitable_For' => 'Any sort of Ordeal can be represented by a node-map, or flow chart. However, node-map Ordeals require a certain amount of preparation, and can be difficult to set up, off the cuff.',
            'Description' => 'The Node-Map is a complex way of thinking about Ordeals. Stages are the major nodes of the map, connected by paths that may include Obstacles and may loop back, or branch, as required. Node Maps are commonly set up by a Yarn-Teller ahead of time as a complex Ordeal that will be performed by the Characters.',
            'Image' => '<figure class="tableimage"><svg width="574" height="490" version="1.1" viewBox="-.5 -.5 574 490" xmlns="http://www.w3.org/2000/svg" xmlns:cc="http://creativecommons.org/ns#" xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:rdf="http://www.w3.org/1999/02/22-rdf-syntax-ns#" xmlns:xhtml="http://www.w3.org/1999/xhtml">
