    public static $ordealTerrain = array(
        array(
            'Type' => 'Open',
            'Description' => 'Wide-open terrain is outdoors, free from clutter, such as a desert, tundra, wasteland, grassland/prairie, open square, open water, empty air and the cold void of outer-space.',
            'Psychosocial' => 'An open mind, unbiased on this topic, or unprejudiced against you is easier to reach, even if there is a great divide between your ideas. Difficulty to travel is often Assisted or Neutral, rarely Opposed.',
            'Rules' => 'Base Range Diff is calculated from the distance in Metres as a Value to a Score (Double Reduced). Base Movement Distance is Pips Value metres so a Jack of Diamonds will let you move 66 metres (11+2 Trump Pips=13). Note that Rolled Scores may be converted to Ordeal Pips by either direct conversion, halving or Reducing depending upon the Power-Level and Facet. Descendant Reach does not alter in Open terrain (a 3 metre Reach is still 3 metres away).'
        ) ,
        array(
            'Type' => 'Closed',
            'Description' => 'Closed terrain is indoors, or a cluttered outdoor space, such as in a woodland, a street with parked vehicles, there’s usually occasional traffic (including pedestrians). This is the normal standard for roads, paths, indoor spaces, and urban settings. It is the standard battle field of the modern day.',
            'Psychosocial' => 'A closed mind is cautious, but already decided. They may be willing to reason to reason, and even change their mind, but it will be a harder fought job. Difficulty to travel is usually Neutral, but may be Assisted or Opposed also.',
            'Rules' => 'Base Range Diff is calculated from the distance in Metres as a Boon to a Score (Reduced). Base Movement Distance is Pips in metres. Descendant Reach is most easily understood in this Terrain.'
        ) ,
        array(
            'Type' => 'Confined',
            'Description' => 'Confined is close-quarters, when your elbows touch the walls, or you are jostled by a crowd. Packed, cluttered environments, such as crowds, jungles, melee, busy market squares, roads with heavy-traffic, cluttered corridors and small furnished rooms.',
            'Psychosocial' => 'A confined mind is completely closed to other ideas. These people believe that beliefs different than their own are somehow already immoral or even criminal. Such a mind is very hard to reach and effect, with years of effective defences, such as the ability to spot fallacies in counter-arguments, formal training in apologetics or mental conditioning such as doublethink. Difficulty to travel is often Opposed, but may be Neutral occasionally. Assisted Paths will exist away from or around Protected Spaces occasionally.',
            'Rules' => 'Base Range Diff is the distance in Metres as a Score. Base Movement Distance is Pips Score (Reduced) in metres. Descendant Reach can create issues causing long-reached Weapons to become ineffective in confined spaces. Range counts for the Reach of the Descendant, and usually counts as Hip-fire (see Firing Type) unless both hands are on the weapon when it may count as braced.'
        ) ,
    );
    public static $ordealTerrainModifiers = array(
        array(
            'Type' => 'Paved',
            'Description' => 'The terrain is smooth, open, level and firm underfoot. Such as you would find on a well-maintained city street, piazza or courtyard.',
            'Rules' => 'Does not modify Range, Reach or Movement at all.'
        ) ,
        array(
            'Type' => 'Uneven',
            'Description' => 'The terrain is paved, but uneven, usually by using river stones or cobbles, or due to wear and tear to bricks or flags.',
            'Rules' => 'Adds +1 Difficulty to all Movement on the terrain. Does not modify Range or Reach'
        ) ,
        array(
            'Type' => 'Field',
            'Description' => 'The terrain is mostly smooth, although the occasional divot or lump may hide in the long grasses.',
            'Rules' => 'Adds +1 Difficulty to all Movement and Range calculations, but does not affect Reach.'
        ) ,
        array(
            'Type' => 'Rough',
            'Description' => 'The terrain is rough ground, this may be due to very uneven ground or dense clutter such as furniture.',
            'Rules' => '1 &half; &times; Difficulty for Movement. Adds +1 Difficulty to all Range and Reach Difficulties.'
        ) ,
        array(
            'Type' => 'Soft',
            'Description' => 'The terrain is soft, such as very muddy soil, deep snow, fine sand, or scree. Soft terrain is not a stable platform for firing except when prone.',
            'Rules' => 'Doubles the Difficulty of Movement and Reach. Adds +3 Difficulty to Range unless prone.'
        ) ,
        array(
            'Type' => 'Slick',
            'Description' => 'The terrain is slick, often smooth rock with a layer of slime, or ice, that makes movement and large weapons more Difficult.',
            'Rules' => 'Doubles Difficulty of Movement and Reach. Adds +1 Difficulty to Range.'
        ) ,
        array(
            'Type' => 'Moving',
            'Description' => 'The terrain is moving, this is common in vehicles, such as the pitch and roll of a ship\'s deck or the yawing of a train corridor.',
            'Rules' => 'Adds between +1d4 to +1d12 Difficulty to all Range, Reach and Movement Actions on the vehicle depending upon the speed, acceleration, violence of the ocean, etc.'
        ) ,
        array(
            'Type' => 'Flooded',
            'Description' => 'The terrain is covered in a liquid, usually water. This is common to oceans, seas, lakes, rivers, shorelines, streams, as well as during floods. Often the liquid will be in motion, whether flowing with gravity or the tide, thermal currents, vortices, undertows, or waves.',
            'Rules' => 'Reach and Movement Difficulties increase by 2% for each centimetre depth of liquid (such that movement Difficulties are Tripled (200%) in 1 metre deep water). Adds +1 to Range Difficulties for each metre of depth to a maximum of +12 (this reflects waves and other ambient motion).'
        ) ,
        array(
            'Type' => 'Jagged',
            'Description' => 'The terrain is covered in something dangerous, such as sharp rocks, brambles, thorns, or poisonous plants. The terrain can wound Characters and Damage Descendants.',
            'Rules' => 'All movement (including Reach attacks) in the area accumulates Pips towards a Wound at the current Stakes. Typically Characters will wish to restrict movement so only Distract Wounds are possible. Any Wound of Flesh Wound or Higher will immediately end a movement Action at the moment it happens (even before the end of expected movement). Does not effect Range.'
        ) ,
        

    );
    public static $ordealMotionType = array(
        array(
            'Type' => 'Flight',
            'Description' => 'Flying, leaping, galloping and sprinting are the fastest ways that things move. You better trust the floor under you (if you touch it) and not want to change direction much.',
            'Rules' => 'Travelling in a straight line you may double the Pips of the card. However, each change of direction by 15-45 degrees also costs 2 Pips and ceases that doubling effect if you make more than a 60 degree turn at any point.'
        ) ,
        array(
            'Type' => 'Run',
            'Description' => 'Jogging, trotting, loping or paced running is how you run long distances. It is never as fast as Flight, but is safer and you can do it for longer. Running is the standard loping, swimming, or bounding gait of most animals, and during most action sequences is the standard way of moving.',
            'Rules' => 'Standard Pips for card, changing direction by up to 45 degrees is free, more than that costs a Pip.'
        ) ,
        array(
            'Type' => 'March/Sneak',
            'Description' => 'Marching is a focused walk, you are going somewhere a good pace, but do not want to exhaust yourself. A march is a brisk-paced walk, but you still have a chance to spot trouble that you might have missed if running. Sneaking is usually a bit slower than a march, but still a quickened walk, with a lot more caution.',
            'Rules' => 'Marching and Sneaking use between two-thirds to three-quarters of the card Pips moving. The remaining one third to a quarter of the Pips can be used to add to another concurrent action, such as hiding, spotting, defence, attacking or whatever. e.g. When playing a Jack of Diamonds (13 Pips of Movement because of the Trump +2), that will allow movement with up to 9 Pips and leave 4 Pips for something else. Changes of Direction are completely free when marching and sneaking.'
        ) ,
        array(
            'Type' => 'Walk',
            'Description' => 'Walking is the standard slow pace we generally use when we aren’t too focused on getting there. Walking should allow you to spot things that you might otherwise miss, and you can move more quietly than a Run, or even when sneaking. Walking is the fastest pace that humans can swim at, generally, and that holds true for most beings out of their normal environment, but accustomed to it.',
            'Rules' => 'Walking halves the Pips of the card. But adds up to half the Pips to any action performed at the same time (such as hiding or taking aim). This can mean you walk closer and then use the remaining Pips to pay Range on a shot, for example. When used for Swimming the other half of the Pips are used to offset the Difficulty of moving through flooded terrain, as well as useful survival skills like not drowning.'
        ) ,
        array(
            'Type' => 'Crawl/Creep',
            'Description' => 'Crawling or Creeping is the slowest way that we move. You can crawl silently and without being detected with only the flimsiest of cover. Crawling is also the standard speed that a being can move at when suddenly stranded in an unfamiliar environment (literally a fish out of water, or human in smoke).',
            'Rules' => 'Crawling allows a card to be prepared, and also used for movement, which is pretty unique. However, crawling Reduces the Pips a tier (A Joker with Pips 15 prepared allows a Crawl of 4 Pips, meaning only one metre when in Confined Terrain. Playing three Tens in Preparation of various actions could allow crawling 7 Pips which is only 2 metres in a crowd. Normally the full Preparation (30 Pips) is available to avoid being noticed (move silently/hide), as defence (from the smoke and fire for example), or for an eventual Attack.'
        )
    );
    public static $ordealFiringType = array(
        array(
            'Type' => 'Hip-Fire',
            'Description' => 'Firing from the hip, snap firing, thrown with a flick of the wrist, turning the gun on its side, or using full-auto (after the first shot) with most SMGs. Also trying to hit multiple targets at the same time (who aren’t stood close together) or hit any target while moving quickly. Also trying to hit someone with a long reach weapon with one hand.',
            'Rules' => 'Difficulty is Reduced one LESS tier than normal or is Doubled, whichever is more. In open territory a range of 105 metres would normally have a difficulty of 5, when Hip-firing this would increase to 17 (being more than 10). Hip-firing should be used by anyone with only a cursory understanding of the weapon, a first use, single applicable proficiency, etc.'
        ) ,
        array(
            'Type' => 'Braced',
            'Description' => 'The moment you brace the gun properly, pull the stock into your shoulder, use the sights, throw with your whole arm, or use a weapon with proper training while stood still, usually with two hands on the weapon, you can say you’re braced. Generally consists of a focused attack, centred on a single target (or close group of targets).',
            'Rules' => 'Standard Range Difficulty is calculated normally from the terrain type, so 50 metres across a shopping mall would have a Difficulty of 10 as it’s a Closed Terrain. Bracing a weapon requires at least two Proficiencies that cover the use of the weapon.'
        ) ,
        array(
            'Type' => 'Prone/Tripod',
            'Description' => 'Lying down, or using a mounted weapon such as a tripod or bi-pod, usually with telescopic sights, proper military training, and preparations (at least one card played preparing the attack) allows Sniping at extended Range.',
            'Rules' => 'Range Diff is Reduced. This might allow a Character to fire into 30 metres of dense crowds, with a Difficulty of 7. Prone shooting requires at least 3 Proficiencies that cover the use of the weapon. Additionally a "spotter" can Prepare additional cards into the shooter’s Style Reserve (if they have a suitable Style Reserve themselves), as they tell them windage, range and other information. '
        )
    );
    public static $ordealEngagementType = array( //ordeal engagement is an optional rule to stop you from running away from enemies in combat without being hit.
        array(
            'Type' => 'Embraced',
            'Description' => 'Embraced is the most engaged that a Character can be. There is physical contact between the Characters at multiple locations on each others bodies, as they are literally wrapped around each other. This is the level of engagement of intimate encounters and grappling combats.',
            'Rules' => 'Embraced Characters cannot disengage without risk of attack from the other and 5 automatic Failure Levels on the Disengagement action. Embraced Characters cannot be engaged by other Characters individually very easily (they are firstly usually engaged as a unit - with additional targets for each member of the embrace automatically applied) so any attack or Fumble that is directed against one, will threaten both, each additional Success Level in an attack may reduce the Wound applied to the one you aren&#39;t targeting by one Level.'
        ) ,
        array(
            'Type' => 'Locked',
            'Description' => 'Characters that are locked in combat are currently close enough to be exchanging blows between them (they are both within each other&#39;s Descendant&#39;s Reach). There will be frequent and swift contact between the Characters or Descendants, usually as melee attacks are exchanged.',
            'Rules' => 'Characters who are locked in combat cannot disengage without risk of attack from the other and 2 automatic Failure Levels on the Disengagement action, but the individual Locked Characters may be engaged (and attacked) by other Characters without too much risk to the other Locked Character.'
        ) ,
        array(
            'Type' => 'Engaged',
            'Description' => 'Characters that are engaged in combat are usually firing shots at each other (either physically or verbally), they will be at greater distance than the Reach of their Descendants, but close enough to shout insults. Characters may circle each other at a distance or try to close as they see fit.',
            'Rules' => 'Engaged Characters cannot disengage without risking an attack from the Character they are engaged with 1 automatic Failure Level on the Disengagement action. Engaged Characters may be engaged by multiple Characters without penalty.'
        ) ,
        array(
            'Type' => 'Suppressing',
            'Description' => 'Characters that are Suppressing are usually firing shots to keep the enemy in cover. They often are not directed Physical attacks at individuals among the enemy, but rather are Psych Duck attacks used on multiple targets to keep them "ducked". Suppressing Characters often do not reveal themselves completely from cover either.',
            'Rules' => 'Suppressing Characters are lightly engaged with everyone they are attacking. Disengagement requires a Disengagement action and risks an attack (usually a suppression) from those you Suppressed.'
        ) ,
        array(
            'Type' => 'Threatening',
            'Description' => 'Characters that are threatening another may have a weapon in their hands, or just have a stern glare, threats are nebulous like that. However, a threatening Character is minimally engaged with their target. They are watching the person they are threatening and are ready to make an attack, or counter-attack if the target starts anything.',
            'Rules' => 'Threatening Characters are semi-engaged with an enemy, even though they have not even drawn a weapon or spoken a word (note that usually holding a weapon is a lot more intimidating than not). They may make a Disengagement Action to cease threatening, but may be attacked when doing so. However, they may react to any attempted Action immediately after that Character’s Draw, by Playing 1 Card as an Attack from their Ordeal Pool, as well as any Prepared Cards from the weapon they are weilding.'
        ) ,
        array(
            'Type' => 'Threatened',
            'Description' => 'Characters who are threatened or suppressed by another Character are semi-engaged. They are being observed and threatened by another. If they make a move to engage or disengage they will be noticed.',
            'Rules' => 'A Character threatened must make Disengagement Action to leave the engagement without risking an attack from the Threatening Character. They can instead Suppress or Engage the enemy, however this Action will risk an Attack from the Threatening Character.'
        ) ,
        array(
            'Type' => 'Disengaging',
            'Description' => 'A Disengaging Character is trying to back out of the engagement carefully, they may duck behind cover and crawl away, or retreat with their weapons drawn to parry any attacks, or they may keep a shield to the enemy and step out of Reach. The point is to get away without exposing yourself to an easy hit or shot.',
            'Rules' => 'Disengaging Characters are trying to disengage from one of the engagement states above (Embraced-Threatened). Disengagement Action involves playing movement cards (<span class="t13ne-redcard">&diams;</span> Trump), one at a time, that can move you to Reach (to escape Embrace), beyond the Reach (to escape Locked), beyond Range (to escape Engaged), or out of sight or away (to escape Threatened/Threatening), of an enemy you are engaged in (note that some may require specific Pip Difficulties). If the enemy can play a Higher card from their Ordeal Pool as an Attack (<span class="t13ne-blackcard">&spades;</span> Trump) after any Disengagement card, then you have failed to Disengage, are still at that level of engagement, and have a Wound to Soak. Additional Failure Levels may Increase the Level of the Wound that must be Soaked. Note it is possible therefore to break successfully from Embraced, through Locked, to Engaged, but then be stuck Engaged with a Carnage Wound and another random Wound to Soak.'
        ) ,
        array(
            'Type' => 'Disengaged',
            'Description' => 'A disengaged Character is not currently engaged or threatened by any one in any way.',
            'Rules' => 'No special rules, they are not engaged. If they see, or are spotted by an enemy they may become threatening or threatened, depending upon the situation.'
        ) ,
    );

    public static $socialOrdealActions = array( //array('Type'=>'', 'Suggested_Facets'=>'Awe, Burden, Craft, Dominion, Enigma, Fury, Gossamer, Heresy, Inertia, Jeer, Key, Liberty, Miasma, Nature, Orthodox, Phoenix, Quiet, Rook, Sin, Trial, Virtue, Wyrd, Yonder, Zeal',  'Description'=>''),
