        array(
            'Type' => 'pool',
            'Description' => 'a group of objects that is used to move objects from one group to another. Pools can copy from a list and create a new list. They can also place things in lists which removes them from the pool. Characters can be copied into the list to be used as a pool of wandering monsters, for example.'
        ) , //5
        array(
