    public static $characterCompositions = array(
        array(
            'Type' => 'Chant',
            'Suitable_For' => 'Extra Characters',
            'Description' => 'Chants are simple Compositions that influence the Extra Characters within the current Setting. Chants are often monotone, or singular chords, and may be focused entirely upon the lyrical content of the chant.',
            'Rules' => 'A Chant affects only Extra Characters. Chants are melodically simple, focusing on a single note or chord in a certain key (although they may change Chord in any Bar like any voicing). Extras who match key with the Chant (or one of the notes of its chord) will be affected by the Chant. Extras who do not, will not. Up to 12 different Chants can be running at once, with each Conductor able to Conduct up to 3 Chants simultaneously.'
        ) ,
        array(
            'Type' => 'March',
            'Suitable_For' => 'Grunt Characters',
            'Description' => 'The March is the signature Composition of the Grunt Character. A March uses a simple time signature, usually 2:2 or 4:4. That is 2 or 4 beats per bar. Marches typically are 16 or 32 bars long with a single modulation usually from Tonic to Subdominant (and occasionally back — see Intervals).',
            'Rules' => 'Marches affect only Grunt Characters (usually of a suitable key).'
        ) ,
        array(
            'Type' => 'Aria',
            'Suitable_For' => 'Hero Characters',
            'Description' => 'The Aria is strictly speaking an operatic solo, that conveys emotions rather than the plot, and is named for the Italian word for "air" which is used in the same musical meaning in English. This is a Composition for a single voice that combines a Melody with lyrics to create a specific song style.',
            'Rules' => 'Arias are strict in their lyrical composition, and must use an AB, ABA, ABB, or ABACA rhyme structure. Hero Characters who are in key with the Aria will experience it as stated. Those Heroes who are not in key may experience distorted versions of the Aria.'
        ) ,
        array(
            'Type' => 'Leitmotif',
            'Suitable_For' => 'Lite Characters and Descendants',
            'Description' => 'Leitmotifs are simple recurring musical ideas within other Compositions that influence Lite Characters and Descendants. They are used in T13 Lite games to guide Character Drama and Development beyond any Plots that may be occurring. Leitmotifs can consist of Pitches (often arranged in Melodies or Chord Sequences) and Rhythms.',
            'Rules' => 'Leitmotifs affect Lite Characters and Lite Descendants that are in key with the Leitmotif.'
        ) ,
        array(
            'Type' => 'Anthem',
            'Suitable_For' => 'Archetype Characters',
            'Description' => 'Anthems are archetypal songs for Archetype Characters. They can be celebrations of nations, careers, and such large groups that they are best represented by Archetype Characters. Anthems are otherwise like any composition.',
            'Rules' => 'Anthems typically affect only Archetype Characters who are in tune with them. However, it is possible for Archetypes to become swept up in any Character Composition, if it becomes Anthemic during play.'
        ) ,
        array(
            'Type' => 'Solo',
            'Suitable_For' => 'Yarn-Teller Character',
            'Description' => 'Solos are Compositions intended to affect only Yarn-Teller Characters. They are typically intense melodic tunes that affect the Yarn-Tellers who are in tune with them. Often affecting (or even specifying) the Yarn-Teller’s Narration Technique as well as the nature of what they must narrate.',
            'Rules' => 'Solos affect only Yarn-Teller Characters who are in tune with them. Yarn-Tellers usually respond and narrate Character Compositions for each other, as well as the other Characters, it is worth noting.'
        ) ,
        array(
            'Type' => 'Symphonies',
            'Suitable_For' => 'Any Locations',
            'Description' => 'Symphonies are Compositions that affect Locations, even Locations as large as Settings. Symphonies can work much like the Score of a Film, with individual Characters bringing their own Tunes, Hymns, Marches and Chants to the Symphony. And Locations can respond to the Character Compositions, but it can also work the otherway. With the Setting and Location defining the Symphony, the Characters, or at least those in tune with the Symphony will be affected by the Location’s influence.',
            'Rules' => 'Symphonies affect a Location, and either respond to Character Compositions, or direct them from the Symphony if they are in tune.'
        ) ,
        array(
            'Type' => 'Opera',
            'Suitable_For' => 'Groups',
            'Description' => 'Operas are Compositions that affect and influence entire groups of people, often this will be a specific Pact that the Opera influences, but any group of Characters that are thrown together can create a spontaneous "Opera".',
            'Rules' => 'Operas typically embrace all the Characters of a group, where possible they will match Keys with all members of the Group, giving each Character a section or voicing where they define the Key. Although additional modulations may be required to reach harmonic resolution.'
        ) ,
        array(
            'Type' => 'Hymn',
            'Suitable_For' => 'Divine Characters',
            'Description' => 'Hymns are Compositions that affect Divine Characters who are in tune with the Hymn. Hymns can affect and influence religious people, as well as more divine and spiritual entities such as angels and gods, although they will be harmonically aligned.',
            'Rules' => 'Religious beings in tune with the Hymn are affected, as are Spiritual beings a Perfect Fourth above the Hymn Key, and Divine beings a Perfect Fifth above the Hymn Key.'
        ) ,
        array(
            'Type' => 'Voice',
            'Suitable_For' => 'Any Character',
            'Description' => 'A Voice is a melody written for a single voice, it may be a line within a choir, and be a part of a larger chord voicing. Voices are typically written for a specific Character, and multiple voicings can be active at once. Compositions may present Chord sequences as separate Voice lines for individual Characters, or the Character may be allowed to choose the Pitch they voice themselves in an improvisation.',
            'Rules' => 'A Voice affects and influences a single Character. A Voice will typically sit within a larger Compostion, like a voice in a choir singing a single Pitch to help create the Choir’s chord, and need not worry about whether the Character is in tune with the Voice at all.'
        ) ,
        array(
            'Type' => 'Melody',
            'Suitable_For' => 'Any Characters',
            'Description' => 'Melodies are a series of Pitches (or notes or tones) along with some rhythms that tell us when to play which pitches. Technically there is no difference between a Voice and a Melody, except Voices are assigned to Characters and Melodies are not.',
            'Rules' => 'Typically a Melody will affect only Characters who are in tune with the Melody. However, if no Character is in tune with a Melody, then all Characters will experience the Melody, even if they are vastly out of tune.'
        ) ,
        array(
            'Type' => 'Refrain',
            'Suitable_For' => 'Any Descendant',
            'Description' => 'A Refrain is a Composition for a singular, specific Descendant. This might reflect a training montage or some similar event in a Character’s story, but is usually some recurring device or idea that various Characters will encounter. If a powerful Descendant has its own Refrain it may have a impact on Characters who are around it, smart-alec magic weapons, and rings of dark lordship often have refrains.',
            'Rules' => 'A Character Composition for a Descendant. Refrains may affect and influence the Descendants Owner, Creator and Weilders. Typically Refrains do not care if the Weilder, Owner or Creator is in Key, and can have profound effects upon these Characters.'
        ) ,
        array(
            'Type' => 'Jingle',
            'Suitable_For' => 'Any Descendants',
            'Description' => 'Jingles are short (often a single Bar) Compositions for Descendants. Unlike Refrains that are specific to a singular Descendant, Jingles are more generic. Where the one true Ring of power has a refrain, all electronic products made by a single fruit-named manufacturer might have the same Jingle.',
            'Rules' => 'Jingles are Compositions for Descendants, they are commonly quite generic and broad (such as all products from the manufacturing company sharing the same Jingle). Typically a Character that uses a Descendant with a Jingle must be "In Tune" to be affected by the Jingle, matching Key in often in Tune, but any Perfect Interval can also count at the Conductor’s discretion.'
        ) ,
    );
    public static $compositionTempos = array( //heavy, creeping, leisurely, moderate, brisk, hurried and hasty
        array(
            'Tempo' => 'Grave',
            'Description' => 'A Grave Tempo implies a depth to the composition, things that happen slowly have gravitas, they tend to be important, huge and unweildy affairs. A Grave tempo implies serious business, with large Stakes, where little happens quickly, such as Geo-politics, Economics, Social Change, etc. Grave Compositions can feel too heavy for some people to use them as Character Arcs, and Plots are better suited to this level of intensity, but a Grave Composition can run alongside an Epic Plot very nicely.',
            'Difficulties' => 'Difficulties usually reflect the size and importance of the Composition, if the fate of a Kingdom is on the line, the Difficulty should reflect at least the size of the Kingdom.',
            'Obstacles' => 'Obstacles are frequent and often multiple. Every Bar should contain at least one Obstacle per Beat, but they are usually collected onto the Strong Beats and often mostly the first beat of the Bar.',
            'Hurdles' => 'Hurdles are most common in Grave Tempo, and every Beat can potentially hold a Hurdle for a Character. Each Bar should hold a Hurdle for at least two Characters (often the lead and bass voicings).',
            'Stakes' => 'Grave Tempo usually means Extreme, Soul or Paradoxical-Stakes, a lot rides on the Stakes of a Grave Composition, including (at least once) the fate of the entire Omniverse.'
        ) ,
        array(
            'Tempo' => 'Creeping',
            'Description' => 'A Creeping Tempo implies slow progress towards some goal, often with a great threat that must be avoided at all costs. Creeping Compositions are often delicate situations, that must be handled with care, as they carry suspense and uneasiness, usually any mistake along the way will destroy or unbalance everything accomplished so far. Creeping tends to be somewhat time sensitive, and is often secretive, such as an infiltration, manipulation, or corruption. Often Creeping Compositions work best alongside a Story or Volume Plot. Creeping Tempo will often be overwhelmed or interrupted by Suspense and Drama from a Plot.',
            'Difficulties' => 'Difficulties in Creeping Compositions are usually caused by those Opposed to the goal of the Composition. This can be as simple as a Character (a guard for example) who must be avoided, persuaded or bribed; how sharp-eyed is this "guard"? How alert to the approach? how corrupt are they? The answers to these questions should let you decide the difficulty.',
            'Obstacles' => 'Obstacles are very common to Creeping Tempo, usually Strong Beats will contain two or three Obstacles, Weak Beats will contain only one or two. In Creeping Tempo even Rests may contain Obstacles.',
            'Hurdles' => 'Hurdles are quite common in Creeping Tempo, typically only one Hurdle is found per Bar, often opening the Bar, this is usually given to the lead voicing Character of the Bar.',
            'Stakes' => 'Creeping Tempo can be of any Stakes, however usually a unique point of the Creeping Composition is that there is a Failure state hanging over the whole Composition. If the Characters cannot reach their goal without being spotted, for example, then they will be captured, and potentially even killed. These Stakes should be obvious from context, and enforced by the Referee, so that if a Conductor fails to make the consequences of failure obvious enough then the Characters should not be unfairly punished.'
        ) ,
        array(
            'Tempo' => 'Leisurely',
            'Description' => 'A Leisurely Tempo is the least important of the slower tempos on the one hand, and quite commonly used on the other. It is the Tempo of relaxed social, vacation or weekend activity, when you meet with friends and are in no rush to leave, can stop for a drink and a chat. This makes it the ideal Tempo for most Character-driven Compositions. Leisurely Compositions can work alongside any Plots very easily and should be used if no other Character Arcs are currently being used.',
            'Difficulties' => 'Difficulties in a Leisurely Tempo tend to be small things, although you may compete against another Character, most Difficulties will be simple routine tasks, or perhaps Hobby challenges at worst.',
            'Obstacles' => 'Leisurely Tempo does not usually include Obstacles, although occasionally one may be placed upon the opening of a new Bar, particularly following a Chord Change.',
            'Hurdles' => 'Hurdles are not common in Leisurely Tempo, but they can occur.',
            'Stakes' => 'Leisurely Tempo is usually a place of Low Stakes although that may rise to Medium or Soul-Stakes on the Strong Beat following a Chord Change.'
        ) ,
        array(
            'Tempo' => 'Moderate',
            'Description' => 'A Moderate Tempo is the most common Tempo, and is pretty much the default. This is the Tempo of normal life, the working week. This is the Tempo of people headed from meeting to meeting, working towards deadlines, and just trying to get to work on time.',
            'Difficulties' => 'Difficulties in Moderate can range vastly, somedays work can be standing at the water cooler, chatting with people and reading a professional journal, other days there is an overdue project and everyone’s nose is on the grindstone.',
            'Obstacles' => 'Obstacles can vary greatly in a Moderate tempo, although Obstacles are common in the last strong beat of the bar.',
            'Hurdles' => 'Hurdles are rare in the Moderate Tempo, although they can occur on any Strong Beat following a Chord change.',
            'Stakes' => 'Stakes of Moderate Tempo are typically Low or Medium, although they can rise to High for a Bar or two.'
        ) ,
        array(
            'Tempo' => 'Brisk',
            'Description' => 'A Brisk Tempo is the slowest of the fast Tempos and is mostly used in social and work situations. A Brisk Tempo implies that the Characters are trying to move things along, or push forwards to get things done faster rather than slower. This briskness implies that Characters should still be careful and thorough, unlike the faster Tempos.',
            'Difficulties' => 'Difficulties are often raised slightly as Characters try to meet deadlines, push things through faster, or get more done than normal. Brisk Tempo Compositions will often make a Character add additional Targets, or reduce production times, and encourage Characters to push ahead without worrying too much about consequences.',
            'Obstacles' => 'Obstacles are exceptionally rare to the Brisk Tempo, although they can be added as a response to the Characters not being thorough.',
            'Hurdles' => 'Normally there will be a single Hurdle that the Characters will have to overcome, this is often a consequence of the Brisk Tempo.',
            'Stakes' => 'Stakes are typically Low, but can occasionally be as high as Extreme. Stakes higher than Medium should be rare.'
        ) ,
        array(
            'Tempo' => 'Hurried',
            'Description' => 'A Hurried Tempo is commonly used when there simply isn’t enough time to get everything done, when working with deadlines, or strict time constraints. Whenever Characters will have to make decisions about what they can do in the time available (do we barricade all the doors a bit, or the main door a lot?) then the Hurried Tempo is probably the one to use. Hurried Tempo creates additional problems as everyone is rushing; mistakes will be made and probably not caught.',
            'Difficulties' => 'Difficulties rise the closer we get to the deadline, even simple tasks can become impossible if left too late, and therefore the Characters must prioritise their actions properly throughout the Hurried Tempo.',
            'Obstacles' => 'Any mistakes or individual Failure Level in a previous Bar of a Hurried Tempo Composition will add an Obstacle to a later Bar. This can, <sem>and will</em>, accumulate, with multiple Obstacles per Bar possible later.',
            'Hurdles' => 'Hurdles can also increase throughout the Composition, although never to the level of Obstacles, 1 Hurdle per Character per Bar is usually the limit here, with only the Lead voice having them earlier, later all Characters will have one.',
            'Stakes' => 'Hurried Tempo can be any Stakes, but always tend to rise with time. Hurried Tempo modifies those Stakes further, adding Automatic Failure Levels to all Actions in the later Bars of the Composition. Typically this is +1 Failure Level per Bar of the Composition that has already past.'
        ) ,
        array(
            'Tempo' => 'Hasty',
            'Description' => 'Hasty Tempo is the most break-neck pace that Characters can operate at. There is no time to stop and think about what the Characters are doing, and inevitably that means that mistakes occur. Hasty Tempo is the fastest that a Composition can move, and is the equivalent of the fastest paced Action Plots.',
            'Difficulties' => 'Difficulties are always raised in a Hasty Tempo. There simply isn’t enough time for them to do anything at a normal pace. Difficulties are often simply Doubled to try and make everything happen as close to instantly as possible.',
            'Obstacles' => 'Hasty Tempo increases the number of Obstacles with time. Typically the number of Obstacles will rise, every Bar, until every Beat of the final Bar has up to 3 Obstacles on the Strong Beats and 2 on the Weak.',
            'Hurdles' => 'If any Character attempts to make any decision in Hasty Tempo, it adds a Hurdle for the Character to at least their next Bar (and the longer the decision took to make, the more Bars should be affected) so if a Character has to choose a door to run through, that is a single Hurdle. If they stop to think about which door, feel free to add a Hurdle to every remaining Bar for that Character.',
            'Stakes' => 'Any, but Stakes tend to rise with time, with additional Failure Levels, Obstacles and Hurdles being automatically added as a consequence of later Bars.'
        ) ,
    );
    public static $narrativeStructures = array(
        array(
            'Type' => 'Rock Song',
            'Description' => 'The classic structure of Rock Songs for no other reason than it struck me.',
            'Structure' => [['Type' => 'Intro',
            'Description' => 'introduces the main Riff'],
            ['Type' => 'Verse',
            'Description' => 'Narrative section'],
            ['Type' => 'Pre-Chorus',
            'Description' => 'Builds Tension towards the Chorus'],
            ['Type' => 'Chorus',
            'Description' => 'The Chorus is the meat of the song'],
            ['Type' => 'Main Riff',
            'Description' => 'The return of the Main Riff from the Intro'],
            ['Type' => 'Solo Section',
            'Description' => 'Variations of the Main Riff and Chorus'],
            ['Type' => 'Bridge',
            'Description' => 'A contrast section before the return of the Chorus.'],
            ['Type' => 'Chorus',
            'Description' => 'Back to the Meat'],
            ['Type' => 'Main Riff',
            'Description' => 'The return of the Main Riff from the Intro']]
        ) ,
        array(
            'Type' => 'Tercet',
            'Description' => 'The classic three-line Stanza structure, usually of a ABA, BCB style progression if continued. The Tercet makes the 1st and 3rd lines rhyme, giving them similar structures and motifs.',
            'Structure' => [['Type' => 'First Line',
            'Description' => 'Something is established, questioned, or occurs, such as an Action sequence involving a rooftop chase.'],
            ['Type' => 'Second Line',
            'Description' => 'Something counter-points the First Line, answers the Question, or reacts to what has occurred. Such as a Recovery Weft following the Action Warp.'],
            ['Type' => 'Third Line',
            'Description' => 'To rhyme with the First. What was established, and counter-pointed, now returns. The question that was answered is asked again, because the answer was not satisfactory, or because of a change of emphasis or meaning. We now have and Action sequence once again high up, perhaps now flying above those roof-tops in a magic carpet dash.']]
        ) ,
        array(
            'Type' => 'Quatrain',
            'Description' => 'A classic four-line Stanza structure, usually of a ABBA, ABAB, or occasionally AABB style progression. The Quatrains A<super>1</super> and A<super>2</super> lines rhyme, giving them similar pacing and structure. This is similarly true of the counterpointing B-Lines, which may have similar or different rhythms to the A Lines.',
            'Structure' => [['Type' => 'First A Line',
            'Description' => 'Something is established, questioned, or occurs, such as an Action sequence involving a rooftop chase.'],
            ['Type' => 'Second A Line',
            'Description' => 'Something that builds on the First A Line. Continuing and echoing it’s style, pacing and setting. This is a continuation or a reprise of the roof-top chase, usually with elevated Stakes, perhaps gun-play, higher roofs, or dark.'],
            ['Type' => 'First B Line',
            'Description' => 'A reaction to either the First or Second A Line. This answers the question that was asked by A or is a Weft to it’s Warp.'],
            ['Type' => 'Second B Line',
            'Description' => 'To rhyme with the First, B-Line. Another Weft follows, or another Question is asked by an A Line is answered. ']]
        ) ,
        array(
            'Type' => 'Spenserian',
            'Description' => 'The fixed verse form created by Edmund Spenser for the Epic poem, made up of lines in the form ABABBCBCC. This creates a complex interplay of themes as the lines share the themes, setting, rhythm and pacing.',
            'Structure' => [['Type' => 'First A Line',
            'Description' => 'Something is established, a statement is made. This is often a Revelation Weft event. An example may be a Revelation of a Portal to a new world.'],
            ['Type' => 'First B Line',
            'Description' => 'A response or reaction to the first A line, a Warp to its Weft, it is the reaction to the Revelation, the immediate actions taken in response. In the example, this is the first interaction with the new world beyond the portal, whether the portal is guarded, in case something comes out (which it must), or explored.'],
            ['Type' => 'Second A Line',
            'Description' => 'Something that builds on the First A Line, echoes it, often directly, hence the "rhyme". In the example, this could be a secondary Revelation, perhaps revealing something about the new world (such as it actually being the past or future of the original world), or revealing something about their original world ("Oh you escaped the simulation").'],
            ['Type' => 'Second B Line',
            'Description' => 'This second B-Line follows the second A-line, and it is another reaction to the previous line. This is a Warp to counter the Revelation. Something has gone wrong, and seems to be getting worse. In the example this is when the portal changes somehow, perhaps growing bigger, spitting out something worse than before, or if they passed through the portal then now it destabilises, with the mouth shooting away, or even closing.'],
            ['Type' => 'Third B Line',
            'Description' => 'This Third B-line follows the second directly. This makes it both a continuation of the B-Lines before, but also a response to themselves. This makes this line an echo Warp, the second Warp that follows the A-line’s Weft. This B-line repeat usually raises the Suspense and Stakes for this echo Warp. In the example if the portal wasn’t unstable, moving or  closing it is now, and if it was already then why not add more?'],
            ['Type' => 'First C Line',
            'Description' => 'A response to the Third B-line, that is different to the A-lines, but still counter-point the B-lines. In our example these C lines are still Wefts, but provide no Revelations for our heroes. So instead they may gain an Ally, Annex or Descendant that can help them.'],
            ['Type' => 'Fourth B Line',
            'Description' => 'This Fourth B-line follows the first C-line, and is a final Warp of the verse and so has the highest Stakes so far. In our example if portals have been plopping out bad guys then the biggest one arrives, if they have been trying to stabilise the portal and return home then some one stries to stop them, or it just gets worse than before.'],
            ['Type' => 'Second C Line',
            'Description' => 'This second C-Line follows the final B-line, and is a Weft to follow that Warp. In our example this line would be a Weft Scene where the characters may make yet another Gain, often as a reward for defeating the beasts, or stabilising the portal.'],
            ['Type' => 'Third C Line',
            'Description' => 'This third C-line follows the second directly. This makes it both a continuation of the C-Lines before, but also a response to them. This makes this line a second Weft, that follows a Weft. In our example it represents a final chance to rest and recover from what happened in the previous lines.'],
            ]
        ) ,
        array(
            'Type' => 'Sonnet',
            'Description' => 'Made famous by an English Bard, this particular verse-form was created in Italy. The rhyme form is ABAB CDCD EFEF GG.',
            'Structure' => [['Type' => 'First A Line',
            'Description' => 'Something is established, a statement is made, or a question is asked. This is usually a Hook Event as Sonnets are full Narratives. '],
            ['Type' => 'First B Line',
            'Description' => 'The first B-line expands the original statement, deepening the question. This is usually a Revelation that reveals the Conflict.'],
            ['Type' => 'Second A Line',
            'Description' => 'Something that builds on the First A-Line, echoes it, often directly, hence the "rhyme". This Line indicates that the Loom begins by echoing the Hook, if we began with a Fight this will be a Warp, if we began at rest then now we receive a Weft.'],
            ['Type' => 'Second B Line',
            'Description' => 'This second B-Line follows the second A-line, and it is a reaction to the previous line, but "rhymes" with the Frame Revelation, by reflecting what was revealed. This could mean more Revelations, or it could be that the Conflict begins with a bang.'],
            ['Type' => 'First C Line',
            'Description' => 'The First C-Line indicates that we are stepping into new territory, narratively speaking. This establishes a new dynamic, that need not follow the old. This C-Line can be a Warp or a Weft, but rarely includes Revelations.'],
            ['Type' => 'First D Line',
            'Description' => 'The First D-Line resplies to the C-Line with this new rhyming scheme. This is the still Revelation free Weft to follow a Warp, or the Warp to follow that Weft.'],
            ['Type' => 'Second C Line',
            'Description' => 'The Second C-Line continues to work the story, repeating a similar Warp or Weft as appropriate.'],
            ['Type' => 'Second D Line',
            'Description' => 'The Second D-Line is an echo of the First, responding to to the C-Line with its own Weft or Warp.'],
            ['Type' => 'First E Line',
            'Description' => 'The First E-Line indicates another change in the conflict, this may include an escalation, perhaps of Stakes or the Embodiment may shift to being a Monster. The First E-line also represents a chance to change pace, and so it may randomly be a Warp or a Weft, and need not reflect the D-Line or repeat the C-Line.'],
            ['Type' => 'First F Line',
            'Description' => 'The First F-Line is a reaction to only the E-Line, it rarely takes influences from earlier in the Sonnet. If the E-Line was a Warp, then the F will be a Weft and vice-versa. It is worth noting that Suspense and Stakes will also be raised and it is not uncommon for other Sides to unleash their Monster Embodiments now.'],
            ['Type' => 'Second E Line',
            'Description' => 'The Second E-Line is an echo of the first, but with even more elevated Stakes and Suspense.'],
            ['Type' => 'Second F Line',
            'Description' => 'The Second F-Line is an echo of the first, but with even more elevated Stakes and Suspense.'],
            ['Type' => 'First G Line',
            'Description' => 'The First G-Line is a break from the old, and the start of the End. This is the Final Ordeal of the Zenith, be it a Final Battle, a Final Revelation or a Final date.'],
            ['Type' => 'Second G Line',
            'Description' => 'The Second G-Line is an echo of the first, but the Final has already happened, so here this becomes the Completion Event that follows that. This Completion event follows on from the Final, and the Central Conflict as you would expect.'],
            ]
        ) ,
    );
