    static public function contains($haystack, $needle)
    {

        if (is_string($needle) && is_string($haystack))
        {
            //print_r('stringmatching...<br/>');
            return (bool)stripos(" " . $haystack, $needle);
        }
        else
        {
            if (is_string($haystack) && is_array($needle))
            {
                //print_r('array in string<br/>');
                foreach ($needle as $need)
                {
                    if ((bool)stripos(" " . $haystack, $need))
                    {
                        return true;
                    }
                }
            }
            elseif (is_array($haystack) && is_string($needle))
            {
                //print_r('string in array<br/>');
                foreach ($haystack as $value)
                if (is_string($value)){
                    {
                        if ((bool)stripos(" " . $value, $needle))
                        {
                            return true;
                        }
                    }
                }else{
                        if (T13Types::contains($value, $needle)){
                            return true;
                        }
                }
                
            }
            elseif (is_array($haystack) && is_array($needle))
            {
                //print_r('array in array<br/>');
                if (count($haystack) > count($needle))
                {
                    $notfound = count($needle);
                }
                else
                {
                    $notfound = count($haystack);
                }

                //print_r('notfound='.json_encode($notfound).'<br/>');
                foreach ($haystack as $hay)
                {
                    foreach ($needle as $nee)
                    {
                        if (is_string($nee))
                        {
                            // the array contains something from the search array if strings
                            if ((bool)stripos(" " . $hay, $nee))
                            {
                                return true;
                            }
                        }
                        else
                        {
                            if ($hay == $nee)
                            {
                                $notfound--;
                            }
                        }

                    }
                }
                return $notfound <= 0;
            }

        }
        return false;
    }
    static public function csser($string)
    {
        return strtolower(ucwords(str_replace("_", "-", $string)));
    }
    static public function json_validate($string)
    {
        // decode the JSON data
        $result = json_decode($string);

        // switch and check possible JSON errors
        switch (json_last_error())
        {
            case JSON_ERROR_NONE:
                $error = ''; // JSON is valid // No error has occurred

            break;
            case JSON_ERROR_DEPTH:
                $error = 'The maximum stack depth has been exceeded.';
            break;
            case JSON_ERROR_STATE_MISMATCH:
                $error = 'Invalid or malformed JSON.';
            break;
            case JSON_ERROR_CTRL_CHAR:
                $error = 'Control character error, possibly incorrectly encoded.';
            break;
            case JSON_ERROR_SYNTAX:
                $error = 'Syntax error, malformed JSON.';
            break;
                // PHP >= 5.3.3

            case JSON_ERROR_UTF8:
                $error = 'Malformed UTF-8 characters, possibly incorrectly encoded.';
            break;
                // PHP >= 5.5.0

            case JSON_ERROR_RECURSION:
                $error = 'One or more recursive references in the value to be encoded.';
            break;
                // PHP >= 5.5.0

            case JSON_ERROR_INF_OR_NAN:
                $error = 'One or more NAN or INF values in the value to be encoded.';
            break;
            case JSON_ERROR_UNSUPPORTED_TYPE:
                $error = 'A value of a type that cannot be encoded was given.';
            break;
            default:
                $error = 'Unknown JSON error occured.';
            break;
        }

        if ($error !== '')
        {
            // throw the Exception or exit // or whatever :)
            exit($error . ':' . $string);
        }

        // everything is OK
        return $result;
    }

    static public function arrayify($string)
    {
        //error_log('arrayifying'.$string);
        if (is_numeric($string))
        {
            //error_log('numeric');
            return array(
                '0' => intval($string)
            );
        }
        $strung = stripslashes($string);
        if (T13Types::contains($string, '``'))
        {
            $strung = str_ireplace('``', '"', $string);
        }
        if (is_string($strung) && !is_numeric($strung) && T13Types::is_Json($strung))
        {
            $strung = json_decode($strung, true);
            if (is_array($strung) || is_object($strung))
            {
                unset($string);
                return (array)$strung;
            }
            else
            {
                error_log("something has gone wrong with the arrayification of that Json" . T13Types::json_validate($string));
            }

        }
        else
        {
            if (is_string($string))
            {
                $strung = [];
                $delimiters = array(
                    '~-~',
                    ' | ',
                    '| ',
                    '|',
                    ' / ',
                    '/ ',
                    '/',
                    ' , ',
                    ', ',
                    ',',
                    ' '
                );
                foreach ($delimiters as $delimiter)
                {
                    if (self::contains($string, $delimiter))
                    {
                        $strung = explode($delimiter, $string);
                        break;
                    }
                }
                if (is_array($strung) && count($strung) > 1)
                {
                    return $strung;
                }
            }

        }
        //error_log('defaulting []');
        return (array)[$string];
    }
    static public function isEmptyArray($var)
    {
        return (is_array($var) && json_encode($var) == '[]');
    }
    static public function arrayGetValue($array, $key)
    {
        if (count($array))
        {
            return $array[$key % count($array) ];
        }
        else
        {
            return NULL;
        }

    }
    static public function makeUniqueArray($array)
    {
        if (is_array($array))
        {
            //encode
            $ret = [];
            $ram = [];
            foreach ($array as $id => $content)
            {
                $ram[$id] = json_encode($content);
            }
            unset($array);
            $ram = array_keys(array_flip($ram));
            foreach ($ram as $i => $content)
            {
                array_push($ret, json_decode($content, true));
            }
            unset($ram);
            return $ret;
        }
    }
    static public function displayUser($userid)
    {
        $avatar = get_avatar($userid, '38', 'wavatar');
        $nickname = get_the_author_meta('nickname', $userid);
        $fullname = get_the_author_meta('first_name', $userid) . ' ' . get_the_author_meta('last_name', $userid);
        $akas = $nickname . ', ' . get_the_author_meta('first_name', $userid) . ', ' . get_the_author_meta('last_name', $userid) . ', ' . get_the_author_meta('display_name', $userid) . ', ' . get_the_author_meta('nicename', $userid) . ', ' . get_the_author_meta('email', $userid) . ', ' . get_the_author_meta('url', $userid) . ', ' . get_the_author_meta('status', $userid);
        $name = [$nickname, $fullname, $akas];
        $geo = T13Geometry::writeGeo($name, true);
        $description = wpautop(get_the_author_meta('description', $userid));
        return "<figure class=\"t13ne-user\"><details><summary class=\"t13ne-tooltip\">{$avatar}<span class=\"t13ne-tooltip\">{$nickname}</span></summary><p>{$geo['GeoText']}</p><p class=\"t13ne-description\">{$description}</p></details></figure>";
    }
    static public function areWeEditing($post_id = 0)
    {
        $editing = false;
        $current = get_current_user_id();
        if ($current)
        {
            if (is_admin())
            {
                if (current_user_can('edit_others_pages'))
                {
                    $editing = true;
                }
                else
                {
                    global $post;
                    if (!$post_id)
                    {
                        $post_id = $post->ID;
                        $post_author = $post->post_author;
                    }
                    else
                    {
                        if ($post_id != $post->ID)
                        {
                            $temp = get_post($post_id);
                            $post_author = $temp->post_author;
                        }
                        else
                        {
                            $post_id = $post->ID;
                            $post_author = $post->post_author;
                        }
                    }
                    if (current_user_can('edit') && $current == $post_author)
                    {
                        $editing = true;
                    }
                }
            }
        }
        return $editing;
    }
    static public function buildDataList($selectArr, $facet = '-1', $card = - 1, $selected = 0)
    {
        $ret = '<!--datalist //-->';
        $sl = strtolower($selected);
        if (!is_array($selectArr))
        {
            if (is_string($selectArr))
            {
                if (isset($$selectArr))
                {
                    $selectArr = $$selectArr;
                }
            }
            else
            {
                if ($facet != - 1)
                {
                    $selectArr == $facet;
                }
                elseif ($card != - 1)
                {
                    $selectArr = $card;
                }
            }
        }
        $js = json_encode($selectArr);
        if ($facet)
        {
            $id = 'facetlist';
        }
        if ($card)
        {
            $id = 'cardlist';
        }
        if (!isset($id))
        {
            $id = 'list' . md5($js);
        }
        if (isset(self::$ids))
        {
            $flids = array_flip(self::$ids);
        }
        else
        {
            $flids = array();
        }
        if (!array_key_exists($id, $flids))
        {
            self::$ids[] = $id;
            $ret .= "<datalist id=\"{$id}\">";
            foreach ($selectArr as $key => $option)
            {
                $rules = '';
                $description = '';
                $text = '';
                if (is_array($option))
                {
                    if (isset($option['Description']))
                    {
                        $description = $option['Description'];
                    }
                    if (isset($option['Text']))
                    {
                        $text = $option['Text'];
                    }
                    if (isset($option['Icon']))
                    {
                        $text = "<p><strong>Applicable Wounds</strong> — {$option['Applicable_Wounds']}</p>";
                        $text = "<p><strong>Best Result</strong> — {$option['Best_Result']}</p>";
                        $text .= "<p><strong>Worst Result</strong> — {$option['Best_Result']}</p>";
                    }
                    if (isset($option['Rules']))
                    {
                        $rules = $option['Rules'];
                    }

                    if (isset($option['Woe']))
                    {
                        $rules = '<span class==#13ne-quirk-text=#><strong>Quirk: </strong> ' . $option['Quirk'] . '</span><p class==#t13ne-flaw\=#><strong>Flaw: </strong> ' . $option['Flaw'] . '</p><p class==#t13ne-woe-text=#><strong>Woe: </strong> ' . $option['Woe'] . '</p>';
                    }
                    if (is_array($facet))
                    {
                        if (isset($facet[$option['Type']]))
                        {
                            $rules = '<strong>' . $facet['FacetName'] . '</strong> — ' . $facet[$option['Type']];
                        }
                    }
                    if ($card != - 1)
                    {
                        //var_dump ($card);
                        $title = $option['Card_Corner'] . T13Suits::$suits[$option['Suit']]['Icon'];
                        $card = strtolower($card);
                        $text = '';
                        $rules = '';
                        $description = '';
                        if (T13Types::contains($card, 'yarn'))
                        {
                            $yarn = T13Cards::getCardText($key, 'yarn');
                            $text .= '<dl class=t13ne-yarn>';
                            foreach ($yarn as $k => $v)
                            {
                                $text .= "<dt>{$k}</dt><dd>{$v}</dd>";
                            }
                            $text .= '</dl>';
                        }
                        if (T13Types::contains($card, 'wyrd'))
                        {
                            $tarot = T13Cards::getCardText($key, 'tarot');
                            $rules .= '<dl class=t13ne-tarot>';
                            foreach ($tarot as $k => $v)
                            {
                                $rules .= "<dt>{$k}</dt><dd>{$v}</dd>";
                            }
                            $rules .= '</dl>';
                        }
                        if (T13Types::contains($card, 'revelations'))
                        {
                            $revs = T13Cards::getCardText($key, 'revelations');
                            $text .= '<dl class=t13ne-revelation>';
                            foreach ($revs as $k => $v)
                            {
                                $text .= "<dt>{$k}</dt><dd>{$v}</dd>";
                            }
                            $text .= '</dl>';
                        }
                        if (T13Types::contains($card, 'ordeal'))
                        {
                            $ordeal = T13Cards::getCardText($key, 'ordeal');
                            $rules .= '<dl class=t13ne-ordeal>';
                            foreach ($ordeal as $k => $v)
                            {
                                $rules .= "<dt>{$k}</dt><dd>{$v}</dd>";
                            }
                            $rules .= '</dl>';
                        }
                        if (T13Types::contains($card, 'obstacles'))
                        {
                            $obstacle = T13Cards::getCardText($key, 'obstacle');
                            $rules .= '<dl class=t13ne-obstacle>';
                            foreach ($obstacle as $k => $v)
                            {
                                $rules .= "<dt>{$k}</dt><dd>{$v}</dd>";
                            }
                            $rules .= '</dl>';
                        }

                    }
                    $title = '?';
                    if (isset($option['Short']))
                    {
                        $title = $option['Short'];
                    }
                    elseif (isset($option['Type']))
                    {
                        $title = $option['Type'];
                    }
                    elseif (isset($option['Icon']))
                    {
                        $title = $option['Name'] . ' ' . $option['Icon'];
                    }
                    elseif (isset($option['Rank']))
                    {
                        $title = $option['Rank'];
                        $option['Type'] = $option['Rank'];
                    }
                    elseif (isset($option['Tier']))
                    {
                        $title = $option['Tier'];
                        $option['Type'] = $option['Tier'];
                    }
                    if ($key == $selected || $title == $selected || strtolower($title) == $sl)
                    {
                        $ret .= '<!-- has matched //-->';
                        $selectthis = 'selected data-debug="' . $key . $selected . '||' . $option['Type'] . '||' . $title . '||' . $sl . '" ';
                        $ru = str_replace('=#', '"', $rules);
                        $tx = $text;
                        $desc = $description;
                    }
                    else
                    {
                        $selectthis = '';
                    }
                    $ret .= "<option value=\"{$key}\" {$selectthis} data-description=\"{$description}\" data-text=\"{$text}\" data-rules=\"{$rules}\">{$title}</option>";
                }
            }

            $ret .= '</datalist>';
            return $ret;
        }
    }
