                        }))
                        {
                            $array = $
                            {
                                $ard[$sub]
                            };
                            $rethtml .= '<!-- ${$[]} -->';
                        }
                        if (isset($
                        {
                            $ard
                        }
                        [$sub]))
                        {
                            $array = $
                            {
                                $ard
                            }
                            [$sub];
                            $rethtml .= '<!-- ${$}[] -->';
                        }

                    }

                }
            }
            else
            {

                if (isset(self::$$ard))
                {
                    if (is_array(self::$$ard))
                    {
                        if ($sub == "")
                        {
                            $array = self::$$ard;
                            $rethtml .= '<!-- self: ard -->';
                        }
                        else
                        {
                            if (is_array($ard))
                            {
                                if (isset(self::$
                                {
                                    $ard[$sub]
                                }))
                                {
                                    $array = self::$
                                    {
                                        $ard[$sub]
                                    };
                                    $rethtml .= '<!--self::${$ard[$sub]}-->';
                                }

                            }
                            else
                            {
                                if (isset(self::$
                                {
                                    $ard
                                }
                                [$sub]))
                                {
                                    $array = self::$
                                    {
                                        $ard
                                    }
                                    [$sub];
                                    $rethtml .= '<!-- self::${$ard}[$sub] -->';
                                }
                            }

                        }
                    }
                }
                else
                {
                    if (isset(T13Plots::$$ard))
                    {
                        if (is_array(T13Plots::$$ard))
                        {
                            $array = T13Plots::$$ard;
                            $rethtml .= '<!-- T13Plots::ard -->';
                        }
                    }
                    elseif (isset(T13Chars::$$ard))
                    {
                        if (is_array(T13Chars::$$ard))
                        {
                            $array = T13Chars::$$ard;
                            $rethtml .= '<!-- T13Chars::ard -->';
                        }
                    }
                    elseif (isset(T13Descendants::$$ard))
                    {
                        if (is_array(T13Descendants::$$ard))
                        {
                            $array = T13Descendants::$$ard;
                            $rethtml .= '<!-- T13Descendants::ard -->';
                        }
                    }
                    elseif (isset(T13Annexes::$$ard))
                    {
                        if (is_array(T13Annexes::$$ard))
                        {
                            $array = T13Annexes::$$ard;
                            $rethtml .= '<!-- T13Annexes::ard -->';
                        }
                    }
                    elseif (isset(T13Hitches::$$ard))
                    {
                        if (is_array(T13Hitches::$$ard))
                        {
                            $array = T13Hitches::$$ard;
                            $rethtml .= '<!-- T13Hitches::ard -->';
                        }
                    }
                    elseif (isset(T13Cards::$$ard))
                    {
                        if (is_array(T13Cards::$$ard))
                        {
                            $array = T13Cards::$$ard;
                            $rethtml .= '<!-- T13Cards::ard -->';
                        }
                    }
                    elseif (isset(T13Geometry::$$ard))
                    {
                        if (is_array(T13Geometry::$$ard))
                        {
                            $array = T13Geometry::$$ard;
                            $rethtml .= '<!-- T13Cards::ard -->';
                        }
                    }
                    else
                    {
                        $rethtml .= 'not found ' . $ard;
                    }
                }
            }
        }
        if (is_array($array))
        {
            $rethtml .= '<div class="t13ne-tablewrap"><table class="t13ne-table t13ne-display"><caption>' . $title . '</caption><thead><tr>';
            $foot = '<tfoot><tr>';
            foreach ($array[0] as $key => $val)
            {
                if ($key !== "Array" && $key !== "" && $key !== "Direction")
                {
                    $keyT = ucwords(str_replace("_", " ", $key));
                    $kel = strtolower(ucwords(str_replace("_", "-", $key)));
                    $foot .= "<td class=\"t13ne-{$kel}\">{$keyT}</td>";
                    $rethtml .= "<th class=\"t13ne-{$kel}\">{$keyT}</th>";
                }
            }
            $rethtml .= '</tr></thead><tbody>';
            $foot .= '</tr></tfoot>';
            foreach ($array as $arr)
            {
                $rethtml .= '<tr>';
                foreach ($arr as $key => $val)
                {
                    $style = '';
                    if ($key !== "Array" && $key !== "" && $key !== "Direction")
                    {
                        $kel = strtolower(ucwords(str_replace("_", "-", $key)));
                        if ($key == "Mode" || $key == "Icon")
                        {
                            $val = '<span class="t13ne-atkicon">' . do_shortcode($val) . '</span>';
                        }
                        if (self::contains($key, 'fences') || $key == 'Applicable_Wounds')
                        {
                            $val = do_shortcode(T13Suits::replaceEmojis($val));
                        }
                        if (is_array($val))
                        {
                            if ($val[1][0] == '#' && self::is_Hex($val[1]))
                            {
                                $hex = $val[1];
                                $bg = '255,255,255';
                                $alpha = 0.1;
                                $val = $val[0];
                                $hex1 = floor(hexdec($hex[1] . $hex[2]) / 2);
                                $hex2 = floor(hexdec($hex[3] . $hex[4]) / 2);
                                $hex3 = floor(hexdec($hex[5] . $hex[6]) / 2);
                                if (($hex1 + $hex2 + $hex3) / 1.5 > 136)
                                {
                                    $bg = '0,0,0';
                                }
                                $style = "color: {$hex}; background-color: rgba({$hex1},{$hex2},{$hex3},{$alpha}); text-shadow:1px 1px 2px rgba({$bg},1), 0px 0px 5px rgba({$bg},0.9), 0px 0px 11px rgba({$bg},0.8), 0px 0px 23px rgba({$bg},0.7), 0px 0px 47px rgba({$bg},0.6) !important ; text-align-last:center;";
                            }
                            else
                            {
                                $val = implode(", ", $val);
                            }

                        }
                        $rethtml .= "<td class=\"t13ne-{$kel}\" style=\"{$style}\">{$val}</td>";
                    }
                }
                $rethtml .= '</tr>';
            }
            $rethtml .= "</tbody>{$foot}</table></div>";
            return $rethtml;
        }
        else
        {
            $rethtml .= '<small>That array was not found or incorrectly targeted .=' . json_encode($array) . '</small>';
            return $rethtml;
        }
    }
    static public function buildTerms($taxon = 't13type', $termname = 'Proficiency', $post_id = '#')
    {
        global $post;
        $defaultTerm = get_term_by('name', $termname, $taxon);
        if ($post_id == '#')
        {
            $post_id = $post->ID;
        }
        $test = get_the_terms($post_id, $taxon);
        $retarr = array(
            $defaultTerm->term_id
        );
        if ($test && !is_wp_error($test))
        {
            foreach ($test as $t)
            {
                $retarr[] = $t->term_id;
            }
        }
        $retarr = array_unique($retarr);
        return $retarr;
    }

    static public function collectTaxonomies($elid)
    {
        //error_log('collect Taxonomies'.$elid. ' ' .$self::$post_type);
        $typeterms = wp_get_post_terms($elid, self::$post_type);
        return $typeterms;
    }
    static public function checkTaxon($check = 'T13 Core', $taxon = 't13genre', $elid = 0)
    {
        $typeTerms = wp_get_post_terms($elid, $taxon);
        if (!empty($typeTerms) && !is_wp_error($typeTerms))
        {
            foreach ($typeTerms as $quay => $valterm)
            {
                //each term
                foreach ($valterm as $qi => $val)
                {
                    //each slug,name, term_id etc...
                    if ($val == $check)
                    {
                        return array(
                            'Term' => $valterm,
                            'Matched' => $qi
                        );
                    }
                }
            }
        }
        return false;
    }
    static public function correctTaxon($taxon)
    {
        if (is_numeric($taxon))
        {
            $taxon = get_term($taxon);
        }
        if (is_array($taxon))
        {
            if (is_numeric($taxon[0]))
            {
                $taxon = get_term($taxon[0]);
            }
            if ($taxon['slug'])
            {
                $taxon = $taxon['slug'];
            }
            else
            {
                if (is_object($taxon[0]))
                {
                    $taxon = $taxon[0];
                }
            }
        }
        if (is_object($taxon))
        {
            if ($taxon->slug)
            {
                $taxon = $taxon->slug;
            }
        }
        switch (strtolower($taxon))
        {
            case 'char':
            case 'character':
            case 'pc':
                $tax_str = 'Character, Lite, Archetype, Detail, Full';
            break;
            case 'alt':
            case 'alternate':
                $tax_str = 'Character, Extra, Lite, Archetype, Detail, Full';
            break;
            case 'full':
