            break;
            case 'detail':
            case 'detailed':
                $tax_str = 'Detailed';
            break;
            case 'extra':
                $tax_str = 'Extra';
            break;
            case 'npc':
            case 'ref-char':
                $tax_str = 'Character, Extra, Lite, Archetype, Detail, Full';
            break;
            case 'lite':
                $tax_str = 'Lite, Extra';
            break;
            case 'desc':
            case 'descendant':
            case 'descendants':
            case 'location':
            case 'locations':
            case 'pact':
                $tax_str = 'Descendant';
            break;
            case 'annex':
            case 'annexes':
            case 'size':
            case 'liteprof':
            case 'conflict':
            case 'personality':
                $tax_str = 'Annex';
            break;
            case 'plot':
            case 'plots':
            case 'cycle':
            case 'cycles':
            case 'epic':
            case 'epics':
            case 'volume':
            case 'volumes':
            case 'arc':
            case 'arcs':
            case 'chapter':
            case 'chapters':
            case 'stories':
            case 'story':
                $tax_str = 'Plot';
            break;
            case 'prof':
            case 'profs':
            case 'proficiency':
            case 'proficiencies':
                $tax_str = 'Proficiency';
            break;
            case 'game':
            case 'games':
                $tax_str = 'Game';
            break;
            case 'book':
            case 'books':
            case 'narrative':
            case 'story-line':
            case 'narratives':
            case 'story-lines':
                $tax_str = 'Narrative';
            break;
            case 'hitch':
            case 'handicap':
            case 'hitches':
                $tax_str = 'Hitch';
            break;
            case 'thread':
                $tax_str = 'Thread, Proficiency, Note';
            break;
            case 'knot':
                $tax_str = 'Knot, Annex, Hitch';
            break;
            case 'pattern':
