    static public function typeTerms($eltype, $name, $terms)
    {
        if (is_array($name))
        {
            $name = implode('~-~', $name);
        }

        //if (isset($terms['debug-input'])){unset($terms['debug-input']);}
        //$ret['debug-input']=$terms;
        //$ret['debug']=array();
        if ($name != '')
        {
            $names = explode("~-~", $name);
            $ret['Geo'] = T13Geometry::writeGeometry($names[0], false);
            $ret['Geo_id'] = T13Geometry::getGeoTerms($names[0]);
        }
        else
        {
            if (isset($terms['Geo']))
            {
                $ret['Geo'] = T13Geometry::writeGeometry($terms['Geo']['Name'], false);;
                $ret['Geo_id'] = T13Geometry::getGeoTerms($terms['Geo']['Name']);
            }
        }
        $terms['Element'] = $eltype;
        $ret['Element'] = $eltype;
        $post_parent = 0;
        if (isset($terms['Parent']))
        {
            if (is_string($terms['Parent']))
            {
                $temp = get_page_by_title($terms['Parent'], 'Object', 'element');
                $ret['Parent'] = $terms['Parent'];
                $ret['Parent_id'] = $temp->ID;
            }
            if (get_post_status($terms['Parent']))
            {
                $ret['Parent_id'] = $terms['Parent'];
                $temp = get_post($ret['Parent_id'], 'Object', 'element');
                $ret['Parent'] = $temp->post_title;
            }
        }
        else
        {
            $ret['Parent_id'] = 0;
        }
        if (isset($terms['Creator']))
        {
            if (is_string($terms['Creator']))
            {
                $temp = get_page_by_title($terms['Creator'], 'Object', 'element');
                $ret['Creator'] = $terms['Creator'];
                $ret['Creator_id'] = $temp->ID;
            }
            if (get_post_status($terms['Creator']))
            {
                $ret['Creator_id'] = $terms['Creator'];
                $temp = get_post($terms['Creator_id'], 'Object', 'element');
                $ret['Creator'] = $temp->post_title;
            }
        }
        if (isset($terms['t13postid']))
        {
            $ret['t13postid'] = $terms['t13postid'];
        }
        if (isset($terms['Owner']))
        {
            if (is_string($terms['Owner']))
            {
                $temp = get_page_by_title($terms['Owner'], 'Object', 'element');
                $ret['Owner'] = $terms['Creator'];
                $ret['Owner_id'] = $temp->ID;
            }
            if (get_post_status($terms['Owner']))
            {
                $terms['Owner_id'] = $terms['Owner'];
                $temp = get_post($terms['Owner_id']);
                $terms['Owner'] = $temp->post_title;
            }
        }
        if (!isset($terms['Scope']))
        {
            $terms['Scope'] = 'Developmental';
        }
        if (!isset($terms['Genre']))
        {
            $terms['Genre'] = 'Experimental';
        }
        if (!isset($terms['Era']))
        {
            $terms['Era'] = 'Unknown';
        }
        if (!isset($terms['Facet']))
        {
            $terms['Facet'] = 'All Facets';
        }
        foreach ($terms as $tn => $term)
        {
            $tk = strtolower($tn);
            //$terms['debug'][]=array('tk'=>$tk, 'term'=>$term);
            $tt = 0;
            $idt = 0;
            if (self::contains($tk, 'element'))
            {
                $tt = 't13type';
                $idt = 'Taxon_id';

            }
            elseif (self::contains($tk, 'facet'))
            {
                $tt = 't13facet';
                $idt = 'Facet_id';
            }
            elseif (self::contains($tk, 'genre'))
            {
                $tt = 't13genre';
                $idt = 'Genre_id';
            }
            elseif (self::contains($tk, 'era'))
            {
                $tt = 't13era';
                $idt = 'Era_id';
            }
            elseif (self::contains($tk, 'scope'))
            {
                $tt = 't13scope';
                $idt = 'Scope_id';
            }
            elseif (self::contains($tk, 'data'))
            {
                $tt = 't13data';
                $idt = 'Data_id';
            }
            elseif (self::contains($tk, 'cat'))
            {
                $tt = 'category';
                $idt = 'Cat_id';
            }
            elseif (self::contains($tk, 'tag'))
            {
                $tt = 'post_tags';
                $idt = 'Tag_id';
            }
            if (is_array($term) && $tt)
            {
                $ret['debug'][] = 'Term Array';
                $ret[$idt] = array();
                $ret[$tn] = array();
                foreach ($term as $m => $ter)
                {
                    if (is_string($ter))
                    {
                        $tempterm = get_term_by('name', $ter, $tt);
                    }
                    elseif (is_numeric($ter))
                    {
                        $tempterm = get_term_by('id', $ter, $tt);
                    }
