                        $ret[$idt][] = intval($tempterm->term_id);
                    }
                    elseif (is_array($tempterm))
                    {
                        $ret[$tn][] = $tempterm['name'];
                        $ret[$idt][] = intval($tempterm['term_id']);
                    }
                }
            }
            elseif (is_numeric($term) && $tt)
            {
                $tempterm = get_term($term, $tt);
                if (is_object($tempterm))
                {
                    $ret[$tn] = $tempterm->name;
                    $ret[$idt] = $tempterm->term_id;
                }
                elseif (is_array($tempterm))
                {
                    $ret[$tn] = $tempterm['name'];
                    $ret[$idt] = $tempterm['term_id'];
                }
            }
            elseif (is_string($term) && $tt)
            {
                $ret[$tn] = $term;
                $tempterm = get_term_by('name', $term, $tt);
                if (!$tempterm)
