                    var_dump($tempterm);
                }
                //$terms['debug'][]=array("terms[{$idt}]"=>intval($terms[$idt]));

            }
        }
        //if (isset($terms['debug-result'])){unset($terms['debug-result']);}
        //$ret['debug-result']=$ret;
        $ret['debug-html'] = '';
        $ret['debug-html'] = htmlspecialchars(json_encode($ret));

