    static public function updateTerms($terms, $term, $add)
    {
        if (!is_array($add))
        {
            if (isset($terms[$term]) && is_string($add))
            {
                $found = 0;
                $jt = json_encode($terms[$term]);
                if (self::contains($jt, $add))
                {
                    $found = 1;
                }
                if (!$found)
                {
                    if (is_string($terms['Facet']))
                    {
                        $terms['Facet'] = array(
                            $add,
                            $terms['Facet']
                        );
                    }
                    elseif (is_array($terms['Facet']))
                    {
                        array_unshift($terms['Facet'], $add);
                    }
                }
            }
        }
        else
        {
            foreach ($add as $ad)
            {
                $terms = self::updateTerms($terms, $term, $ad);
            }
        }
        return $terms;
    }

