    static public function array_flatten($array = null)
    {
        $result = array();
        if (!is_array($array))
        {
            $array = func_get_args();
        }
        if (is_null($array)){
            error_log('something went wrong in array flattening');
            return null;
        }
        foreach ($array as $key => $value)
        {
            if (is_array($value))
            {
                $result = array_merge($result, self::array_flatten($value));
            }
            else
            {
                $result = array_merge($result, array(
                    $key => $value
                ));
            }
        }
        return array_filter($result);
    }
    static public function array_fold($array = null)
    {
        //makes 2d array from 1d
        $result = [];
        if (!is_array($array))
        {
            $array = func_get_args();
        }
        if (isset($array[0][0]))
        {
            return $array;
        } //already 2d
        $count = count($array);
        $sq = floor(sqrt($count));
        for ($i = 0;$i < $sq;$i++)
        {
            for ($j = 0;$j < $sq;$j++)
            {
                $result[$i][$j] = array_shift($array);
            }
        }
        return $result;
    }
    static public function rotate2dArray($array = null)
    {
        if (!is_array($array))
        {
            $array = func_get_args();
        }
        if (!isset($array[0][0]) && isset($array[0]))
        {
            //if it isn't 2d fold it
            $array = self::array_fold($array);
        }
        array_unshift($array, null);
        if (is_array($array)){
            $array = call_user_func_array('array_map', $array);
            $array = array_map('array_reverse', $array);
        }
        
        return $array;
    }
    static public function spiralArray($array = [], $x = 0, $y = 0)
    {

        if (is_array($array))
        {
            if (count($array) > 0)
            {
                if (!isset($array[0][0]))
                {
                    $array = self::array_fold($array);
                }
                if (isset($array[$x][$y]))
                {
                    return $array[$x][$y];
                }
                else
                {
                    $xcount = count($array);
                    if ($xcount > 0)
                    {
                        $ycount = count($array[$x % $xcount]);
                        if ($ycount > 0)
                        {
                            return $array[$x % $xcount][$y % $ycount];
                        }
                        else
                        {
                            return T13Dice::RNG(0, 53);
                        }
                    }
                    else
                    {
                        return T13Dice::RNG(0, 53);
                    }

                }
            }

        }
        return 'something messed up in spiral array...';

    }
    static public function remapArray($array = [], $mapArray = [])
    {
        if (!isset($array[0][0]) && isset($array[0]))
        {
            $array = self::array_fold($array);
        } //make a 2d array (it really helps)
        $countArray = count($array); //meant to be a 2d array
        $countMap = count($mapArray);
        $flat = self::array_flatten($array);
        $flatcount = count($flat) - 1;
        $retArray = range(0, $flatcount); //build the empty flat array
        if ($countArray == $countMap)
        {
            //map seems big enough
            foreach ($mapArray as $row => $rowe)
            {
                foreach ($rowe as $col => $column)
                {
                    $retArray[$column] = $array[$row][$col];
                }
            }
        }
        return $retArray;
    }

    static public function spiralMapping($array = null)
    {
        if (!is_array($array))
        {
            $array = func_get_args();
        }
        if (!isset($array[0][0]) && isset($array[0]))
        {
            $array = self::array_fold($array);
        }
        $countArray = count($array);
        switch ($countArray)
        {
            case 2:
                return self::remapArray($array, [[1, 2], [3, 0]]);
            break;
            case 3:
                return self::remapArray($array, [[6, 7, 8], [5, 0, 1], [4, 3, 2]]);
            break;
            case 4:
                return self::remapArray($array, [[6, 7, 8, 9], [5, 0, 1, 10], [4, 3, 2, 11], [15, 14, 13, 12]]);
            break;
            case 5:
                return self::remapArray($array, [[20, 21, 22, 23, 24], [19, 6, 7, 8, 9], [18, 5, 0, 1, 10], [17, 4, 3, 2, 11], [16, 15, 14, 13, 12]]);
            break;
            case 6:
                return self::remapArray($array, [[20, 21, 22, 23, 24, 25], [19, 6, 7, 8, 9, 26], [18, 5, 0, 1, 10, 27], [17, 4, 3, 2, 11, 28], [16, 15, 14, 13, 12, 29], [35, 34, 33, 32, 31, 30]]);
            break;
            case 7:
                return self::remapArray($array, [[42, 43, 44, 45, 46, 47, 48], [41, 20, 21, 22, 23, 24, 25], [40, 19, 6, 7, 8, 9, 26], [39, 18, 5, 0, 1, 10, 27], [38, 17, 4, 3, 2, 11, 28], [37, 16, 15, 14, 13, 12, 29], [36, 35, 34, 33, 32, 31, 30]]);
            break;
            default:
                return null;
            break;
        }
    }

    static public function spiralise2dArray($array = null)
    {
        return self::spiralMapping($array);
    }

