    static public function swappairs($array)
    {
        $count = count($array);
        if ($count > 1)
        {
            for ($i = 0;$i < $count;$i += 2)
            {
                if (isset($array[($i + 1) % $count])&& isset($array[$i% $count]))
                {
                    $temp = $array[$i% $count];
                    $array[$i% $count] = $array[($i + 1) % $count];
                    $array[($i + 1) % $count] = $temp;
                    unset($temp);
                }
            }
        }
        return $array;
    }
    static public function addT13Menu($meny, $entries = 0)
    {
        $locations = get_theme_mod('nav_menu_locations');
        //if(has_nav_menu( $meny )){
             // Check if the menu exists
        //}
        

        $ex = wp_get_nav_menu_object($meny);
        if (!$ex)
        {
            $id = wp_create_nav_menu($meny);
        }
        else
        {
            $id = $ex->ID;
        }

        if (isset($entries[0]))
        {
            foreach ($entries as $entry)
            {
                self::addT13MenuEntry($entry, $id);
            }
        }
        else
        {
            self::addT13MenuEntry($entries, $id);
        }

        if (!isset($locations['primary']) && isset($id))
        {
            $locations['T13NE Menu'] = $id;
            set_theme_mod('nav_menu_locations', $locations);
        }

    }
    static public function addT13MenuEntry($entry, $id = 0)
    {
        if (is_array($entry) && $id > 0 && isset($entry['Name']))
        {
            $menu_object = wp_get_nav_menu_items( esc_attr( $id ) );
            $menu_items = wp_list_pluck( $menu_object, 'object_id' );
            if ( !in_array( (int) $entry['ID'], $menu_items )){
                wp_update_nav_menu_item($id, 0, array(
                    'menu-item-attr-title' => 'Read the rules on ' . $entry['Name'],
                    'menu-item-object-id' => $entry['ID'],
                    'menu-item-object' => $entry['Type'],
                    'menu-item-type' => $entry['Item_Type'],
                    'menu-item-title' => $entry['Name'],
                    'menu-item-url' => $entry['URL'],
                    'menu-item-description' => $entry['Description'],
                    'menu-item-classes' => 't13ne-' . strtolower($entry['Name']) ,
                    'menu-item-status' => 'publish',
                ));
            }
        }
    }
